import type { ExamQuestion } from "./types";

export const rnPathoTestbankQuestions: ExamQuestion[] = [
  // ============================================================
  // DIABETES TYPE 1 (40 questions)
  // ============================================================
  { q: "A 12-year-old is newly diagnosed with Type 1 diabetes. The parent asks why the child cannot take pills instead of insulin injections. Which response by the nurse is most accurate?", o: ["Oral medications will be started once the child's blood sugar stabilizes", "Type 1 diabetes destroys the insulin-producing beta cells, so the body cannot make insulin and requires insulin injections for survival", "Oral medications are only approved for adults", "The child may switch to oral medications after puberty"], a: 1, r: "T1DM results from autoimmune destruction of pancreatic beta cells, causing absolute insulin deficiency. Oral hypoglycemic agents require functioning beta cells or target insulin resistance — they cannot replace absent insulin production.", s: "Endocrine" },
  { q: "A patient with T1DM has a blood glucose of 42 mg/dL and is diaphoretic, tremulous, and confused. What is the priority nursing action?", o: ["Administer 15g of fast-acting carbohydrate and recheck glucose in 15 minutes", "Give insulin to prevent rebound hyperglycemia", "Encourage the patient to eat a full meal", "Recheck the blood glucose in 30 minutes without intervention"], a: 0, r: "The Rule of 15: administer 15g fast-acting carbohydrate (4 oz juice, glucose tablets), recheck in 15 minutes. The patient is conscious and can swallow safely. If glucose remains <70 after treatment, repeat.", s: "Endocrine" },
  { q: "The nurse is teaching a patient about insulin glargine (Lantus). Which statement by the patient indicates correct understanding?", o: ["I will mix this insulin with my rapid-acting insulin to reduce the number of injections", "I will take this insulin at the same time each day and never mix it with other insulins", "I will shake the vial vigorously before drawing up the dose", "I will take extra doses before meals"], a: 1, r: "Glargine is a long-acting basal insulin given once daily. It must NEVER be mixed with other insulins due to its acidic pH (4.0), which causes precipitation. It appears clear and should not be shaken.", s: "Endocrine" },
  { q: "A patient with T1DM reports feeling shaky, sweaty, and anxious at 3 AM but wakes with a blood glucose of 280 mg/dL at 7 AM. This pattern is most consistent with:", o: ["Dawn phenomenon", "Somogyi effect", "Insulin resistance", "Medication non-adherence"], a: 1, r: "The Somogyi effect is rebound hyperglycemia caused by counter-regulatory hormone release (glucagon, epinephrine, cortisol) in response to nocturnal hypoglycemia. The 3 AM symptoms (shakiness, sweating) confirm hypoglycemia. Dawn phenomenon has no nocturnal hypoglycemia.", s: "Endocrine" },
  { q: "Which laboratory test best distinguishes Type 1 from Type 2 diabetes?", o: ["Fasting blood glucose", "HbA1c level", "C-peptide level", "Oral glucose tolerance test"], a: 2, r: "C-peptide is co-secreted with insulin and reflects endogenous insulin production. In T1DM, C-peptide is low or undetectable (beta cells destroyed). In T2DM, C-peptide is normal or elevated (insulin resistance, not deficiency).", s: "Endocrine" },
  { q: "A nurse is preparing to administer insulin lispro (Humalog). When should this insulin be given?", o: ["30 minutes before the meal", "Within 15 minutes of starting the meal", "At bedtime", "2 hours after the meal"], a: 1, r: "Rapid-acting insulin (lispro, aspart, glulisine) has onset within 15 minutes and peaks at 1-2 hours. It should be given within 15 minutes before or immediately after starting to eat to cover the postprandial glucose rise.", s: "Endocrine" },
  { q: "A patient with T1DM has an HbA1c of 9.8%. The nurse understands this indicates:", o: ["Well-controlled diabetes over the past 2-3 months", "Poorly controlled diabetes with average blood glucose approximately 235 mg/dL over the past 2-3 months", "Acute hyperglycemia only", "Normal glucose metabolism"], a: 1, r: "HbA1c reflects average blood glucose over 2-3 months (the lifespan of a red blood cell). The target for most adults is <7.0%. An HbA1c of 9.8% corresponds to an estimated average glucose of approximately 235 mg/dL, indicating poor control.", s: "Endocrine" },
  { q: "Which complications should the nurse screen for annually in a patient with Type 1 diabetes? Select all that apply.", o: ["Diabetic retinopathy via dilated eye exam", "Diabetic nephropathy via urine albumin-to-creatinine ratio", "Diabetic neuropathy via monofilament foot exam", "Thyroid function (associated autoimmune conditions)", "Bone density scan"], a: 0, r: "Annual screening for microvascular complications includes dilated eye exam (retinopathy), UACR (nephropathy), monofilament foot exam (neuropathy), and thyroid screening (T1DM is associated with other autoimmune conditions including Hashimoto thyroiditis).", s: "Endocrine", t: "sata", ca: [0, 1, 2, 3] },
  { q: "The nurse is educating a patient about sick-day rules for T1DM. Which instruction is MOST important?", o: ["Stop all insulin until you are able to eat normally", "Never stop your basal insulin — check blood glucose every 2-4 hours and check ketones if glucose is above 250", "Take half your usual insulin dose when sick", "Only take insulin if you eat a full meal"], a: 1, r: "Basal insulin must NEVER be stopped, even during illness or when not eating. Basal insulin prevents ketogenesis and controls hepatic glucose output. During illness, counter-regulatory hormones increase, often requiring MORE insulin.", s: "Endocrine" },
  { q: "A patient asks about the 'honeymoon period' after T1DM diagnosis. The nurse explains:", o: ["This is a permanent remission of diabetes", "This is a temporary period when remaining beta cells increase insulin output, reducing insulin needs — it always ends as autoimmune destruction continues", "This means oral medications can replace insulin", "This period lasts for the rest of the patient's life"], a: 1, r: "The honeymoon period occurs when residual beta cells temporarily increase insulin production, sometimes dramatically reducing exogenous insulin requirements. This is NOT remission — autoimmune destruction continues and the honeymoon always ends.", s: "Endocrine" },
  { q: "A patient with T1DM is found unconscious with a blood glucose of 32 mg/dL. No IV access is available. What is the priority intervention?", o: ["Administer oral glucose tablets", "Administer IM glucagon", "Give orange juice sublingually", "Wait for IV access to administer D50"], a: 1, r: "An unconscious patient cannot safely swallow oral glucose (aspiration risk). With no IV access, IM glucagon is the appropriate treatment. It stimulates hepatic glycogenolysis, raising blood glucose within 10-15 minutes. Position the patient in the recovery position.", s: "Endocrine" },
  { q: "The nurse notes lipohypertrophy at a patient's insulin injection site. What is the most likely cause?", o: ["Allergic reaction to insulin", "Repeated injection at the same site without rotating", "Using expired insulin", "Injecting insulin too deeply"], a: 1, r: "Lipohypertrophy (fatty lumps) occurs from repeated insulin injection at the same site. It impairs insulin absorption, leading to unpredictable glucose levels. The nurse should teach the patient to rotate injection sites within the same body region.", s: "Endocrine" },
  { q: "Which statement about insulin storage is correct?", o: ["All insulin must be kept frozen until use", "Unopened insulin should be refrigerated; in-use vials may be kept at room temperature for up to 28 days", "Insulin should be stored in direct sunlight for activation", "Opened insulin vials must be discarded after 7 days"], a: 1, r: "Unopened insulin is stored in the refrigerator (36-46°F). Once opened or in use, insulin vials/pens can be kept at room temperature (up to 86°F) for 28 days. Insulin should never be frozen, stored in extreme heat, or exposed to direct sunlight.", s: "Endocrine" },
  { q: "A patient with T1DM using an insulin pump reports nausea, vomiting, and blood glucose of 380 mg/dL. The nurse should assess for:", o: ["Insulin pump catheter occlusion or malfunction causing insulin interruption and possible DKA", "Gastroenteritis unrelated to diabetes", "Hypoglycemia symptoms", "Allergic reaction to the pump"], a: 0, r: "Insulin pump malfunction (catheter occlusion, infusion set displacement, pump failure) interrupts all insulin delivery, including basal insulin. This can lead to rapid DKA development because pump users have no long-acting insulin depot. Check ketones immediately.", s: "Endocrine" },
  { q: "Which autoantibody panel is used to confirm the autoimmune etiology of Type 1 diabetes?", o: ["Anti-nuclear antibody (ANA)", "Anti-GAD65, anti-IA-2, IAA, and anti-ZnT8", "Anti-CCP and rheumatoid factor", "Anti-dsDNA and anti-Smith"], a: 1, r: "Islet autoantibodies (anti-GAD65, anti-IA-2, insulin autoantibodies/IAA, anti-ZnT8) confirm the autoimmune etiology of T1DM. The presence of 2 or more autoantibodies in at-risk individuals predicts progression to T1DM with near certainty.", s: "Endocrine" },
  { q: "A nurse is caring for a patient with diabetic peripheral neuropathy. Which assessment finding is expected?", o: ["Unilateral sharp knee pain", "Bilateral numbness and tingling in a stocking-glove pattern, worse at night", "Sudden onset severe headache", "Joint swelling with warmth and erythema"], a: 1, r: "Diabetic peripheral neuropathy presents as bilateral, symmetric numbness, tingling, and burning pain starting distally (feet/toes) and progressing proximally in a 'stocking-glove' distribution. Symptoms are often worse at night.", s: "Endocrine" },
  { q: "The nurse instructs a T1DM patient to check urine ketones when blood glucose exceeds:", o: ["150 mg/dL", "200 mg/dL", "250 mg/dL", "400 mg/dL"], a: 2, r: "Ketone testing is recommended when blood glucose exceeds 250 mg/dL or during illness. Elevated ketones with hyperglycemia suggest evolving DKA requiring immediate intervention. Contact the provider if ketones are moderate or large.", s: "Endocrine" },
  { q: "A patient's continuous glucose monitor shows a rapidly dropping blood glucose trend arrow. What should the nurse anticipate?", o: ["Imminent hyperglycemia", "Potential hypoglycemia requiring proactive carbohydrate intake", "No action needed — CGMs are not reliable", "Increase the insulin dose"], a: 1, r: "A rapidly falling glucose trend on CGM predicts hypoglycemia before it occurs. Proactive intake of 15-20g carbohydrate can prevent hypoglycemia. CGMs provide real-time glucose data and trend information that guide proactive management.", s: "Endocrine" },
  { q: "Which chronic diabetic complication is the leading cause of non-traumatic lower-extremity amputation?", o: ["Diabetic retinopathy", "Diabetic nephropathy", "Diabetic neuropathy", "Diabetic cardiomyopathy"], a: 2, r: "Diabetic neuropathy (peripheral and autonomic) is the leading cause of non-traumatic lower-extremity amputation. Loss of protective sensation leads to unrecognized foot injuries that progress to ulceration, infection, and ultimately amputation.", s: "Endocrine" },
  { q: "The nurse is teaching foot care to a patient with diabetes. Which instructions should be included? Select all that apply.", o: ["Inspect feet daily, including between toes", "Wear well-fitting shoes — never walk barefoot", "Use moisturizer on feet but not between toes", "Soak feet in hot water daily for relaxation", "Cut toenails straight across"], a: 0, r: "Daily inspection, proper footwear, moisturizing (not between toes — moisture promotes fungal infection), and straight-across toenail cutting are all essential. Hot water soaking should be avoided — neuropathy may prevent detection of water temperature, risking burns.", s: "Endocrine", t: "sata", ca: [0, 1, 2, 4] },
  { q: "An adolescent with T1DM has an HbA1c of 7.2%. Which response by the nurse is most appropriate?", o: ["This is excellent control — continue current management", "This indicates poor control requiring immediate hospitalization", "This means you no longer have diabetes", "This is dangerously low and insulin should be decreased"], a: 0, r: "An HbA1c of 7.2% is near the target of <7.0% for most adults and adolescents, representing good glycemic control. Positive reinforcement and continued adherence to the current management plan are appropriate.", s: "Endocrine" },
  { q: "A patient with T1DM is scheduled for surgery at 7 AM. The nurse should:", o: ["Hold all insulin on the morning of surgery", "Administer the usual basal insulin dose — basal insulin should NEVER be stopped", "Give double the morning insulin dose", "Switch to oral diabetic medications preoperatively"], a: 1, r: "Basal insulin prevents ketogenesis and controls hepatic glucose output even during NPO periods. It should be continued (some protocols reduce to 50-80% of usual dose). Blood glucose monitoring every 1-2 hours perioperatively is essential.", s: "Endocrine" },
  { q: "Which mechanism explains why T1DM patients develop weight loss despite eating more?", o: ["Increased physical activity", "Without insulin, the body cannot use glucose for energy and catabolizes fat and muscle protein for fuel, causing weight loss despite polyphagia", "Medication side effects", "Malabsorption syndrome"], a: 1, r: "Without insulin, glucose cannot enter insulin-dependent cells. The body shifts to fat (lipolysis) and protein (proteolysis) catabolism for energy. This produces the classic triad: polyuria (osmotic diuresis), polydipsia (dehydration), polyphagia (cellular starvation), plus weight loss.", s: "Endocrine" },
  { q: "A nurse notes a patient's insulin pen says 'Lantus' but the patient has been administering it before each meal. What is the priority concern?", o: ["The patient is getting appropriate coverage", "Lantus is a long-acting basal insulin — giving it at mealtimes instead of once daily disrupts the dosing regimen and may cause unpredictable glucose fluctuations", "Lantus works the same regardless of timing", "The patient should also add Lantus at bedtime"], a: 1, r: "Lantus (glargine) is a once-daily basal insulin designed to provide 24-hour background coverage. It is NOT a mealtime insulin. Mealtime coverage requires a rapid-acting insulin (lispro, aspart). The nurse should clarify the regimen with the provider.", s: "Endocrine" },
  { q: "The nurse is reviewing a newly diagnosed T1DM patient's islet autoantibody results: anti-GAD65 positive, anti-IA-2 positive. These results:", o: ["Indicate the patient has Type 2 diabetes", "Confirm autoimmune etiology of Type 1 diabetes with high specificity", "Are normal findings in healthy individuals", "Suggest thyroid disease"], a: 1, r: "Positive islet autoantibodies (anti-GAD65, anti-IA-2, IAA, anti-ZnT8) confirm the autoimmune basis of T1DM. The presence of multiple autoantibodies virtually ensures progression to clinical T1DM in pre-symptomatic individuals.", s: "Endocrine" },
  { q: "A nurse is caring for a T1DM patient who reports exercise-induced hypoglycemia. Which preventive strategy should be taught?", o: ["Avoid all exercise permanently", "Eat 15-30g of carbohydrate before exercise and carry fast-acting glucose; may need to reduce pre-exercise insulin dose", "Increase insulin dose before exercise", "Exercise only at bedtime"], a: 1, r: "Exercise increases glucose uptake by muscles independently of insulin (via GLUT4 translocation through AMPK pathway). T1DM patients should eat carbohydrate before exercise, reduce pre-exercise rapid-acting insulin, carry fast-acting glucose, and monitor glucose before, during, and after exercise.", s: "Endocrine" },
  { q: "A patient with T1DM asks about continuous glucose monitoring (CGM). The nurse explains that CGM:", o: ["Eliminates the need for all fingerstick glucose checks", "Provides real-time interstitial glucose readings and trend data, allowing proactive management of glucose fluctuations", "Is not accurate enough for clinical use", "Can only be used with insulin pumps"], a: 1, r: "CGMs measure interstitial glucose every 1-5 minutes, providing real-time data with trend arrows and alerts for hypo/hyperglycemia. While some CGMs are approved for treatment decisions without confirmatory fingersticks, calibration checks may still be needed.", s: "Endocrine" },
  { q: "Which HLA associations are linked to Type 1 diabetes?", o: ["HLA-B27", "HLA-DR3 and HLA-DR4", "HLA-DQ2 and HLA-DQ8 only", "HLA-A2 and HLA-A3"], a: 1, r: "HLA-DR3 and HLA-DR4 are the strongest genetic risk factors for T1DM. The DR3/DR4 heterozygous genotype confers the highest risk (approximately 5% lifetime risk). These HLA class II molecules present beta-cell autoantigens to autoreactive T cells.", s: "Endocrine" },
  { q: "A patient with T1DM reports that their blood glucose before breakfast has been consistently 250-300 mg/dL. The 3 AM blood glucose is 180 mg/dL. This is most consistent with:", o: ["Somogyi effect", "Dawn phenomenon — early morning hyperglycemia from physiologic cortisol and growth hormone surge", "Insulin overdose", "Adequate glucose control"], a: 1, r: "The 3 AM glucose is NOT low (ruling out Somogyi effect, which requires nocturnal hypoglycemia). The consistent morning hyperglycemia with normal 3 AM glucose is the Dawn phenomenon — caused by physiologic early morning cortisol and growth hormone surge. Treatment: adjust basal insulin timing/dose.", s: "Endocrine" },
  { q: "A T1DM patient develops diabetic nephropathy. The nurse expects the provider to prescribe:", o: ["A calcium channel blocker", "An ACE inhibitor or ARB for renal protection", "A thiazide diuretic", "An alpha-blocker"], a: 1, r: "ACE inhibitors (lisinopril, enalapril) or ARBs (losartan, valsartan) are first-line renoprotective agents in diabetic nephropathy. They reduce intraglomerular pressure by dilating the efferent arteriole, slowing progression of proteinuria and renal decline.", s: "Endocrine" },
  { q: "The nurse notes that a T1DM patient's insulin vial appears cloudy and has clumps. What should the nurse do?", o: ["Use the insulin — cloudiness is normal for all insulins", "Discard the insulin — clumping indicates degradation and the insulin should not be used", "Shake vigorously to dissolve the clumps", "Warm the vial under hot water"], a: 1, r: "Clumping, frosting, or unusual cloudiness in insulin indicates protein aggregation and degradation. The insulin has lost potency and should NOT be used. Regular and rapid-acting insulins should be clear; NPH is normally uniformly cloudy.", s: "Endocrine" },
  { q: "Which four biochemical pathways mediate chronic hyperglycemia-induced microvascular damage?", o: ["Glycolysis, Krebs cycle, electron transport, fatty acid synthesis", "Polyol pathway, AGE formation, PKC activation, hexosamine pathway", "Gluconeogenesis, glycogenolysis, lipolysis, proteolysis", "Beta-oxidation, ketogenesis, transamination, deamination"], a: 1, r: "The four pathways of microvascular damage: (1) polyol pathway (sorbitol accumulation), (2) AGE formation (protein cross-linking), (3) PKC activation (vascular permeability changes), (4) hexosamine pathway (transcription factor modification). All are driven by excess intracellular glucose.", s: "Endocrine" },
  { q: "A patient with T1DM and gastroparesis should be taught:", o: ["Eat three large meals daily", "Eat small, frequent, low-fat meals and consider switching to faster-acting insulin analogs", "Increase fiber intake significantly", "Take insulin 2 hours before meals"], a: 1, r: "Diabetic gastroparesis (autonomic neuropathy affecting the vagus nerve) delays gastric emptying, making mealtime insulin timing challenging. Small, frequent, low-fat, low-fiber meals improve emptying. Rapid-acting insulin may be given after meals to better match delayed nutrient absorption.", s: "Endocrine" },
  { q: "A patient with T1DM is prescribed insulin detemir (Levemir). The nurse should teach:", o: ["This is a rapid-acting insulin for mealtimes", "This is a long-acting basal insulin given once or twice daily at the same time each day", "Mix this with rapid-acting insulin in the same syringe", "Take this only when blood glucose exceeds 200"], a: 1, r: "Insulin detemir is a long-acting basal insulin analog with a duration of approximately 12-24 hours. It may require twice-daily dosing (unlike glargine which is typically once daily). It should NOT be mixed with other insulins.", s: "Endocrine" },
  { q: "A parent asks about the risk of their other children developing T1DM. The nurse explains:", o: ["There is no genetic component to T1DM", "Siblings of a child with T1DM have a 5-6% risk (compared to 0.4% in the general population), and screening with islet autoantibody panels can identify at-risk children", "The risk is 100% for all siblings", "Only identical twins are at risk"], a: 1, r: "T1DM has a genetic component with HLA associations. Siblings have approximately 5-6% lifetime risk (vs 0.4% general population). Offspring risk is 3-8% if one parent has T1DM. Autoantibody screening can identify pre-symptomatic at-risk individuals.", s: "Endocrine" },
  { q: "A T1DM patient reports blurred vision that comes and goes with blood glucose fluctuations. The nurse explains:", o: ["This indicates permanent retinopathy", "Glucose fluctuations cause osmotic changes in the lens shape, temporarily affecting vision — this resolves with stable glucose control", "The patient needs immediate laser therapy", "This is unrelated to diabetes"], a: 1, r: "Acute blood glucose fluctuations cause osmotic swelling or shrinkage of the lens, temporarily changing its refractive properties. This is reversible with glucose stabilization. It is distinct from diabetic retinopathy, which involves permanent microvascular damage to the retina.", s: "Endocrine" },
  { q: "When mixing NPH and regular insulin in the same syringe, the nurse should:", o: ["Draw up NPH first, then regular", "Draw up regular (clear) insulin first, then NPH (cloudy) — 'clear before cloudy'", "Shake both vials vigorously", "It doesn't matter which is drawn first"], a: 1, r: "'Clear before cloudy' — draw up regular insulin (clear) first to prevent contamination of the regular insulin vial with NPH particles. If NPH contaminates the regular vial, it would alter the regular insulin's pharmacokinetics in future doses.", s: "Endocrine" },
  { q: "A patient diagnosed with T1DM 3 months ago now requires very little insulin and has near-normal blood glucose levels. The nurse recognizes:", o: ["The patient is cured of diabetes", "This is the 'honeymoon period' — remaining beta cells are temporarily producing more insulin; this will end as autoimmune destruction continues", "The diagnosis was incorrect", "The patient should stop all insulin"], a: 1, r: "The honeymoon period occurs early after T1DM diagnosis when surviving beta cells transiently increase insulin secretion. While encouraging, this is temporary and always ends. Basal insulin should continue even during this period to prevent DKA and preserve residual beta-cell function.", s: "Endocrine" },
  { q: "The nurse is monitoring a T1DM patient for signs of diabetic ketoacidosis. Which findings indicate DKA? Select all that apply.", o: ["Blood glucose >250 mg/dL", "Kussmaul respirations (deep, rapid breathing)", "Fruity/acetone breath odor", "Nausea, vomiting, and abdominal pain", "Bradycardia and hypertension"], a: 0, r: "DKA presents with hyperglycemia (>250), Kussmaul respirations (compensating for metabolic acidosis), fruity breath (exhaled acetone), and GI symptoms (nausea, vomiting, abdominal pain from ketone-induced irritation). Tachycardia and hypotension occur (not bradycardia/hypertension).", s: "Endocrine", t: "sata", ca: [0, 1, 2, 3] },
  { q: "A patient with T1DM and chronic kidney disease (CKD stage 4) may need which insulin adjustment?", o: ["Increased insulin doses", "Decreased insulin doses — the kidneys metabolize insulin, and impaired clearance extends insulin's duration and increases hypoglycemia risk", "Switch to oral hypoglycemics", "No changes needed"], a: 1, r: "The kidneys metabolize and clear approximately 30-50% of circulating insulin. In CKD, impaired renal clearance prolongs insulin's half-life, increasing the risk of hypoglycemia. Insulin doses typically need to be reduced as renal function declines.", s: "Endocrine" },

  // ============================================================
  // DKA / HHS (40 questions)
  // ============================================================
  { q: "A patient presents with blood glucose 450 mg/dL, pH 7.18, HCO3 8 mEq/L, and positive serum ketones. What is the priority intervention?", o: ["Start an insulin drip immediately", "Initiate IV normal saline bolus and check serum potassium before starting insulin", "Administer IV bicarbonate", "Give oral fluids and recheck in 1 hour"], a: 1, r: "IV fluid resuscitation is the FIRST intervention in DKA. NS 1-1.5 L/hour for the first 1-2 hours corrects dehydration. Serum potassium must be ≥3.3 mEq/L before starting insulin — insulin drives K+ intracellularly and can cause fatal hypokalemia.", s: "Endocrine" },
  { q: "During DKA treatment, the patient's blood glucose drops from 500 to 230 mg/dL but the anion gap remains 22 (normal <12). What should the nurse do?", o: ["Stop the insulin drip — the glucose is improving", "Continue the insulin drip and add D5 to the IV fluids to prevent hypoglycemia while clearing remaining ketones", "Switch to subcutaneous insulin", "Administer bicarbonate to close the gap"], a: 1, r: "The elevated anion gap indicates ongoing ketone production. Stopping insulin would cause ketone rebound. Add D5 to IV fluids when glucose reaches 200-250 mg/dL to provide glucose substrate while the insulin infusion continues to suppress ketogenesis and close the anion gap.", s: "Endocrine" },
  { q: "A patient in DKA has a serum potassium of 2.8 mEq/L. The insulin drip is running. What is the nurse's IMMEDIATE action?", o: ["Increase the insulin drip to lower glucose faster", "STOP the insulin drip and notify the provider — K+ is critically low", "Continue current therapy without changes", "Give oral potassium supplements"], a: 1, r: "K+ of 2.8 mEq/L is critically low. Insulin drives potassium intracellularly, which would further drop K+ to potentially fatal levels, risking ventricular fibrillation. The insulin MUST be held and IV potassium aggressively replaced before resuming.", s: "Endocrine" },
  { q: "The nurse is monitoring a child in DKA treatment who suddenly develops headache, vomiting, and decreasing consciousness. What complication should the nurse suspect?", o: ["Improving DKA", "Cerebral edema — the most dangerous complication of DKA treatment in children", "Hypoglycemia", "Medication allergy"], a: 1, r: "Cerebral edema is the leading cause of DKA-related death in children. Rapid fluid administration and too-rapid glucose correction cause osmotic shifts of water into brain cells. Signs: headache, vomiting, altered LOC, bradycardia, hypertension (Cushing response).", s: "Endocrine" },
  { q: "Which assessment finding differentiates HHS from DKA?", o: ["Presence of hyperglycemia", "Serum osmolality >320 mOsm/kg with minimal ketosis, glucose often >600, and pH >7.30", "Polyuria", "Dehydration"], a: 1, r: "HHS is characterized by extreme hyperglycemia (>600, often >1000), profound dehydration, hyperosmolarity (>320 mOsm/kg), and minimal/absent ketosis (pH >7.30). The key differentiator is the ABSENCE of significant ketoacidosis — enough residual insulin exists to prevent ketogenesis.", s: "Endocrine" },
  { q: "How often should blood glucose be monitored during a DKA insulin infusion?", o: ["Every 4 hours", "Every hour", "Every 15 minutes", "Twice daily"], a: 1, r: "Hourly glucose monitoring is required during IV insulin infusion to ensure the target rate of decline (50-75 mg/dL/hour), prevent hypoglycemia, and determine when to add dextrose to IV fluids (glucose reaches 200-250 mg/dL).", s: "Endocrine" },
  { q: "IV bicarbonate in DKA is considered ONLY when:", o: ["The anion gap is elevated", "pH is less than 6.9", "Blood glucose exceeds 500 mg/dL", "All patients with DKA receive bicarbonate"], a: 1, r: "Bicarbonate is reserved for severe, life-threatening acidosis (pH <6.9). It can paradoxically worsen intracellular acidosis, cause hypokalemia, and shift the oxygen dissociation curve leftward. Most DKA resolves with insulin and fluids alone.", s: "Endocrine" },
  { q: "Which electrolyte changes are expected in DKA? Select all that apply.", o: ["Potassium appears normal or elevated despite total body depletion", "Sodium may be falsely low due to hyperglycemia-induced dilution", "Phosphate is depleted through osmotic diuresis", "Magnesium levels increase significantly", "Bicarbonate is consumed by ketoacid buffering"], a: 0, r: "In DKA: K+ appears normal/high (acidosis shifts K+ extracellularly, masking depletion); Na+ appears low (corrected Na accounts for glucose); phosphate is lost via osmotic diuresis; HCO3 is consumed buffering ketoacids. Magnesium is also depleted, not increased.", s: "Endocrine", t: "sata", ca: [0, 1, 2, 4] },
  { q: "The nurse calculates the anion gap: Na 140, Cl 100, HCO3 8. What is the anion gap and what does it indicate?", o: ["32 — consistent with a high anion gap metabolic acidosis from DKA", "12 — normal anion gap", "20 — mild elevation", "8 — below normal"], a: 0, r: "Anion gap = Na - (Cl + HCO3) = 140 - (100 + 8) = 32. Normal is 8-12. A gap of 32 indicates significant accumulation of unmeasured anions (ketone bodies) consistent with severe DKA. The gap must close before transitioning to SQ insulin.", s: "Endocrine" },
  { q: "A patient in DKA has abdominal pain severe enough to mimic an acute surgical abdomen. The nurse understands:", o: ["The patient needs immediate surgery", "Abdominal pain in DKA is caused by ketone-induced gastric irritation and ileus — it typically resolves with DKA treatment", "This is unrelated to DKA", "Antibiotics should be started for peritonitis"], a: 1, r: "Abdominal pain in DKA can be severe and may mimic appendicitis, pancreatitis, or bowel obstruction. It results from ketone-mediated gastric irritation and functional ileus. Serial abdominal assessments are warranted, but pain typically resolves as DKA is treated.", s: "Endocrine" },
  { q: "During DKA treatment, at what rate should blood glucose decrease?", o: ["As rapidly as possible", "50-75 mg/dL per hour", "200 mg/dL per hour", "Less than 20 mg/dL per hour"], a: 1, r: "Target glucose decrease is 50-75 mg/dL/hour. Too-rapid correction increases risk of cerebral edema (especially in children) from osmotic water shifts. If glucose drops faster than 100 mg/dL/hour, decrease the insulin infusion rate.", s: "Endocrine" },
  { q: "The nurse understands that the fruity breath odor in DKA is caused by:", o: ["Dehydration", "Exhaled acetone, a volatile ketone body", "High blood glucose directly", "Lactic acid accumulation"], a: 1, r: "Acetone is a volatile ketone body produced during ketogenesis. Unlike beta-hydroxybutyrate and acetoacetate, acetone is exhaled through the lungs, producing the characteristic fruity (nail polish remover) odor. This is a clinical hallmark of DKA.", s: "Endocrine" },
  { q: "Which type of insulin is given during DKA treatment?", o: ["Insulin glargine IV", "Regular insulin IV continuous infusion", "NPH insulin IV", "Insulin lispro subcutaneously"], a: 1, r: "Regular insulin is the ONLY insulin approved for IV administration. It is given as a continuous infusion (0.1-0.14 units/kg/hour) for precise glucose control. Long-acting and intermediate insulins form depot preparations designed only for subcutaneous injection.", s: "Endocrine" },
  { q: "When can the insulin drip be discontinued in DKA?", o: ["When blood glucose reaches normal levels", "When the anion gap has closed, pH >7.30, HCO3 >18, the patient can eat, and SQ insulin has been given 1-2 hours prior", "After 24 hours regardless of labs", "When potassium normalizes"], a: 1, r: "All four criteria must be met: normalized anion gap (ketones cleared), pH >7.30, HCO3 >18, AND ability to eat. SQ insulin must overlap the IV drip by 1-2 hours to prevent rebound ketoacidosis from the gap between IV and SQ insulin onset.", s: "Endocrine" },
  { q: "A patient with HHS has a blood glucose of 950 mg/dL, serum osmolality 348 mOsm/kg, and is confused. Priority treatment includes:", o: ["Rapid IV insulin bolus", "Aggressive IV fluid resuscitation with 0.9% NS — addressing the severe dehydration is the FIRST priority", "Oral hydration", "IV bicarbonate"], a: 1, r: "HHS involves profound dehydration (8-12L deficit). Aggressive IV NS resuscitation is the first priority — it lowers glucose through hemodilution and improved renal clearance, and restores circulation. Fluid resuscitation alone decreases glucose by 35-70 mg/dL/hour initially.", s: "Endocrine" },
  { q: "What is the average fluid deficit in DKA versus HHS?", o: ["DKA: 1-2 liters; HHS: 3-4 liters", "DKA: 6-9 liters; HHS: 8-12 liters", "Both are equal at 3 liters", "DKA: 10-15 liters; HHS: 1-2 liters"], a: 1, r: "DKA develops acutely (hours) with an average 6-9L deficit. HHS develops insidiously over days to weeks, allowing more severe dehydration (8-12L deficit) because patients lack the ketoacidosis symptoms that prompt earlier medical attention in DKA.", s: "Endocrine" },
  { q: "A nurse is caring for a patient recovering from DKA. The potassium has dropped from 4.2 to 3.1 mEq/L during treatment. The nurse understands:", o: ["This is expected — as acidosis corrects with insulin, potassium shifts back into cells, revealing the true total body depletion", "This indicates a medication error", "Potassium should not change during DKA treatment", "The patient is developing hyperkalemia"], a: 0, r: "In DKA, acidosis drives K+ extracellularly (appearing normal/high). As insulin corrects acidosis and drives K+ back into cells, the true total body K+ depletion is unmasked. This is why K+ must be monitored every 1-2 hours and replaced aggressively.", s: "Endocrine" },
  { q: "The corrected sodium in DKA is calculated because:", o: ["Sodium is always falsely elevated in DKA", "Hyperglycemia draws water into the vascular space, diluting sodium — corrected Na accounts for this osmotic shift", "Sodium testing is inaccurate in DKA", "It is not necessary to correct sodium"], a: 1, r: "High glucose creates an osmotic gradient that pulls water from intracellular to extracellular space, diluting serum sodium. Corrected Na = measured Na + 1.6 × [(glucose - 100)/100]. This helps guide IV fluid selection (0.9% vs 0.45% NS).", s: "Endocrine" },
  { q: "An insulin pump user presents with DKA. After IV treatment, what is the MOST important next step regarding their pump?", o: ["Restart the pump immediately", "Investigate and resolve the pump malfunction (kinked catheter, site inflammation, empty reservoir) before resuming pump therapy", "Discontinue pump permanently", "No investigation is needed"], a: 1, r: "DKA in a pump user usually indicates insulin delivery failure — catheter occlusion, infusion set displacement, or pump malfunction. The cause must be identified and corrected before resuming pump therapy to prevent recurrence. A new infusion set at a new site should be placed.", s: "Endocrine" },
  { q: "Which precipitating factor is the MOST common trigger for DKA?", o: ["Exercise", "Infection or missed insulin doses", "Eating too much sugar", "Emotional stress alone"], a: 1, r: "The two most common DKA precipitants are non-adherence to insulin therapy (missed doses) and infection/acute illness. Infection triggers counter-regulatory hormones that increase insulin requirements. Always search for an underlying infectious trigger in DKA.", s: "Endocrine" },
  { q: "The mortality rate of HHS compared to DKA is:", o: ["Lower in HHS than DKA", "Higher in HHS (10-20%) compared to DKA (1-5%)", "Identical for both conditions", "HHS is never fatal"], a: 1, r: "HHS carries a significantly higher mortality rate (10-20%) compared to DKA (1-5%). This is due to the affected population (elderly with comorbidities), insidious onset allowing severe dehydration, and extreme hyperosmolarity causing neurological complications.", s: "Endocrine" },
  { q: "What monitoring is essential when giving IV potassium replacement to a DKA patient?", o: ["Blood glucose checks only", "Continuous cardiac telemetry monitoring for arrhythmias related to potassium shifts", "Urine output only", "No special monitoring needed"], a: 1, r: "Both hypokalemia and hyperkalemia cause life-threatening cardiac arrhythmias. Continuous telemetry monitors for peaked T waves (hyperkalemia), flat T waves/U waves (hypokalemia), and other conduction disturbances during potassium replacement and insulin therapy.", s: "Endocrine" },
  { q: "SGLT2 inhibitors can precipitate a dangerous form of DKA called:", o: ["Hyperglycemic DKA", "Euglycemic DKA — ketoacidosis with near-normal blood glucose levels", "Hypoglycemic DKA", "Alkalotic DKA"], a: 1, r: "SGLT2 inhibitors promote urinary glucose excretion, keeping blood glucose lower while shifting metabolism toward fatty acid oxidation and ketone production. This can produce DKA with near-normal glucose, delaying recognition. Check ketones if symptoms present regardless of glucose.", s: "Endocrine" },
  { q: "The nurse notes Kussmaul respirations in a DKA patient. This breathing pattern represents:", o: ["Respiratory distress from pneumonia", "Deep, rapid respirations as respiratory compensation for metabolic acidosis — increasing CO2 elimination to raise pH", "Cheyne-Stokes breathing pattern", "Normal breathing during sleep"], a: 1, r: "Kussmaul breathing is the respiratory system's compensatory mechanism for metabolic acidosis. Deep, rapid breathing increases CO2 elimination (respiratory alkalosis component), attempting to restore pH toward normal. It is a sign of significant metabolic acidosis (pH <7.20).", s: "Endocrine" },
  { q: "Which neurological finding is most characteristic of HHS?", o: ["Kussmaul respirations", "Altered mental status ranging from confusion to coma, correlating with serum osmolality >320 mOsm/kg", "Focal seizures", "Normal neurological exam"], a: 1, r: "The hallmark neurological feature of HHS is altered mental status correlating with the degree of hyperosmolarity. Serum osmolality >320 mOsm/kg causes progressive neurological dysfunction from cellular dehydration in the CNS. Focal neurological deficits may mimic stroke.", s: "Endocrine" },
  { q: "A nurse is caring for a patient recovering from DKA. Which criteria indicate readiness for transition to subcutaneous insulin? Select all that apply.", o: ["Anion gap has normalized (closed)", "pH >7.30 and HCO3 >18 mEq/L", "Patient is able to eat", "SQ insulin has been administered 1-2 hours before stopping the drip", "Blood glucose is normal regardless of anion gap"], a: 0, r: "All four criteria must be met before stopping the insulin drip: closed anion gap (indicating ketone clearance), normalized pH/bicarb, ability to eat, and SQ insulin overlap of 1-2 hours. Normal glucose alone is NOT sufficient — ketones may still be present if the anion gap hasn't closed.", s: "Endocrine", t: "sata", ca: [0, 1, 2, 3] },
  { q: "Beta-hydroxybutyrate accounts for approximately what percentage of ketone bodies in DKA?", o: ["25%", "50%", "75%", "100%"], a: 2, r: "Beta-hydroxybutyrate accounts for approximately 75% of ketone bodies in DKA. Standard urine ketone tests (nitroprusside reaction) detect acetoacetate but NOT beta-hydroxybutyrate, potentially underestimating the severity. Point-of-care beta-hydroxybutyrate blood testing is more accurate.", s: "Endocrine" },
  { q: "A patient with DKA is receiving IV insulin at 5 units/hour. The blood glucose drops from 400 to 180 mg/dL in 2 hours. What should the nurse report?", o: ["This is an expected rate of decline", "The glucose is declining TOO rapidly (110 mg/dL/hour exceeds the target of 50-75 mg/dL/hour) — the insulin rate should be decreased", "The insulin should be stopped completely", "No concern — faster is better"], a: 1, r: "The target decline rate is 50-75 mg/dL/hour. A drop of 220 mg/dL in 2 hours (110/hour) is too rapid, increasing the risk of cerebral edema. The insulin rate should be reduced and glucose rechecked in 1 hour.", s: "Endocrine" },
  { q: "DKA in Type 2 diabetes can occur in which circumstance?", o: ["It never occurs in Type 2", "During severe physiologic stress (sepsis, MI, major surgery) when counter-regulatory hormones overwhelm residual insulin secretion, or with SGLT2 inhibitor use", "Only when the patient stops eating", "Only in very young patients"], a: 1, r: "While DKA classically occurs in T1DM, it can occur in T2DM during extreme stress when massive counter-regulatory hormone release overwhelms remaining insulin secretion. 'Ketosis-prone Type 2 diabetes' is also recognized. SGLT2 inhibitors can precipitate euglycemic DKA in T2DM.", s: "Endocrine" },
  { q: "During DKA treatment, phosphate replacement is indicated when:", o: ["Phosphate is mildly low", "Serum phosphate is <1.0 mg/dL with respiratory muscle weakness or hemolytic anemia", "All DKA patients need phosphate", "Phosphate is not monitored in DKA"], a: 1, r: "Routine phosphate replacement is not recommended. However, severe hypophosphatemia (<1.0 mg/dL) can cause respiratory muscle weakness (impaired ventilation), hemolytic anemia (ATP depletion in RBCs), and cardiac dysfunction, warranting replacement.", s: "Endocrine" },
  { q: "A nurse is preparing to start an insulin drip for DKA. The serum potassium is 5.4 mEq/L. What should the nurse do?", o: ["Hold the insulin — potassium is too high", "Start the insulin drip as ordered — K+ ≥3.3 is adequate; hold potassium supplementation and recheck in 2 hours", "Administer potassium before starting insulin", "Request a repeat potassium before any intervention"], a: 1, r: "K+ >5.3 means insulin can safely be started, but potassium supplementation should be held (risk of hyperkalemia). As insulin and acidosis correction drive K+ intracellularly, the level will fall. Recheck K+ in 2 hours and begin replacement when K+ drops to 3.3-5.3 range.", s: "Endocrine" },
  { q: "Counter-regulatory hormones that worsen hyperglycemia in DKA include all EXCEPT:", o: ["Glucagon", "Cortisol", "Insulin", "Epinephrine"], a: 2, r: "Insulin LOWERS blood glucose — it is not a counter-regulatory hormone. The counter-regulatory hormones that oppose insulin and raise glucose are glucagon (hepatic gluconeogenesis/glycogenolysis), cortisol (gluconeogenesis, insulin antagonism), epinephrine/norepinephrine (glycogenolysis), and growth hormone (insulin resistance).", s: "Endocrine" },
  { q: "A patient with DKA is on an insulin drip and IV fluids. The nurse notes the urine output has decreased to 15 mL/hour. This is most likely due to:", o: ["Normal response to treatment", "Worsening dehydration or acute kidney injury from hypovolemia — report to the provider", "Excessive IV fluid administration", "The insulin drip is working"], a: 1, r: "Urine output <0.5 mL/kg/hour indicates inadequate renal perfusion. Despite fluid resuscitation, ongoing osmotic diuresis and persistent hypovolemia can cause prerenal AKI. The nurse should report this finding for additional fluid bolus consideration and renal function monitoring.", s: "Endocrine" },
  { q: "What is the purpose of the corrected sodium calculation in DKA?", o: ["To diagnose hypertension", "To determine the true sodium status by accounting for the osmotic dilution effect of hyperglycemia, which guides IV fluid selection", "To calculate insulin doses", "To predict length of hospital stay"], a: 1, r: "Corrected Na = measured Na + 1.6 × [(glucose-100)/100]. Hyperglycemia causes pseudohyponatremia from osmotic water shifts. If corrected Na is elevated, use hypotonic fluids (0.45% NS) to provide free water. If corrected Na is normal/low, continue isotonic NS.", s: "Endocrine" },
  { q: "After DKA resolution, the patient's previous insulin regimen should be:", o: ["Started immediately without changes", "Resumed (or adjusted) with basal-bolus therapy, and the precipitating cause of DKA must be identified and addressed", "Replaced with oral medications", "Discontinued if glucose is normal"], a: 1, r: "After DKA resolution, the patient transitions back to their previous insulin regimen (or it is adjusted based on total IV insulin requirements). Critically, the precipitating cause must be identified and addressed to prevent recurrence — this may be infection, medication non-adherence, or pump malfunction.", s: "Endocrine" },
  { q: "A nurse is assessing a patient for signs of fluid overload during aggressive DKA fluid resuscitation. Which finding would indicate this complication?", o: ["Crackles in lung fields, distended neck veins, and increasing oxygen requirements", "Improved urine output", "Resolution of tachycardia", "Decreasing blood glucose"], a: 0, r: "Aggressive IV fluid resuscitation can cause fluid overload, especially in patients with underlying cardiac or renal disease. Signs include pulmonary crackles, JVD, peripheral edema, and increasing O2 requirements. Monitor lung sounds and I&O closely during resuscitation.", s: "Endocrine" },
  { q: "Which patient is at HIGHEST risk for developing HHS?", o: ["A 15-year-old with newly diagnosed Type 1 diabetes", "A 78-year-old with Type 2 diabetes, cognitive impairment, and limited access to fluids during a urinary tract infection", "A 30-year-old pregnant woman with gestational diabetes", "A 40-year-old with well-controlled Type 2 diabetes on metformin"], a: 1, r: "HHS typically occurs in elderly T2DM patients who are unable to maintain adequate hydration (cognitive impairment, immobility, limited fluid access) during an acute illness that increases glucose (infection, stroke). The insidious onset over days allows extreme dehydration and hyperglycemia.", s: "Endocrine" },
  { q: "What is Winter's formula and why is it used in DKA?", o: ["It calculates insulin dosing", "Expected pCO2 = (1.5 × HCO3) + 8 ± 2 — it determines if the respiratory compensation for metabolic acidosis is appropriate", "It calculates potassium replacement", "It determines fluid requirements"], a: 1, r: "Winter's formula predicts the expected respiratory compensation (pCO2) for metabolic acidosis. If the actual pCO2 is higher than predicted, there is a concurrent respiratory acidosis (e.g., from exhaustion, pneumonia). If lower, a concurrent respiratory alkalosis exists.", s: "Endocrine" },
  { q: "A patient presents with blood glucose 1,100 mg/dL, serum osmolality 355, pH 7.35, and minimal ketones. This presentation is most consistent with:", o: ["DKA", "HHS", "Lactic acidosis", "Insulin overdose"], a: 1, r: "Extreme hyperglycemia (>600), profound hyperosmolarity (>320), preserved pH (>7.30), and minimal ketosis define HHS. The patient retains enough insulin to suppress ketogenesis but not enough to prevent hyperglycemia. This is a medical emergency with 10-20% mortality.", s: "Endocrine" },

  // ============================================================
  // THYROID DISEASE (40 questions)
  // ============================================================
  { q: "The most sensitive screening test for thyroid dysfunction is:", o: ["Free T4", "Free T3", "TSH", "Thyroid ultrasound"], a: 2, r: "TSH is the most sensitive screening test because the pituitary responds to subtle thyroid hormone changes with amplified TSH changes (logarithmic relationship). A normal TSH effectively rules out primary thyroid dysfunction. Free T4 is ordered when TSH is abnormal.", s: "Endocrine" },
  { q: "A patient with Graves disease develops temperature 105.2°F, heart rate 172, agitation, and delirium. The nurse recognizes:", o: ["Simple fever from infection", "Thyroid storm — a life-threatening thyrotoxic emergency", "Hypoglycemia", "Neuroleptic malignant syndrome"], a: 1, r: "Hyperpyrexia (>104°F), severe tachycardia (>140), and CNS dysfunction (agitation, delirium, psychosis) define thyroid storm — a medical emergency with 10-30% mortality. Treatment requires antithyroid drugs, beta-blockers, corticosteroids, and iodide in sequence.", s: "Endocrine" },
  { q: "In thyroid storm, medications should be given in which specific order?", o: ["Iodide first, then antithyroid drugs", "PTU first, then beta-blocker, then iodide ONE HOUR after the antithyroid drug", "Beta-blockers only", "Aspirin first for fever"], a: 1, r: "Sequence matters: PTU first (blocks synthesis AND T4→T3 conversion), then propranolol (symptom control AND blocks T4→T3 conversion), then iodide 1 hour AFTER PTU (blocks hormone release via Wolff-Chaikoff effect — giving iodide first provides substrate for new hormone synthesis).", s: "Endocrine" },
  { q: "Why is aspirin contraindicated in thyroid storm?", o: ["It is ineffective for high fevers", "Aspirin displaces T4 from thyroid-binding globulin, increasing free T4 levels and worsening thyrotoxicosis", "Aspirin interacts with methimazole", "Aspirin causes hypothyroidism"], a: 1, r: "Aspirin increases free (active) T4 by displacing it from binding proteins, worsening the thyrotoxic state. Use acetaminophen for fever and external cooling measures (cooling blankets, tepid sponging, ice packs to groin and axillae).", s: "Endocrine" },
  { q: "A patient taking methimazole reports sore throat and fever of 101.8°F. The nurse's priority action is:", o: ["Administer acetaminophen and advise rest", "Advise the patient to come immediately for a CBC with differential — these symptoms suggest agranulocytosis", "Continue the medication and schedule a routine appointment", "Switch to a different antithyroid medication at home"], a: 1, r: "Sore throat + fever in a patient on thionamide antithyroid drugs (methimazole/PTU) is a RED FLAG for agranulocytosis — a potentially fatal drop in neutrophils. Immediate CBC with ANC is required. If ANC is critically low, the drug must be stopped and the patient may need isolation and antibiotics.", s: "Endocrine" },
  { q: "After thyroidectomy, the nurse monitors for signs of hypocalcemia every 2-4 hours. Which assessment findings indicate this complication? Select all that apply.", o: ["Positive Chvostek sign (facial twitch when tapping the cheek)", "Positive Trousseau sign (carpopedal spasm with BP cuff inflation)", "Perioral and fingertip tingling/numbness", "Muscle cramps and tetany", "Hypertension and bradycardia"], a: 0, r: "Parathyroid damage during thyroidectomy causes acute hypocalcemia. Signs include: Chvostek sign (facial nerve hyperexcitability), Trousseau sign (carpopedal spasm), perioral/fingertip paresthesias, muscle cramps, tetany, and potentially laryngospasm.", s: "Endocrine", t: "sata", ca: [0, 1, 2, 3] },
  { q: "Which emergency equipment must be at the bedside after thyroidectomy?", o: ["Insulin and glucose monitor", "Calcium gluconate IV and a tracheostomy set", "Chest tube insertion kit", "Central line insertion tray"], a: 1, r: "Post-thyroidectomy emergencies: (1) Hypocalcemia from parathyroid damage — treated with IV calcium gluconate; (2) Airway compromise from hemorrhage/hematoma or recurrent laryngeal nerve injury — requires emergency tracheostomy if intubation fails.", s: "Endocrine" },
  { q: "The nurse teaching levothyroxine administration should instruct the patient to:", o: ["Take with breakfast and calcium supplements", "Take on an empty stomach 30-60 minutes before breakfast with water; separate from calcium and iron by 4 hours", "Take at bedtime with a large meal", "Take whenever convenient — timing does not matter"], a: 1, r: "Levothyroxine absorption is significantly reduced by food, calcium, iron, and antacids. Taking on an empty stomach with plain water maximizes absorption. Separate from calcium/iron by 4 hours. Take at a consistent time daily.", s: "Endocrine" },
  { q: "The nurse evaluates lab results showing elevated TSH and low free T4. This indicates:", o: ["Hyperthyroidism", "Primary hypothyroidism", "Secondary hypothyroidism", "Normal thyroid function"], a: 1, r: "Elevated TSH + low free T4 = primary hypothyroidism. The thyroid gland is failing, so the pituitary increases TSH production in an attempt to stimulate the thyroid. This is the most common pattern seen in Hashimoto thyroiditis.", s: "Endocrine" },
  { q: "Graves ophthalmopathy causes proptosis because:", o: ["Thyroid hormones enlarge the eyeball", "TSI antibodies activate TSH receptors on orbital fibroblasts, causing retro-orbital inflammation, fat expansion, and extraocular muscle swelling within the rigid bony orbit", "Fluid retention behind the eyes", "Increased intraocular pressure from glaucoma"], a: 1, r: "Orbital fibroblasts express TSH receptors. TSI antibodies (specific to Graves) activate these receptors, triggering inflammation, glycosaminoglycan deposition, adipogenesis, and muscle swelling within the confined orbital space, pushing the globe forward (proptosis).", s: "Endocrine" },
  { q: "Which lab result distinguishes Graves disease from other causes of hyperthyroidism?", o: ["Elevated TSH", "Positive thyroid-stimulating immunoglobulins (TSI)", "Low free T4", "Elevated anti-TPO antibodies"], a: 1, r: "TSI antibodies are pathognomonic for Graves disease. They bind and activate TSH receptors, causing autonomous thyroid hormone production. While anti-TPO antibodies can be present in Graves (also found in Hashimoto), TSI is specific to Graves disease.", s: "Endocrine" },
  { q: "A hypothyroid patient presents with hypothermia (94°F), bradycardia (42 bpm), hypoventilation, and decreased consciousness. The nurse suspects:", o: ["Thyroid storm", "Myxedema coma — a life-threatening hypothyroid emergency", "Sepsis", "Stroke"], a: 1, r: "Myxedema coma is the extreme decompensation of hypothyroidism: hypothermia, profound bradycardia, hypoventilation (CO2 narcosis), altered mental status, and non-pitting edema. Mortality is 30-60%. Treatment: IV levothyroxine, IV hydrocortisone, supportive ICU care.", s: "Endocrine" },
  { q: "A patient has been on levothyroxine for 2 weeks and asks why they don't feel better yet. The nurse explains:", o: ["The medication is not working — a different drug should be tried", "Levothyroxine has a long half-life (7 days), so it takes 4-6 weeks to reach steady state and for full therapeutic effect", "The dose is probably too low", "The medication should be changed to T3 supplementation"], a: 1, r: "Levothyroxine's half-life is approximately 7 days. Full steady-state is not achieved for 4-6 weeks. TSH should not be rechecked until this time. Reassure the patient that gradual improvement is expected and the dose will be adjusted based on follow-up TSH.", s: "Endocrine" },
  { q: "Hashimoto thyroiditis is confirmed by which lab findings?", o: ["Positive TSI antibodies", "Positive anti-TPO antibodies (>90% sensitivity), elevated TSH, low free T4", "Low TSH with high T3", "Positive anti-GAD65 antibodies"], a: 1, r: "Hashimoto thyroiditis shows: anti-TPO antibodies positive (>90%), elevated TSH (primary hypothyroidism), and low free T4. Anti-thyroglobulin antibodies may also be present. TSI antibodies indicate Graves, not Hashimoto.", s: "Endocrine" },
  { q: "Radioactive iodine therapy is absolutely contraindicated in:", o: ["Elderly patients", "Pregnancy and breastfeeding", "Male patients", "Patients with goiter"], a: 1, r: "RAI crosses the placenta and concentrates in the fetal thyroid, causing its destruction and congenital hypothyroidism. It is also secreted in breast milk. Pregnancy must be excluded before RAI, and women should wait 6-12 months after RAI before conceiving.", s: "Endocrine" },
  { q: "A post-thyroidectomy patient develops a sudden swelling in the neck with difficulty breathing. What is the priority action?", o: ["Apply ice to the neck", "Notify the surgeon IMMEDIATELY — this suggests hematoma formation causing airway compromise; prepare for emergency opening of the wound and possible tracheostomy", "Administer antibiotics", "Reposition the patient flat"], a: 1, r: "Post-thyroidectomy hemorrhage/hematoma can compress the trachea, causing acute airway obstruction. This is a surgical emergency. The surgeon must be notified immediately. Emergency supplies (suture removal kit, tracheostomy tray) should be at the bedside. Opening the wound at bedside may be necessary.", s: "Endocrine" },
  { q: "Propranolol is preferred over other beta-blockers in hyperthyroidism because:", o: ["It is the only beta-blocker available", "It blocks beta-adrenergic symptoms AND uniquely inhibits peripheral T4-to-T3 conversion", "It has the fewest side effects", "It is available in IV form only"], a: 1, r: "Propranolol has a dual mechanism unique among beta-blockers: (1) non-selective beta-blockade controls tachycardia, tremor, and anxiety; (2) inhibition of type 1 deiodinase blocks peripheral conversion of inactive T4 to active T3, reducing the biological activity of thyroid hormones.", s: "Endocrine" },
  { q: "Methimazole is preferred over PTU in most situations because:", o: ["PTU has more side effects and higher hepatotoxicity risk; methimazole has once-daily dosing and better compliance", "Methimazole is safe in all trimesters of pregnancy", "PTU does not work for hyperthyroidism", "Methimazole has no side effects"], a: 0, r: "Methimazole is preferred due to once-daily dosing (better adherence), lower hepatotoxicity risk (PTU causes rare but fulminant hepatic necrosis), and longer duration of action. Exception: PTU is preferred in the first trimester (methimazole is teratogenic) and in thyroid storm (blocks T4→T3 conversion).", s: "Endocrine" },
  { q: "A nurse assesses a patient with thyroid storm. Which vital signs are most expected?", o: ["Hypothermia, bradycardia, hypotension", "Hyperpyrexia >104°F, tachycardia >140 bpm, potential atrial fibrillation, and wide pulse pressure", "Normal vital signs with anxiety only", "Hypothermia with tachycardia"], a: 1, r: "Thyroid storm presents with hyperpyrexia (>104°F from increased metabolic rate), severe tachycardia (>140 from catecholamine potentiation), atrial fibrillation (10-25% of hyperthyroid patients), and widened pulse pressure from decreased SVR. These reflect the hypermetabolic state.", s: "Endocrine" },
  { q: "The Burch-Wartofsky Point Scale score of ≥45 suggests:", o: ["Hypothyroidism", "Thyroid storm is highly likely", "Normal thyroid function", "Hashimoto thyroiditis"], a: 1, r: "The BWPS clinically scores thyroid storm likelihood by assigning points for temperature, CNS effects, GI/hepatic dysfunction, heart rate, heart failure, and atrial fibrillation. Score ≥45 = highly suggestive; 25-44 = impending storm; <25 = unlikely.", s: "Endocrine" },
  { q: "A patient with Graves disease is considering radioactive iodine ablation. The nurse explains that:", o: ["RAI cures hyperthyroidism without any ongoing medication needs", "RAI destroys thyroid follicular cells, and most patients become permanently hypothyroid requiring lifelong levothyroxine replacement", "RAI only temporarily suppresses the thyroid", "RAI is the same as external radiation therapy"], a: 1, r: "RAI (I-131) is concentrated by thyroid cells via the sodium-iodide symporter and destroys them with localized beta radiation. Most patients become hypothyroid within 6-18 months and require lifelong levothyroxine. This is considered a successful outcome, not a complication.", s: "Endocrine" },
  { q: "Levothyroxine dose adjustments should be monitored by rechecking TSH after:", o: ["24 hours", "1 week", "4-6 weeks", "6 months"], a: 2, r: "Due to levothyroxine's long half-life (~7 days), a new steady state is not reached for 4-6 weeks after any dose change. Checking TSH earlier does not reflect the true impact of the adjustment and may lead to inappropriate further changes.", s: "Endocrine" },
  { q: "Which medication interaction with levothyroxine is most important to teach?", o: ["Aspirin decreases absorption", "Calcium, iron, and aluminum-containing antacids reduce absorption — separate by 4 hours", "Acetaminophen enhances absorption", "No significant drug interactions exist"], a: 1, r: "Calcium, iron, and aluminum-containing antacids chelate levothyroxine in the GI tract, dramatically reducing its absorption. These must be separated by at least 4 hours. Levothyroxine should be taken first thing in the morning on an empty stomach.", s: "Endocrine" },
  { q: "A patient with Graves disease is having an exacerbation of hyperthyroid symptoms. Which assessment is MOST important?", o: ["Skin integrity", "Heart rate and rhythm — thyrotoxicosis can cause atrial fibrillation and tachyarrhythmias", "Visual acuity only", "Joint mobility"], a: 1, r: "Thyrotoxicosis causes tachycardia through catecholamine potentiation and direct chronotropic effects. Atrial fibrillation occurs in 10-25% of hyperthyroid patients. Sustained tachycardia can lead to high-output heart failure. Continuous cardiac monitoring is essential.", s: "Endocrine" },
  { q: "Amiodarone-induced thyroid dysfunction occurs because amiodarone:", o: ["Directly stimulates TSH secretion", "Contains 37% iodine by weight, which can cause both hypothyroidism and hyperthyroidism", "Destroys the pituitary gland", "Has no effect on thyroid function"], a: 1, r: "Amiodarone delivers a massive iodine load with each dose. This can cause hypothyroidism (Wolff-Chaikoff effect — iodine excess inhibits organification) or hyperthyroidism (Jod-Basedow effect — iodine excess fuels autonomous hormone production). Monitor thyroid function every 6 months.", s: "Endocrine" },
  { q: "In thyroid storm, hydrocortisone IV is administered because:", o: ["It treats fever", "Glucocorticoids block T4-to-T3 conversion AND treat potential concomitant adrenal insufficiency from accelerated cortisol metabolism", "It replaces thyroid hormone", "It has no specific role in thyroid storm"], a: 1, r: "Hydrocortisone 100mg IV q8h serves dual purposes: (1) inhibits peripheral conversion of T4 to active T3; (2) addresses potential relative adrenal insufficiency (thyroid hormones increase cortisol metabolism, and the hypermetabolic state increases cortisol demand).", s: "Endocrine" },
  { q: "A patient recently started on PTU for Graves disease asks when symptoms will improve. The nurse responds:", o: ["Immediately", "It takes 4-8 weeks for full effect because PTU blocks NEW hormone synthesis but does not affect already-formed hormone stores, which must be depleted first", "6-12 months", "PTU does not treat hyperthyroidism"], a: 1, r: "PTU (and methimazole) inhibit thyroid peroxidase, blocking iodine organification and new hormone synthesis. However, the thyroid has preformed hormone stores that must be depleted through natural metabolism before clinical improvement occurs (4-8 weeks).", s: "Endocrine" },
  { q: "Subclinical hypothyroidism is characterized by:", o: ["Low TSH with normal T4", "Elevated TSH with normal free T4 — the earliest stage of thyroid failure", "Normal TSH and normal T4", "Suppressed TSH with elevated T3"], a: 1, r: "Subclinical hypothyroidism represents early thyroid failure detected biochemically before clinical symptoms develop. The pituitary detects a subtle decline in thyroid hormone and increases TSH output. Free T4 remains normal due to the compensatory TSH increase.", s: "Endocrine" },
  { q: "What voice change should the nurse monitor for after thyroidectomy?", o: ["Deepening of the voice", "Hoarseness from recurrent laryngeal nerve injury", "Complete loss of speech", "Higher-pitched voice"], a: 1, r: "The recurrent laryngeal nerve (RLN) runs posterior to the thyroid and controls the vocal cord muscles. Surgical damage causes hoarseness (unilateral injury) or stridor/airway obstruction (bilateral injury). The nurse should assess voice quality postoperatively.", s: "Endocrine" },
  { q: "The Wolff-Chaikoff effect is therapeutically utilized in thyroid storm by:", o: ["Withholding iodine", "Administering iodide (SSKI/Lugol solution) AFTER antithyroid drugs — high iodine temporarily inhibits thyroid hormone release", "Giving radioactive iodine", "Removing the thyroid surgically"], a: 1, r: "The Wolff-Chaikoff effect is the thyroid's autoregulatory response to iodine excess, temporarily shutting down organification and hormone release. In thyroid storm, iodide is given 1 hour AFTER antithyroid drugs to block release of stored hormone without providing substrate for new synthesis.", s: "Endocrine" },
  { q: "Which finding differentiates Hashimoto thyroiditis from Graves disease?", o: ["Both present identically", "Hashimoto: anti-TPO positive, elevated TSH, hypothyroid; Graves: TSI positive, suppressed TSH, hyperthyroid", "Hashimoto causes hyperthyroidism", "Graves is treated with levothyroxine"], a: 1, r: "Hashimoto = autoimmune thyroid destruction → hypothyroidism (anti-TPO+, high TSH, low T4). Graves = TSI-mediated thyroid stimulation → hyperthyroidism (TSI+, suppressed TSH, high T4). They are opposite conditions despite both being autoimmune thyroid diseases.", s: "Endocrine" },
  { q: "A patient with hypothyroidism is scheduled for emergency surgery. The nurse should be aware that untreated hypothyroidism increases surgical risk for:", o: ["Bleeding", "Cardiovascular instability including sensitivity to anesthetics, bradycardia, hypothermia, and delayed drug metabolism", "Allergic reactions", "Blood clots only"], a: 1, r: "Hypothyroid patients have decreased cardiac output, reduced metabolic clearance of drugs (prolonging anesthetic effects), impaired thermoregulation (hypothermia risk), and heightened sensitivity to CNS depressants. These factors significantly increase surgical risk.", s: "Endocrine" },
  { q: "Which discharge instructions should the nurse provide to a patient with newly diagnosed hypothyroidism? Select all that apply.", o: ["Take levothyroxine on an empty stomach 30-60 minutes before breakfast", "This is a lifelong medication — do not stop without provider guidance", "Separate from calcium and iron supplements by 4 hours", "Report signs of thyrotoxicosis (palpitations, weight loss, heat intolerance) — may indicate over-replacement", "Take the medication only when symptomatic"], a: 0, r: "All listed instructions are essential except the last: levothyroxine must be taken consistently regardless of symptoms. Empty stomach administration, lifelong adherence, drug separation from calcium/iron, and recognition of over-replacement symptoms are all critical teaching points.", s: "Endocrine", t: "sata", ca: [0, 1, 2, 3] },
  { q: "A patient with Graves disease who is pregnant should be managed with:", o: ["Radioactive iodine", "PTU in the first trimester, potentially switching to methimazole in the second and third trimesters", "High-dose aspirin", "No treatment until after delivery"], a: 1, r: "PTU is preferred in the first trimester (methimazole is associated with aplasia cutis and choanal atresia). After the first trimester, methimazole is preferred due to PTU's risk of fulminant hepatic necrosis. RAI is absolutely contraindicated in pregnancy.", s: "Endocrine" },
  { q: "Thyroid storm is differentiated from simple hyperthyroidism by:", o: ["The presence of elevated thyroid hormones", "Multi-organ decompensation with hyperpyrexia, CNS dysfunction, cardiovascular collapse, and GI/hepatic dysfunction", "Elevated TSH levels", "The presence of goiter"], a: 1, r: "Thyroid storm is NOT simply severe hyperthyroidism — it represents decompensation of the body's compensatory mechanisms. While thyroid hormone levels may not be significantly higher than in uncomplicated hyperthyroidism, the clinical presentation includes life-threatening multi-organ dysfunction.", s: "Endocrine" },
  { q: "A patient's thyroid function tests show: TSH suppressed (<0.01), Free T4 elevated, Free T3 elevated. This indicates:", o: ["Hypothyroidism", "Hyperthyroidism — the pituitary has shut off TSH production in response to excess thyroid hormone", "Normal thyroid function", "Pituitary adenoma"], a: 1, r: "Suppressed TSH + elevated T4/T3 = hyperthyroidism. The excess thyroid hormone provides strong negative feedback to the pituitary, suppressing TSH to undetectable levels. This pattern is seen in Graves disease, toxic multinodular goiter, and thyroid adenoma.", s: "Endocrine" },
  { q: "Thyroid function should be monitored in patients taking which cardiac medication?", o: ["Lisinopril", "Amiodarone — contains 37% iodine by weight", "Metoprolol", "Amlodipine"], a: 1, r: "Amiodarone contains 37% iodine by weight and has a very long half-life (40-55 days). It can cause both hypothyroidism and hyperthyroidism. Thyroid function tests should be monitored every 6 months and whenever symptoms suggest thyroid dysfunction.", s: "Endocrine" },
  { q: "If a patient needs both thyroid hormone AND cortisol replacement, which should be started FIRST?", o: ["Levothyroxine first", "Cortisol (hydrocortisone) FIRST — starting levothyroxine first increases cortisol metabolism and can precipitate adrenal crisis", "Both at the same time", "Neither — they interact"], a: 1, r: "Thyroid hormone increases cortisol metabolism and clearance. Starting levothyroxine in a patient with untreated adrenal insufficiency can precipitate life-threatening adrenal crisis. ALWAYS replace cortisol first, then start levothyroxine.", s: "Endocrine" },

  // ============================================================
  // ADRENAL DISORDERS / HPA AXIS (40 questions)
  // ============================================================
  { q: "A patient with known Addison disease presents with BP 68/38, HR 138, severe abdominal pain, vomiting, and confusion. What is the FIRST priority?", o: ["Draw serum cortisol and ACTH levels", "Administer IV hydrocortisone 100mg STAT and initiate aggressive IV NS resuscitation", "Obtain a CT scan of the abdomen", "Start antibiotics"], a: 1, r: "This is adrenal crisis — an immediately life-threatening emergency. Treatment must NOT be delayed for diagnostic testing. IV hydrocortisone 100mg STAT (addresses cortisol deficiency) plus aggressive NS bolus (addresses volume depletion) are the first priorities.", s: "Endocrine" },
  { q: "Which clinical finding differentiates primary from secondary adrenal insufficiency?", o: ["Fatigue and weakness", "Hyperpigmentation (present ONLY in primary, absent in secondary)", "Hypotension", "Nausea and vomiting"], a: 1, r: "Hyperpigmentation occurs in PRIMARY adrenal insufficiency because destroyed adrenals remove cortisol negative feedback, causing massive ACTH elevation. POMC (ACTH precursor) also produces MSH, which stimulates melanocytes. In SECONDARY (pituitary), ACTH is LOW — no hyperpigmentation.", s: "Endocrine" },
  { q: "A patient who has been taking prednisone 20mg daily for 8 months tells the nurse they want to stop the medication. What should the nurse teach?", o: ["Stop immediately since the condition is resolved", "NEVER stop chronic corticosteroids abruptly — the dose must be tapered gradually over weeks to months to allow HPA axis recovery", "Cut the dose in half and stop after one week", "Switch to OTC ibuprofen instead"], a: 1, r: "Chronic exogenous corticosteroid use suppresses the HPA axis, causing adrenal atrophy. Abrupt discontinuation removes all cortisol (both exogenous and endogenous), causing adrenal crisis. Gradual tapering over weeks to months allows the adrenal glands to resume cortisol production.", s: "Endocrine" },
  { q: "The electrolyte pattern in primary adrenal insufficiency typically shows:", o: ["Hypernatremia and hypokalemia", "Hyponatremia and hyperkalemia", "Normal electrolytes", "Hypercalcemia and hypophosphatemia"], a: 1, r: "In primary AI, loss of aldosterone impairs sodium reabsorption and potassium excretion in the renal distal tubule/collecting duct. This causes hyponatremia (sodium wasting), hyperkalemia (potassium retention), and hypovolemia (water follows sodium).", s: "Endocrine" },
  { q: "Cushing syndrome is characterized by all of the following EXCEPT:", o: ["Moon face and buffalo hump", "Central obesity with thin extremities", "Purple striae and easy bruising", "Hyperpigmentation and weight loss"], a: 3, r: "Hyperpigmentation occurs in ADDISON disease (elevated ACTH/MSH), not Cushing syndrome. Weight LOSS occurs in Addison. Cushing syndrome features: central obesity, moon face, buffalo hump, purple striae, easy bruising, hyperglycemia, immunosuppression, proximal muscle wasting.", s: "Endocrine" },
  { q: "A patient with adrenal insufficiency is scheduled for a dental extraction. What medication adjustment should the nurse anticipate?", o: ["No changes needed", "Double the usual hydrocortisone dose on the day of the procedure (stress dosing for minor stress)", "Triple the dose and give IV steroids", "Stop hydrocortisone the day before"], a: 1, r: "Stress dosing: minor stress (dental, mild illness) = double the usual daily dose. Moderate stress (moderate surgery, severe illness) = triple dose or 50mg q8h. Major stress (septic shock, major surgery) = 100mg IV q8h. Taper back to maintenance as stress resolves.", s: "Endocrine" },
  { q: "The ACTH stimulation (cosyntropin) test is used to:", o: ["Screen for thyroid disease", "Diagnose adrenal insufficiency — a normal response shows cortisol rising to >18-20 mcg/dL; failure to respond confirms AI", "Measure blood glucose", "Evaluate kidney function"], a: 1, r: "The ACTH stimulation test is the gold standard for AI diagnosis. Synthetic ACTH (cosyntropin) 250 mcg is given IV. Normal adrenals respond by producing cortisol >18-20 mcg/dL within 30-60 minutes. Failure to respond confirms adrenal insufficiency.", s: "Endocrine" },
  { q: "Fludrocortisone is prescribed for primary but NOT secondary adrenal insufficiency because:", o: ["It is too expensive for secondary AI", "Aldosterone production (regulated by RAAS, not ACTH) is preserved in secondary AI, so mineralocorticoid replacement is unnecessary", "Fludrocortisone is not available", "Secondary AI does not exist"], a: 1, r: "Aldosterone is regulated primarily by RAAS and potassium levels — NOT by ACTH. In secondary AI (pituitary ACTH deficiency), the adrenal zona glomerulosa continues producing aldosterone normally. Only primary AI (adrenal destruction) loses both cortisol AND aldosterone.", s: "Endocrine" },
  { q: "A patient with Cushing syndrome should be monitored for:", o: ["Hypoglycemia", "Hyperglycemia, osteoporosis, immunosuppression/infections, and proximal muscle weakness", "Weight loss and hypotension", "Hypothyroidism"], a: 1, r: "Chronic cortisol excess causes: hyperglycemia (gluconeogenesis, insulin resistance), osteoporosis (osteoblast suppression), immunosuppression (opportunistic infections), proximal myopathy (protein catabolism), and psychiatric effects (euphoria, depression, psychosis).", s: "Endocrine" },
  { q: "The nurse provides the following discharge instructions for a patient with adrenal insufficiency. Select all that apply.", o: ["Wear a medical alert bracelet at all times", "Carry an emergency hydrocortisone injection kit", "Know stress dosing rules — double for minor illness, triple for major stress", "Never stop corticosteroids abruptly", "Take medication only when symptomatic"], a: 0, r: "All are essential EXCEPT taking medication only when symptomatic — hydrocortisone must be taken daily as prescribed to replace deficient cortisol. The four pillars: medical alert ID, emergency injection kit, stress dosing knowledge, and never abrupt discontinuation.", s: "Endocrine", t: "sata", ca: [0, 1, 2, 3] },
  { q: "A patient presents with moon face, buffalo hump, purple abdominal striae, and blood glucose of 246 mg/dL. The overnight dexamethasone suppression test shows failure to suppress cortisol. This is consistent with:", o: ["Addison disease", "Cushing syndrome", "Hypothyroidism", "Type 1 diabetes"], a: 1, r: "The clinical features (Cushingoid appearance, hyperglycemia) combined with failure to suppress cortisol on the DST (indicating autonomous cortisol production not regulated by normal HPA feedback) confirms Cushing syndrome.", s: "Endocrine" },
  { q: "A patient on chronic prednisone therapy is scheduled for major abdominal surgery. What perioperative steroid management should the nurse anticipate?", o: ["Continue the regular oral dose", "IV hydrocortisone 100mg before surgery, then 50-100mg q8h during the perioperative period, tapering back to maintenance as the patient recovers", "Stop prednisone 1 week before surgery", "No changes to steroid therapy needed"], a: 1, r: "Patients on chronic steroids have suppressed HPA axes and cannot mount adequate cortisol responses to surgical stress. IV hydrocortisone stress dosing provides cortisol coverage. Tapering back to maintenance occurs as the surgical stress resolves (typically over 1-3 days).", s: "Endocrine" },
  { q: "Waterhouse-Friderichsen syndrome is:", o: ["Chronic adrenal insufficiency from autoimmune disease", "Acute bilateral adrenal hemorrhage from meningococcal septicemia causing fulminant adrenal crisis, DIC, and purpura fulminans", "A thyroid disorder", "A pituitary tumor"], a: 1, r: "Waterhouse-Friderichsen is a devastating complication of meningococcemia: DIC causes bilateral adrenal hemorrhagic infarction, leading to acute adrenal crisis with cardiovascular collapse and purpura fulminans. Immediate treatment: IV hydrocortisone + antibiotics.", s: "Endocrine" },
  { q: "How long can HPA axis suppression persist after discontinuing chronic corticosteroid therapy?", o: ["24 hours", "1 week", "Up to 12 months", "HPA axis recovers immediately"], a: 2, r: "Chronic exogenous steroids cause adrenal atrophy. After discontinuation, adrenal recovery may take up to 12 months (sometimes longer). Patients remain at risk for adrenal crisis during this period and should carry medical alert identification and emergency hydrocortisone.", s: "Endocrine" },
  { q: "When is cortisol normally highest during the day?", o: ["Midnight", "Early morning 6-8 AM", "Mid-afternoon", "Evening"], a: 1, r: "Cortisol follows a circadian rhythm peaking at 6-8 AM (the cortisol awakening response) to prepare the body for daytime metabolic demands. It reaches its nadir at midnight. This pattern is disrupted in Cushing syndrome (loss of circadian variation).", s: "Endocrine" },
  { q: "A critically ill patient in septic shock has a random cortisol of 8 mcg/dL despite maximum vasopressor support. This suggests:", o: ["Normal adrenal function", "Relative adrenal insufficiency — cortisol should be significantly elevated during severe stress", "Cushing syndrome", "The cortisol result is falsely low"], a: 1, r: "During severe physiologic stress, cortisol should rise to 25-30+ mcg/dL. A level of 8 mcg/dL in septic shock represents relative adrenal insufficiency. Empiric hydrocortisone 200mg/day (50mg q6h or continuous infusion) may improve hemodynamic response.", s: "Endocrine" },
  { q: "Cortisol masks signs of infection by:", o: ["Killing bacteria directly", "Suppressing the inflammatory response — reducing fever, WBC recruitment, and inflammatory markers, making infections harder to detect", "Improving immunity", "Having no effect on infection"], a: 1, r: "Cortisol suppresses virtually all inflammatory responses: reduces cytokine production, inhibits NF-kB, reduces neutrophil migration, and blunts the febrile response. Patients on chronic steroids may have serious infections with minimal clinical signs — maintain a LOW threshold for infection workup.", s: "Endocrine" },
  { q: "Cushing disease specifically refers to:", o: ["Any cause of cortisol excess", "Cushing syndrome caused by an ACTH-secreting pituitary adenoma — the most common endogenous cause", "Iatrogenic Cushing from steroid use", "Cushing syndrome from an adrenal tumor"], a: 1, r: "Cushing DISEASE = pituitary adenoma producing excess ACTH (70% of endogenous Cushing). Cushing SYNDROME = any cause of cortisol excess (iatrogenic most common overall, then pituitary, ectopic ACTH, adrenal tumors). The distinction is important for treatment planning.", s: "Endocrine" },
  { q: "A patient with primary adrenal insufficiency has markedly increased skin pigmentation in the palmar creases and oral mucosa. What causes this?", o: ["Sun exposure", "Elevated ACTH and melanocyte-stimulating hormone (MSH) — both derived from the same POMC precursor molecule", "Iron deposition from hemochromatosis", "Medication side effect"], a: 1, r: "In primary AI, adrenal destruction removes cortisol negative feedback, causing massive POMC gene activation. POMC is cleaved into ACTH AND MSH (melanocyte-stimulating hormone). Elevated MSH stimulates melanocytes, causing hyperpigmentation in skin creases, buccal mucosa, and sun-exposed areas.", s: "Endocrine" },
  { q: "A nurse is caring for a patient after bilateral adrenalectomy. What lifelong medications will this patient require?", o: ["Only hydrocortisone", "Both hydrocortisone (glucocorticoid replacement) AND fludrocortisone (mineralocorticoid replacement)", "Only fludrocortisone", "No medications needed"], a: 1, r: "Bilateral adrenalectomy removes all adrenal cortical hormone production. Lifelong replacement of both glucocorticoid (hydrocortisone) and mineralocorticoid (fludrocortisone) is essential. The patient also needs education on stress dosing, medical alert ID, and emergency injection kit.", s: "Endocrine" },
  { q: "The most common cause of adrenal insufficiency worldwide is:", o: ["Autoimmune adrenalitis in developed countries; tuberculosis in developing countries", "Pituitary tumors", "Medications", "Congenital adrenal hyperplasia"], a: 0, r: "In developed countries, autoimmune adrenalitis (80% of cases) is the leading cause. Globally, tuberculosis remains the most common cause due to TB's propensity to infect the adrenal glands and cause granulomatous destruction.", s: "Endocrine" },
  { q: "Hydrocortisone dosing for chronic adrenal insufficiency should mimic:", o: ["Random timing", "The normal circadian cortisol pattern: 2/3 of the daily dose in the morning, 1/3 in the afternoon", "Equal doses throughout the day", "All at bedtime"], a: 1, r: "Normal cortisol peaks in the early morning and declines through the day. Replacement should mimic this: 2/3 of the total daily dose (10-15mg) in the morning upon waking, 1/3 (5-10mg) in the early afternoon. This improves energy, sleep, and overall well-being.", s: "Endocrine" },
  { q: "A patient with Cushing syndrome has thin, fragile skin with multiple ecchymoses. What should the nursing care plan include?", o: ["Vigorous skin care with exfoliating scrubs", "Gentle skin handling, padding bony prominences, avoiding adhesive tape, and careful repositioning to prevent skin tears", "Applying tight compression garments", "Using hot packs to improve circulation"], a: 1, r: "Chronic cortisol excess inhibits collagen synthesis, making skin thin, fragile, and prone to tears and bruising. The nursing care plan should include gentle handling, skin protection measures, frequent repositioning, and monitoring for skin breakdown.", s: "Endocrine" },
  { q: "Stress-induced hyperglycemia in hospitalized patients occurs because:", o: ["They are eating too much hospital food", "Cortisol promotes hepatic gluconeogenesis and insulin resistance as part of the physiologic stress response", "Insulin is being withheld inappropriately", "IV fluids contain too much glucose"], a: 1, r: "During physiologic stress, cortisol and catecholamines increase hepatic glucose production and peripheral insulin resistance, raising blood glucose even in non-diabetic patients. Stress hyperglycemia is associated with worse outcomes and may require insulin management.", s: "Endocrine" },
  { q: "Which nursing assessment is MOST important when a patient with known adrenal insufficiency develops a fever and vomiting?", o: ["Check for skin rash", "Assess hemodynamic stability (BP, HR) for signs of evolving adrenal crisis — vomiting may prevent oral steroid absorption", "Review dietary intake", "Check visual acuity"], a: 1, r: "Vomiting prevents oral corticosteroid absorption, and fever indicates physiologic stress requiring increased cortisol. This combination puts the patient at high risk for adrenal crisis. Assess hemodynamic stability, consider IM emergency hydrocortisone injection, and seek emergency care.", s: "Endocrine" },
  { q: "Dexamethasone is NOT appropriate as sole replacement therapy in primary adrenal insufficiency because:", o: ["It is too expensive", "Dexamethasone has NO mineralocorticoid activity — patients with primary AI also need aldosterone replacement (fludrocortisone)", "It is less potent than hydrocortisone", "It has too many side effects"], a: 1, r: "Unlike hydrocortisone (which has some mineralocorticoid activity at physiologic doses), dexamethasone has zero mineralocorticoid effect. Primary AI involves loss of BOTH cortisol and aldosterone. Separate mineralocorticoid replacement (fludrocortisone) is essential.", s: "Endocrine" },
  { q: "A patient with Cushing syndrome develops a vertebral compression fracture. The nurse understands this occurred because:", o: ["The patient fell", "Chronic cortisol excess suppresses osteoblasts and enhances osteoclast activity, causing osteoporosis and pathological fractures", "Calcium intake was adequate but not absorbed", "Vertebral fractures are unrelated to Cushing syndrome"], a: 1, r: "Glucocorticoid-induced osteoporosis is a major complication of Cushing syndrome. Cortisol directly suppresses osteoblast function and survival, enhances osteoclast activity through increased RANKL expression, reduces intestinal calcium absorption, and increases renal calcium excretion.", s: "Endocrine" },
  { q: "Which test is most useful for screening for Cushing syndrome?", o: ["Morning serum cortisol alone", "24-hour urine free cortisol or overnight 1mg dexamethasone suppression test", "Random ACTH level", "Thyroid function tests"], a: 1, r: "Two first-line screening tests: (1) 24-hour urine free cortisol (elevated in Cushing); (2) overnight 1mg DST (failure to suppress morning cortisol to <1.8 mcg/dL suggests autonomous cortisol production). Late-night salivary cortisol is a third option.", s: "Endocrine" },
  { q: "A nurse caring for a patient in adrenal crisis should monitor blood glucose because:", o: ["Cortisol excess causes hyperglycemia", "Cortisol deficiency impairs gluconeogenesis, leading to life-threatening hypoglycemia", "Blood glucose is always normal in adrenal crisis", "Insulin resistance increases"], a: 1, r: "Cortisol is essential for hepatic gluconeogenesis. Without cortisol, the liver cannot adequately produce glucose, especially during fasting or stress. Hypoglycemia in adrenal crisis can be severe and life-threatening. IV dextrose should be given as needed.", s: "Endocrine" },
  { q: "The nurse should advise a patient with adrenal insufficiency to seek emergency care if:", o: ["They have a mild headache", "They experience vomiting (preventing oral steroid absorption), fever, severe illness, or any situation requiring significantly increased cortisol", "They feel slightly fatigued", "They miss one dose of medication"], a: 1, r: "Vomiting prevents oral steroid absorption; fever and illness increase cortisol demand. These situations can rapidly precipitate adrenal crisis if cortisol requirements are not met. The patient should administer their IM emergency hydrocortisone and seek emergency care.", s: "Endocrine" },
  { q: "Which anti-inflammatory effect of cortisol is most clinically significant in masking infection?", o: ["Increased body temperature", "Suppression of NF-kB transcription factor, reducing production of ALL pro-inflammatory cytokines, chemokines, and adhesion molecules", "Enhanced WBC migration to sites of infection", "Increased antibody production"], a: 1, r: "Cortisol's primary anti-inflammatory mechanism is suppression of NF-kB, the master transcription factor for inflammatory mediators. This globally reduces cytokine production, leukocyte recruitment, and the febrile response, making infections clinically silent until advanced.", s: "Endocrine" },
  { q: "A patient on chronic prednisone develops new-onset diabetes. This is an example of:", o: ["Type 1 diabetes", "Steroid-induced diabetes from cortisol's effect on hepatic gluconeogenesis and peripheral insulin resistance", "Coincidental Type 2 diabetes", "Lab error"], a: 1, r: "Glucocorticoid-induced diabetes results from cortisol's metabolic effects: increased hepatic gluconeogenesis (PEPCK and G6Pase upregulation), decreased peripheral glucose uptake (GLUT4 downregulation), and impaired insulin secretion. It may require insulin therapy during steroid use.", s: "Endocrine" },
  { q: "Ectopic ACTH production causing Cushing syndrome is most commonly seen with:", o: ["Breast cancer", "Small cell lung cancer", "Prostate cancer", "Brain tumors"], a: 1, r: "Small cell lung cancer is the most common cause of ectopic ACTH syndrome (accounting for ~50% of ectopic cases). Other sources include bronchial carcinoid tumors, thymomas, medullary thyroid cancer, and pheochromocytoma. Ectopic ACTH is typically associated with rapid onset and severe hypokalemia.", s: "Endocrine" },
  { q: "A patient taking hydrocortisone 15mg AM and 10mg PM for Addison disease develops pneumonia. How should the hydrocortisone dose be adjusted?", o: ["No adjustment needed", "Double to triple the dose (moderate illness stress dosing) and contact the provider for evaluation", "Reduce the dose to prevent immunosuppression", "Stop hydrocortisone completely"], a: 1, r: "Pneumonia represents moderate physiologic stress requiring increased cortisol. The patient should double or triple their maintenance dose and contact their provider. If vomiting prevents oral absorption, the emergency IM hydrocortisone injection should be used and emergency care sought.", s: "Endocrine" },
  { q: "A patient with Cushing syndrome develops proximal muscle weakness. This occurs because:", o: ["Inactivity causes deconditioning", "Cortisol promotes skeletal muscle protein catabolism, preferentially affecting proximal muscles (shoulder and hip girdle)", "Vitamin D deficiency from cortisol", "Peripheral neuropathy"], a: 1, r: "Chronic cortisol excess causes protein catabolism in skeletal muscle, with proximal muscles (shoulders, thighs) being preferentially affected. This produces the characteristic thin extremities with central obesity. Assessment includes testing the patient's ability to rise from a chair without using arms.", s: "Endocrine" },
  { q: "Which type of Cushing syndrome is MOST common overall?", o: ["Cushing disease from pituitary adenoma", "Iatrogenic (exogenous) Cushing syndrome from chronic corticosteroid therapy", "Ectopic ACTH from lung cancer", "Adrenal carcinoma"], a: 1, r: "Iatrogenic Cushing syndrome from chronic glucocorticoid therapy is by far the most common cause overall. It develops in patients receiving prednisone, dexamethasone, or other systemic corticosteroids for conditions such as asthma, RA, SLE, organ transplant rejection, and inflammatory bowel disease.", s: "Endocrine" },
  { q: "A patient's ACTH level is elevated while cortisol is low. This localizes the problem to:", o: ["The pituitary gland", "The adrenal gland (primary adrenal insufficiency) — the pituitary is appropriately increasing ACTH to stimulate the failing adrenals", "The hypothalamus", "The kidneys"], a: 1, r: "Elevated ACTH + low cortisol = PRIMARY adrenal insufficiency. The adrenal glands are destroyed/dysfunctional, so the pituitary increases ACTH output in an attempt to stimulate cortisol production. In secondary AI (pituitary problem), ACTH would be LOW.", s: "Endocrine" },
  { q: "A patient taking chronic corticosteroids should be counseled about which routine health screenings? Select all that apply.", o: ["Bone density screening (glucocorticoid-induced osteoporosis)", "Glucose monitoring (steroid-induced diabetes)", "Eye examinations (posterior subcapsular cataracts and glaucoma)", "Blood pressure monitoring (cortisol-induced hypertension)", "Thyroid function tests"], a: 0, r: "Chronic corticosteroid complications requiring screening: osteoporosis (DEXA scan), diabetes (glucose monitoring), cataracts and glaucoma (ophthalmology), hypertension (BP monitoring), infection surveillance, weight gain, and psychiatric effects.", s: "Endocrine", t: "sata", ca: [0, 1, 2, 3] },

  // ============================================================
  // LEUKEMIA (40 questions)
  // ============================================================
  { q: "A child with ALL has an ANC of 320 and develops a temperature of 100.8°F. What is the priority nursing action?", o: ["Administer acetaminophen and recheck temperature in 1 hour", "Obtain blood cultures and administer broad-spectrum antibiotics within 1 hour", "Apply cooling measures", "Wait for morning labs before acting"], a: 1, r: "Febrile neutropenia (ANC <500 + temperature >100.4°F) is a medical emergency. Infection is the leading cause of death in leukemia patients. Blood cultures from 2 sites and empiric IV broad-spectrum antibiotics must be initiated within 1 HOUR — do not wait for culture results.", s: "Hematology" },
  { q: "Auer rods on a peripheral blood smear are pathognomonic for which type of leukemia?", o: ["ALL", "AML", "CLL", "CML"], a: 1, r: "Auer rods are needle-shaped cytoplasmic inclusions of fused azurophilic granules (crystallized myeloperoxidase) found ONLY in myeloid blasts. They are pathognomonic for AML and are NEVER seen in ALL. Multiple Auer rods ('faggot cells') indicate APL.", s: "Hematology" },
  { q: "A patient starting chemotherapy for ALL should receive TLS prophylaxis. What does this include? Select all that apply.", o: ["Aggressive IV hydration (3L/m²/day)", "Allopurinol or rasburicase to reduce uric acid", "Electrolyte monitoring every 4-6 hours (K+, PO4, Ca2+, uric acid, creatinine)", "Continuous cardiac monitoring for hyperkalemia", "Protein restriction"], a: 0, r: "TLS prophylaxis includes: aggressive hydration (to promote renal clearance), allopurinol/rasburicase (to prevent/treat hyperuricemia), frequent electrolyte monitoring (to detect dangerous levels), and cardiac monitoring (hyperkalemia causes fatal arrhythmias).", s: "Hematology", t: "sata", ca: [0, 1, 2, 3] },
  { q: "Tumor lysis syndrome is characterized by which electrolyte pattern?", o: ["Low K+, low PO4, high Ca2+", "High K+, high PO4, LOW Ca2+, high uric acid", "Normal electrolytes with elevated glucose", "Low Na+ and high Cl-"], a: 1, r: "TLS: massive cancer cell lysis releases K+ (hyperkalemia → arrhythmias), PO4 (hyperphosphatemia → binds Ca2+ → hypocalcemia → tetany/seizures), nucleic acids → uric acid (hyperuricemia → renal tubular obstruction → AKI). Occurs 12-72 hours post-chemo.", s: "Hematology" },
  { q: "ALL is the most common childhood malignancy. What is the approximate cure rate in children?", o: ["30%", "50%", "70%", "90%"], a: 3, r: "Modern multi-agent chemotherapy protocols have achieved approximately 90% cure rates in childhood ALL — one of the greatest success stories in oncology. Adult ALL has lower cure rates (40-50%). Prognosis depends on age, WBC at diagnosis, and cytogenetics.", s: "Hematology" },
  { q: "Vincristine administration is STRICTLY limited to which route?", o: ["Intrathecal", "Intravenous ONLY — intrathecal administration is FATAL", "Intramuscular", "Subcutaneous"], a: 1, r: "Intrathecal vincristine causes ascending motor and sensory neuropathy, paralysis, and death. It must be given IV push ONLY. Many institutions have safety protocols mandating separate administration times and locations from intrathecal medications.", s: "Hematology" },
  { q: "A patient with AML-M3 (APL) is started on ATRA. On day 5, the patient develops fever, dyspnea, weight gain of 4 kg, and bilateral pulmonary infiltrates. What should the nurse suspect?", o: ["Hospital-acquired pneumonia", "Fluid overload from IV fluids", "Differentiation syndrome — requires immediate IV dexamethasone", "Tumor lysis syndrome"], a: 2, r: "Differentiation syndrome occurs as APL promyelocytes mature into neutrophils under ATRA, releasing massive cytokines causing capillary leak. Symptoms: fever, dyspnea, pulmonary infiltrates, weight gain, effusions. Treatment: immediate IV dexamethasone 10mg q12h — delay can be fatal.", s: "Hematology" },
  { q: "DIC is present at diagnosis in approximately what percentage of APL patients?", o: ["10%", "30%", "50%", "80%"], a: 3, r: "DIC occurs in approximately 80% of APL patients at presentation. Granule-rich promyelocytes release tissue factor and cancer procoagulant, activating systemic coagulation. DIC is the most common cause of early death in APL. Early ATRA initiation dramatically reduces DIC mortality.", s: "Hematology" },
  { q: "A nurse is implementing neutropenic precautions for a patient with leukemia. Which interventions are appropriate? Select all that apply.", o: ["Private room with strict hand hygiene", "No fresh flowers or standing water", "Neutropenic diet (no raw fruits/vegetables)", "Avoid rectal temperatures and procedures", "Allow unlimited visitors"], a: 0, r: "Neutropenic precautions: private room, strict hand hygiene (most important), no fresh flowers/plants/standing water (Aspergillus risk), neutropenic diet (cooked foods only), avoid rectal procedures (mucosal injury + infection risk). Visitors should be limited and screened for illness.", s: "Hematology", t: "sata", ca: [0, 1, 2, 3] },
  { q: "The AML '7+3' induction regimen consists of:", o: ["7 days of rest and 3 days of chemotherapy", "7 days of continuous IV cytarabine plus 3 days of IV daunorubicin", "7 different drugs given over 3 weeks", "7 units of blood product support and 3 antibiotics"], a: 1, r: "The '7+3' regimen is the backbone of AML induction: 7 consecutive days of continuous IV cytarabine (24-hour infusion) plus 3 days of IV daunorubicin (an anthracycline). This produces severe aplasia lasting 3-4 weeks, requiring hospitalization for supportive care.", s: "Hematology" },
  { q: "Why are blood products for leukemia patients irradiated?", o: ["To warm the blood for transfusion", "To inactivate donor lymphocytes and prevent transfusion-associated graft-versus-host disease (TA-GVHD)", "To kill bacteria in the blood", "To increase platelet count"], a: 1, r: "Irradiation inactivates donor T lymphocytes that could engraft in the severely immunocompromised leukemia patient and attack host tissues (TA-GVHD). TA-GVHD is nearly always fatal (>90% mortality), making irradiation essential for immunocompromised recipients.", s: "Hematology" },
  { q: "Leukostasis is a medical emergency that occurs when:", o: ["Hemoglobin drops below 7 g/dL", "WBC exceeds 100,000/uL and blast cells cause sludging in pulmonary and cerebral microvasculature", "Platelet count drops below 10,000", "Uric acid exceeds 15 mg/dL"], a: 1, r: "Leukostasis occurs with extreme leukocytosis (>100,000). Large, sticky blast cells sludge in pulmonary capillaries (respiratory failure, hypoxemia) and cerebral vasculature (headache, confusion, stroke). Emergent leukapheresis and hydroxyurea for cytoreduction are required.", s: "Hematology" },
  { q: "A nurse is caring for a patient with AML. The patient's platelet count is 8,000/uL. Which intervention is CONTRAINDICATED?", o: ["Administering platelet transfusion", "Using a soft-bristle toothbrush", "Taking a rectal temperature", "Applying pressure to venipuncture sites"], a: 2, r: "Rectal temperatures, rectal suppositories, and enemas are CONTRAINDICATED in thrombocytopenic patients (platelets <20,000 — but especially <10,000). Rectal mucosa is highly vascular, and even minor trauma can cause uncontrollable hemorrhage.", s: "Hematology" },
  { q: "Daunorubicin cardiotoxicity is:", o: ["Reversible and temporary", "Cumulative and dose-dependent — cardiac function (ECHO/MUGA) must be monitored; lifetime dose limit is 550 mg/m²", "Not a clinical concern", "Only seen in pediatric patients"], a: 1, r: "Anthracycline (daunorubicin/doxorubicin) cardiotoxicity is cumulative, dose-dependent, and often irreversible. It causes dilated cardiomyopathy from free radical damage to cardiac myocytes. Monitor ejection fraction before and during therapy. Lifetime limit: 550 mg/m² (lower with mediastinal radiation).", s: "Hematology" },
  { q: "A nurse is monitoring a patient after chemotherapy for signs of tumor lysis syndrome. Which finding requires IMMEDIATE intervention?", o: ["Potassium 3.8 mEq/L", "Potassium 6.8 mEq/L with peaked T waves on the cardiac monitor", "Calcium 9.0 mg/dL", "Phosphorus 4.0 mg/dL"], a: 1, r: "Potassium 6.8 mEq/L is dangerously elevated. Peaked T waves indicate cardiac effects of hyperkalemia, which can progress rapidly to widened QRS, ventricular fibrillation, and cardiac arrest. Immediate treatment: IV calcium gluconate (cardioprotection), insulin+glucose, sodium bicarbonate, kayexalate.", s: "Hematology" },
  { q: "Rasburicase is contraindicated in patients with:", o: ["Diabetes", "G6PD deficiency", "Hypertension", "Liver disease"], a: 1, r: "Rasburicase converts uric acid to allantoin, generating H2O2 as a byproduct. G6PD-deficient patients cannot generate adequate NADPH to neutralize this oxidative stress, leading to severe hemolytic anemia and methemoglobinemia. Screen for G6PD before administration.", s: "Hematology" },
  { q: "The nurse is calculating the ANC. WBC is 3,200, with 15% neutrophils and 5% bands. The ANC is:", o: ["640 — severely neutropenic (ANC <1000)", "1,600", "320", "3,200"], a: 0, r: "ANC = WBC × (% neutrophils + % bands) = 3,200 × (0.15 + 0.05) = 3,200 × 0.20 = 640. An ANC <1,000 requires neutropenic precautions. ANC <500 represents severe neutropenia with high infection risk.", s: "Hematology" },
  { q: "A child with ALL complains of severe bone pain, especially in the legs. This is caused by:", o: ["Growing pains", "Bone marrow expansion from blast cell proliferation within the marrow cavity", "Vitamin D deficiency", "Arthritis"], a: 1, r: "Bone pain in leukemia results from rapid blast cell proliferation expanding the marrow cavity and infiltrating the periosteum. In children, this may cause limping, refusal to walk, or complaints of diffuse leg pain — sometimes the presenting symptom leading to diagnosis.", s: "Hematology" },
  { q: "An important safety measure when administering intrathecal chemotherapy is:", o: ["Mix vincristine and methotrexate together to reduce procedures", "NEVER administer vincristine intrathecally — only methotrexate, cytarabine, and hydrocortisone are given by this route", "No special precautions are needed", "All chemotherapy agents can be given intrathecally"], a: 1, r: "Vincristine is FATAL if given intrathecally. Only approved IT agents (methotrexate, cytarabine, hydrocortisone) should be administered via lumbar puncture or Ommaya reservoir. Many institutions require vincristine to be diluted in a minibag (not syringe) to prevent accidental IT injection.", s: "Hematology" },
  { q: "Gingival hyperplasia in AML is most commonly associated with which subtypes?", o: ["AML-M1 and M2", "AML-M4 and M5 (monocytic subtypes)", "AML-M3 (APL)", "AML-M7"], a: 1, r: "Monocytic subtypes of AML (M4 myelomonocytic, M5 monocytic) have a predilection for infiltrating soft tissues including the gingiva (causing hyperplasia), skin (leukemia cutis), and CNS. Gingival hyperplasia may be the presenting clinical finding in these subtypes.", s: "Hematology" },
  { q: "The nurse notes that a newly diagnosed AML patient's coagulation studies show: PT prolonged, aPTT prolonged, fibrinogen 80 mg/dL, D-dimer markedly elevated, platelets 28,000. This pattern suggests:", o: ["Normal coagulation", "Disseminated intravascular coagulation (DIC)", "Vitamin K deficiency only", "Liver failure only"], a: 1, r: "Prolonged PT/aPTT + low fibrinogen + elevated D-dimer + thrombocytopenia = classic DIC pattern. DIC involves simultaneous activation of coagulation (consuming clotting factors and platelets) and fibrinolysis (generating D-dimer/FDPs). In AML, DIC is most common in APL (M3).", s: "Hematology" },
  { q: "CNS prophylaxis in ALL treatment involves:", o: ["Whole brain radiation for all patients", "Intrathecal methotrexate to prevent CNS leukemic relapse", "Oral antibiotics for infection prevention", "No CNS-directed therapy is needed"], a: 1, r: "ALL has high CNS tropism — without prophylaxis, up to 50% develop CNS relapse. Intrathecal chemotherapy (methotrexate ± cytarabine ± hydrocortisone) is a standard component of ALL protocols, given at regular intervals throughout induction, consolidation, and maintenance.", s: "Hematology" },
  { q: "The Philadelphia chromosome t(9;22) in ALL:", o: ["Indicates excellent prognosis", "Indicates poor prognosis — the BCR-ABL1 fusion protein drives uncontrolled proliferation; treatment includes tyrosine kinase inhibitors", "Has no prognostic significance", "Only occurs in chronic leukemias"], a: 1, r: "Philadelphia chromosome creates the constitutively active BCR-ABL1 tyrosine kinase. In adult ALL, it occurs in 25% and confers poor prognosis. Targeted therapy with TKIs (imatinib, dasatinib) added to chemotherapy has significantly improved outcomes for Ph+ ALL.", s: "Hematology" },
  { q: "A patient undergoing ALL induction chemotherapy develops mucositis. Appropriate nursing interventions include:", o: ["Vigorous toothbrushing and commercial mouthwash", "Gentle oral care with soft toothettes, saline/baking soda mouth rinses every 2-4 hours, and pain management", "Nothing by mouth until mucositis resolves", "Hot food and beverages to improve appetite"], a: 1, r: "Mucositis (chemotherapy-induced oral mucositis) requires gentle oral care: soft toothettes (not standard toothbrush), non-alcoholic mouth rinses (saline/baking soda), pain assessment and management (viscous lidocaine, systemic analgesics), and soft, bland, non-irritating foods.", s: "Hematology" },
  { q: "ATRA (all-trans retinoic acid) is unique in cancer therapy because:", o: ["It kills cancer cells through cytotoxicity", "It induces terminal differentiation of malignant cells rather than killing them — forcing immature promyelocytes to mature into functional neutrophils", "It is a form of radiation", "It works for all types of leukemia"], a: 1, r: "ATRA is 'differentiation therapy' — it binds the PML-RARA fusion protein in APL cells, releasing the differentiation block and inducing maturation. This is fundamentally different from cytotoxic chemotherapy which kills dividing cells. Combined with arsenic trioxide, APL cure rates exceed 90%.", s: "Hematology" },
  { q: "A patient with AML has a WBC count of 145,000. The nurse should monitor for signs of leukostasis including: Select all that apply.", o: ["Dyspnea and hypoxemia", "Headache and confusion", "Visual changes", "Altered level of consciousness", "Improved energy and appetite"], a: 0, r: "Leukostasis with WBC >100,000: pulmonary symptoms (dyspnea, hypoxemia from blast sludging in pulmonary vasculature) and neurological symptoms (headache, confusion, visual changes, altered LOC from cerebral microvascular sludging). This is a medical emergency requiring emergent leukapheresis.", s: "Hematology", t: "sata", ca: [0, 1, 2, 3] },
  { q: "A patient with ALL has Down syndrome. The nurse understands that children with Down syndrome:", o: ["Have no increased cancer risk", "Have a 20-fold increased risk of developing ALL and require modified treatment protocols", "Cannot receive chemotherapy", "Always have poor prognosis"], a: 1, r: "Children with Down syndrome (trisomy 21) have approximately 20x increased risk of developing ALL (and also AML). They are more sensitive to certain chemotherapy agents (especially methotrexate) and require modified protocols, but overall outcomes are good with appropriate treatment.", s: "Hematology" },
  { q: "After achieving remission in ALL, why does the patient require 2-3 years of maintenance chemotherapy?", o: ["Remission is not real — the disease never goes away", "Despite undetectable disease, minimal residual disease (MRD) persists — prolonged low-dose therapy eliminates remaining leukemic cells and prevents relapse", "Maintenance therapy treats side effects of induction", "It is optional and has no benefit"], a: 1, r: "Complete remission means <5% blasts in marrow, but microscopic disease (MRD) can persist. ALL maintenance therapy (daily oral mercaptopurine + weekly oral methotrexate for 2-3 years) maintains drug pressure on residual leukemic cells. Without maintenance, relapse rates are significantly higher.", s: "Hematology" },
  { q: "A patient with leukemia has a platelet count of 15,000. What bleeding precaution is MOST important?", o: ["Limiting fluid intake", "Using electric razors, soft-bristle toothbrush, avoiding IM injections and rectal procedures, and applying pressure to venipuncture sites for 5+ minutes", "Normal grooming activities are safe", "Bed rest until platelet count normalizes"], a: 1, r: "Thrombocytopenia <20,000 requires strict bleeding precautions: electric razor (not safety razor), soft toothbrush, avoid IM injections and rectal procedures, apply prolonged pressure to venipuncture sites, no aspirin/NSAIDs, and monitor for spontaneous bleeding (petechiae, melena, hematuria).", s: "Hematology" },
  { q: "High-dose cytarabine (HiDAC) used in AML consolidation requires monitoring for:", o: ["Hepatotoxicity only", "Cerebellar toxicity — perform neurological assessment (finger-to-nose, tandem gait) before each dose", "Cardiac toxicity", "Renal toxicity only"], a: 1, r: "High-dose cytarabine can cause cerebellar toxicity presenting as ataxia, dysarthria, nystagmus, and impaired hand coordination. A neurological exam (finger-to-nose, rapid alternating movements, tandem gait) must be performed before each dose. If any signs develop, cytarabine must be held.", s: "Hematology" },
  { q: "A patient's absolute blast count is calculated as 45,000 (WBC 90,000 × 50% blasts). At this level, the nurse should anticipate:", o: ["Normal bone marrow function", "Possible leukostasis and need for emergent cytoreduction with hydroxyurea and potential leukapheresis", "No intervention needed", "Oral antibiotics only"], a: 1, r: "WBC >100,000 with high blast percentage creates significant leukostasis risk. Even at 90,000 with 50% blasts, the patient has 45,000 blasts causing microvascular sludging. Emergent hydroxyurea (oral cytoreduction) and/or leukapheresis may be needed before starting induction chemotherapy.", s: "Hematology" },

  // ============================================================
  // SICKLE CELL DISEASE (40 questions)
  // ============================================================
  { q: "A patient with sickle cell disease presents to the ED in severe vaso-occlusive crisis. The patient rates pain 10/10 and has visited the ED 5 times this month. What is the most appropriate nursing response?", o: ["Express concern about potential drug-seeking behavior", "Initiate the pain management protocol within 30 minutes — SCD pain is real, severe, and should be treated promptly without judgment", "Suggest relaxation techniques first", "Limit opioid administration to prevent dependence"], a: 1, r: "Sickle cell crisis causes real, severe, ischemic pain. Frequent ED visits are expected, NOT indicators of drug-seeking behavior. Evidence-based guidelines mandate prompt analgesic administration within 30 minutes. Undertreating SCD pain is unethical and increases morbidity.", s: "Hematology" },
  { q: "The MOST important initial intervention in sickle cell vaso-occlusive crisis is:", o: ["Cold compresses to the affected area", "IV hydration at 1.5x maintenance to dilute HbS concentration and improve blood flow", "Supplemental oxygen for all patients", "Immediate blood transfusion"], a: 1, r: "IV hydration is the #1 priority. Dehydration concentrates HbS, promoting polymerization and sickling. Aggressive hydration (D5-1/2NS at 1.5x maintenance) dilutes HbS, improves blood viscosity, and reduces sickling. Oxygen is given ONLY if SpO2 <92% or below baseline.", s: "Hematology" },
  { q: "Why should cold compresses be AVOIDED in sickle cell crisis?", o: ["They are uncomfortable", "Cold causes vasoconstriction, which slows blood flow, increases RBC transit time, and worsens vaso-occlusion and sickling", "They have no therapeutic effect", "They are medically unnecessary"], a: 1, r: "Cold causes peripheral vasoconstriction, slowing blood flow through capillaries. Slower flow increases the transit time of deoxygenated RBCs, promoting more HbS polymerization and sickling. WARM (not cold) compresses should be used to promote vasodilation and blood flow.", s: "Hematology" },
  { q: "Acute chest syndrome in SCD is the leading cause of death. Which findings define ACS? Select all that apply.", o: ["New pulmonary infiltrate on chest X-ray", "Fever", "Chest pain, cough, or dyspnea", "Hypoxemia (SpO2 below baseline)", "Elevated blood glucose"], a: 0, r: "ACS is defined by a NEW pulmonary infiltrate on CXR plus at least one of: fever, chest pain, cough, dyspnea, or hypoxemia. It results from pulmonary vaso-occlusion, fat embolism from bone marrow necrosis, and/or infection. Aggressive treatment including transfusion may be needed.", s: "Hematology", t: "sata", ca: [0, 1, 2, 3] },
  { q: "Hydroxyurea is the first-line disease-modifying therapy for SCD. It works by:", o: ["Providing pain relief", "Increasing fetal hemoglobin (HbF) production, which interrupts HbS polymerization by occupying the hydrophobic binding sites", "Replacing sickled red blood cells with normal ones", "Preventing dehydration"], a: 1, r: "Hydroxyurea increases HbF production. HbF cannot participate in HbS polymer formation because it lacks the valine substitution at position 6. HbF interrupts the polymerization cascade, reducing sickling, crisis frequency (by ~50%), ACS, and improving survival.", s: "Hematology" },
  { q: "Splenic sequestration crisis in a sickle cell child presents with:", o: ["Gradual onset fatigue over weeks", "Sudden left upper quadrant pain, rapidly falling hemoglobin, rapid spleen enlargement, and signs of hypovolemic shock", "Right lower quadrant pain mimicking appendicitis", "Bilateral joint swelling"], a: 1, r: "Splenic sequestration: massive pooling of blood in the spleen causes rapid splenic enlargement (LUQ pain), severe acute anemia (Hgb drops >2 g/dL within hours), and hypovolemic shock. Most common in children <5 years (before autosplenectomy). Life-threatening — requires immediate transfusion.", s: "Hematology" },
  { q: "By what age do most children with SCD have functional asplenia?", o: ["1-2 years", "5-6 years — repeated splenic infarction causes autosplenectomy", "10-12 years", "Spleen function is maintained throughout life"], a: 1, r: "Repeated sickling episodes cause progressive splenic infarction. By age 5-6, most SCD patients have functional asplenia (autosplenectomy). This eliminates splenic immune surveillance, increasing susceptibility to encapsulated bacteria (S. pneumoniae, H. influenzae, N. meningitidis).", s: "Hematology" },
  { q: "Fever in a sickle cell patient with functional asplenia is a medical emergency because:", o: ["Fever indicates drug-seeking behavior", "Encapsulated bacteria can cause rapidly fatal sepsis in asplenic patients — blood cultures and antibiotics are needed IMMEDIATELY", "Fever is always benign in SCD", "Fever indicates crisis resolution"], a: 1, r: "Functional asplenia removes the spleen's ability to clear encapsulated bacteria (S. pneumoniae, H. influenzae). These organisms can cause fulminant sepsis with death within hours. Any SCD patient with fever requires immediate blood cultures and empiric antibiotics.", s: "Hematology" },
  { q: "Supplemental oxygen in sickle cell crisis should be administered:", o: ["To all patients regardless of oxygen saturation", "ONLY if SpO2 is below 92% or below the patient's known baseline — routine O2 in normoxic patients may suppress erythropoiesis", "At the highest flow rate available", "Only during sleep"], a: 1, r: "Routine supplemental O2 in normoxic SCD patients is not beneficial and may suppress erythropoietin production, reducing red cell production. O2 should be administered only when SpO2 is <92% or below the patient's known baseline (SCD patients often have baseline SpO2 of 92-96%).", s: "Hematology" },
  { q: "Dactylitis (hand-foot syndrome) is often the FIRST manifestation of SCD, typically presenting in:", o: ["Newborns", "Infants 6 months to 2 years of age", "Adolescents", "Elderly adults"], a: 1, r: "Dactylitis presents as painful swelling of the hands and feet from vaso-occlusion of small metacarpal/metatarsal bone marrow vessels. It occurs between 6 months and 2 years — earlier than 6 months, fetal hemoglobin (HbF) protects against sickling. It is often the first clinical manifestation of SCD.", s: "Hematology" },
  { q: "Aplastic crisis in SCD is most commonly caused by:", o: ["Folate deficiency", "Parvovirus B19 infection, which selectively destroys erythroid precursors", "Iron deficiency", "Chemotherapy"], a: 1, r: "Parvovirus B19 has tropism for erythroid precursors expressing the P antigen, temporarily halting red blood cell production (reticulocyte count drops to near zero). In SCD with shortened RBC lifespan (10-20 days vs normal 120), this causes rapid, severe anemia.", s: "Hematology" },
  { q: "A child with SCD is prescribed prophylactic penicillin. This should continue until:", o: ["1 year of age", "Age 5 — to protect against overwhelming pneumococcal sepsis during the period of highest susceptibility", "Age 10", "Lifelong"], a: 1, r: "Prophylactic penicillin is started at 2 months and continued until at least age 5 to protect against S. pneumoniae sepsis during the period of functional asplenia development. Some experts recommend continuing longer if the child has not received adequate pneumococcal vaccination.", s: "Hematology" },
  { q: "Exchange transfusion in SCD is indicated for:", o: ["Mild vaso-occlusive crisis", "Acute stroke, severe ACS, or acute multi-organ failure — targets HbS reduction to <30%", "Routine anemia management", "Prophylaxis before minor dental procedures"], a: 1, r: "Exchange transfusion rapidly removes HbS-containing RBCs and replaces them with normal HbA-containing cells, targeting HbS <30%. Indications: acute ischemic stroke (emergent), severe ACS, multi-organ failure, and severe priapism unresponsive to initial management.", s: "Hematology" },
  { q: "Priapism in SCD is:", o: ["A normal finding", "A urologic emergency — prolonged, painful erection from penile vaso-occlusion requiring urgent treatment if lasting >4 hours", "Related to sexual activity", "Self-resolving without intervention"], a: 1, r: "Priapism results from sickling within the corpora cavernosa, blocking venous outflow. If untreated for >4 hours, ischemic damage causes permanent erectile dysfunction. Treatment: IV hydration, analgesics, aspiration/irrigation by urology, and potentially exchange transfusion.", s: "Hematology" },
  { q: "A nurse is educating a patient with SCD about crisis prevention. Which instructions should be included? Select all that apply.", o: ["Maintain adequate hydration (8-10 glasses of water daily)", "Avoid temperature extremes (especially cold)", "Avoid high altitudes (decreased oxygen tension promotes sickling)", "Take hydroxyurea as prescribed", "Participate in competitive high-intensity sports without restriction"], a: 0, r: "Crisis prevention: adequate hydration (dilutes HbS), avoid cold (vasoconstriction), avoid high altitude/hypoxia (promotes deoxygenation and sickling), medication adherence (hydroxyurea), avoid extreme physical exertion (increases oxygen demand), manage stress, and avoid alcohol.", s: "Hematology", t: "sata", ca: [0, 1, 2, 3] },
  { q: "Transcranial Doppler (TCD) screening in SCD children is performed to:", o: ["Assess hearing", "Screen for stroke risk — elevated cerebral blood flow velocity >200 cm/s indicates high stroke risk requiring chronic transfusion therapy", "Evaluate brain tumors", "Measure IQ"], a: 1, r: "TCD measures blood flow velocity in cerebral arteries. Velocities >200 cm/s indicate sickle vasculopathy with high stroke risk. Annual TCD screening (ages 2-16) and prophylactic chronic transfusion therapy for abnormal results reduce childhood stroke risk by 92%.", s: "Hematology" },
  { q: "The nurse notes that a patient with SCD has scleral icterus and an indirect bilirubin of 3.8 mg/dL. This is caused by:", o: ["Liver disease", "Chronic hemolysis — sickled RBCs are rapidly destroyed, releasing hemoglobin that is metabolized to unconjugated (indirect) bilirubin", "Biliary obstruction", "Medication side effect"], a: 1, r: "SCD involves chronic extravascular hemolysis — damaged sickled RBCs are removed by the spleen and reticuloendothelial system. Hemoglobin breakdown produces unconjugated (indirect) bilirubin, causing jaundice and scleral icterus. Pigment gallstones (bilirubin stones) are also common.", s: "Hematology" },
  { q: "Hydroxyurea monitoring includes:", o: ["Blood glucose checks", "CBC every 2-4 weeks during dose titration to monitor for myelosuppression", "Thyroid function tests", "Bone density scans"], a: 1, r: "Hydroxyurea works partly through mild myelosuppression. CBC must be monitored every 2-4 weeks during dose titration and every 4-8 weeks at stable doses. Hold if ANC <2,000 or platelets <80,000. Target MCV increase confirms adherence and optimal dosing.", s: "Hematology" },
  { q: "A patient with SCD has a hemoglobin of 6.5 g/dL (baseline 8.0). What does the nurse assess FIRST?", o: ["Dietary intake", "Signs and symptoms of acute complication — a drop of >2 g/dL from baseline suggests splenic sequestration, aplastic crisis, or acute hemolysis requiring urgent evaluation", "Exercise tolerance", "Skin color"], a: 1, r: "A hemoglobin drop >2 g/dL from baseline is clinically significant in SCD. The nurse should assess for: splenic sequestration (LUQ pain, splenomegaly, shock), aplastic crisis (low reticulocyte count from parvovirus B19), or acute hemolytic crisis. This requires urgent provider notification.", s: "Hematology" },
  { q: "Essential vaccinations for SCD patients include:", o: ["Only the standard childhood vaccination schedule", "Pneumococcal, meningococcal, Haemophilus influenzae type b, and annual influenza vaccines — in addition to routine vaccinations", "No vaccinations are needed", "Only hepatitis B"], a: 1, r: "Due to functional asplenia, SCD patients need enhanced protection against encapsulated organisms: pneumococcal (PCV13 + PPSV23), meningococcal (MenACWY + MenB), and Hib vaccines. Annual influenza vaccination is also essential. These are in ADDITION to routine childhood vaccinations.", s: "Hematology" },
  { q: "What laboratory value distinguishes aplastic crisis from hemolytic crisis in SCD?", o: ["Hemoglobin level", "Reticulocyte count — markedly LOW in aplastic crisis (parvovirus suppresses erythropoiesis) vs ELEVATED in hemolytic crisis", "WBC count", "Platelet count"], a: 1, r: "In aplastic crisis (parvovirus B19), the reticulocyte count drops to near zero because erythroid precursors are destroyed. In hemolytic crisis, the reticulocyte count is elevated (bone marrow attempting to compensate for increased RBC destruction). Both cause worsening anemia.", s: "Hematology" },

  // ============================================================
  // THALASSEMIA (20 questions)
  // ============================================================
  { q: "Thalassemia and iron deficiency anemia both cause microcytic anemia. The key lab finding that differentiates them is:", o: ["Hemoglobin level", "Serum ferritin — NORMAL or ELEVATED in thalassemia vs LOW in iron deficiency", "MCV", "WBC count"], a: 1, r: "Both produce low MCV (microcytic) anemia, but iron studies are the differentiator: thalassemia = ferritin NORMAL/HIGH (iron overload from transfusions and increased absorption); iron deficiency = ferritin LOW (<15). This distinction is critical — giving iron to a thalassemia patient worsens iron overload.", s: "Hematology" },
  { q: "The leading cause of death in thalassemia major is:", o: ["Infection", "Iron cardiomyopathy — cardiac iron deposition causes heart failure and fatal arrhythmias", "Bone fractures", "Renal failure"], a: 1, r: "Cardiac iron overload (from transfusions and increased GI absorption) deposits iron in myocytes, generating ROS via Fenton reaction. This causes dilated cardiomyopathy and arrhythmias. Cardiac MRI T2* monitoring and iron chelation compliance are life-saving.", s: "Hematology" },
  { q: "A patient with thalassemia major has bronze skin discoloration, hepatomegaly, and new-onset diabetes. These findings indicate:", o: ["Medication side effects", "Iron overload (hemochromatosis) affecting the skin, liver, and pancreatic beta cells", "Viral hepatitis", "Autoimmune disease"], a: 1, r: "Classic hemochromatosis triad: bronze skin (iron in dermis), hepatomegaly progressing to cirrhosis (hepatic iron), and 'bronze diabetes' (pancreatic beta-cell destruction from iron deposits). Serum ferritin is markedly elevated. Iron chelation therapy is essential.", s: "Hematology" },
  { q: "When administering a blood transfusion to a thalassemia patient, what is the MOST important safety measure?", o: ["Warm the blood", "Verify patient identification, ABO/Rh compatibility, and monitor for transfusion reactions — remain with the patient for the first 15 minutes", "Administer rapidly to reduce procedure time", "Give iron supplements simultaneously"], a: 1, r: "Standard blood transfusion safety: dual patient identification, ABO/Rh verification with two nurses, baseline vital signs, remain with patient for first 15 minutes (most severe reactions occur early), monitor VS per protocol. NEVER give iron supplements — these patients have iron OVERLOAD.", s: "Hematology" },
  { q: "Reddish-orange urine during deferoxamine therapy is:", o: ["A sign of kidney damage requiring immediate intervention", "An EXPECTED finding indicating successful iron chelation — the ferrioxamine complex is excreted in urine", "A sign of hematuria", "A medication allergy"], a: 1, r: "Reddish-orange urine during deferoxamine therapy is NORMAL and EXPECTED. It represents the excretion of ferrioxamine (iron-deferoxamine complex) through the kidneys. Patients should be informed this means the medication is effectively removing iron.", s: "Hematology" },
  { q: "'Chipmunk facies' in thalassemia major results from:", o: ["Iron deposits in facial bones", "Massive bone marrow expansion into facial bones (frontal bossing, maxillary hyperplasia) driven by compensatory erythropoiesis in response to severe anemia", "Allergic reaction to transfusions", "Corticosteroid side effects"], a: 1, r: "Severe chronic anemia triggers erythropoietin-driven marrow expansion. The expanding marrow cavity pushes into cortical bone, particularly affecting the skull and facial bones, causing frontal bossing, prominent cheekbones, and flat nasal bridge. Regular transfusions to suppress erythropoiesis prevent these skeletal changes.", s: "Hematology" },
  { q: "Deferasirox (Exjade/Jadenu) monitoring should include:", o: ["Blood glucose checks", "Monthly serum creatinine and liver function tests — nephrotoxicity and hepatotoxicity are the main safety concerns", "Thyroid function tests", "Bone density scans"], a: 1, r: "Deferasirox can cause nephrotoxicity (dose-dependent) and hepatotoxicity. Serum creatinine and LFTs should be monitored monthly. Dose adjustment is required for rising creatinine. Also monitor audiometry and ophthalmology annually (auditory and visual toxicity possible).", s: "Hematology" },
  { q: "Why should iron supplements NEVER be given to a thalassemia patient?", o: ["Iron supplements are expensive", "Thalassemia causes iron OVERLOAD (from transfusions and increased absorption), not deficiency — adding iron worsens organ damage", "Iron interferes with chelation therapy", "Iron causes anemia in thalassemia"], a: 1, r: "Despite microcytic anemia (which is often mistakenly attributed to iron deficiency), thalassemia patients have iron OVERLOAD from chronic transfusions and hepcidin-suppressed increased GI absorption. Adding iron supplements would accelerate organ damage.", s: "Hematology" },
  { q: "Cardiac MRI T2* measurement is used in thalassemia to:", o: ["Assess heart valve function", "Non-invasively quantify cardiac iron loading — T2* <20ms indicates iron overload; <10ms indicates high risk of cardiac events within 1 year", "Diagnose arrhythmias", "Measure ejection fraction only"], a: 1, r: "Cardiac MRI T2* is the gold standard for non-invasive cardiac iron quantification. Iron deposits shorten T2* relaxation time. T2* <20ms = cardiac iron overload; <10ms = high risk of heart failure or fatal arrhythmia within 1 year. Guides chelation therapy intensification.", s: "Hematology" },
  { q: "The target pre-transfusion hemoglobin in thalassemia major is:", o: ["6-7 g/dL", "9-10.5 g/dL — to suppress ineffective erythropoiesis and prevent skeletal deformities", "12-14 g/dL", "15-16 g/dL"], a: 1, r: "Maintaining pre-transfusion Hgb at 9-10.5 g/dL suppresses endogenous erythropoietin-driven marrow expansion (preventing skeletal deformities and extramedullary hematopoiesis), allows normal growth and development, and maintains adequate oxygen delivery.", s: "Hematology" },

  // ============================================================
  // PANCYTOPENIA (20 questions)
  // ============================================================
  { q: "Pancytopenia is defined as:", o: ["Low red blood cells only", "Simultaneous decrease of ALL THREE blood cell lineages: RBCs, WBCs, and platelets", "Low white blood cells only", "Low platelets only"], a: 1, r: "Pancytopenia = pan (all) + cytopenia (cell deficiency): anemia (low RBCs → fatigue, pallor), leukopenia/neutropenia (low WBCs → infection risk), and thrombocytopenia (low platelets → bleeding risk). It is a FINDING requiring investigation of the underlying cause.", s: "Hematology" },
  { q: "The bone marrow biopsy in aplastic anemia characteristically shows:", o: ["Hypercellular marrow with blast cells", "HYPOCELLULAR marrow with fat replacement — hematopoietic cells are replaced by adipose tissue", "Normal marrow cellularity", "Fibrosis"], a: 1, r: "Aplastic anemia = immune-mediated destruction of hematopoietic stem cells → marrow becomes hypocellular (<25% cellularity) with fat replacing normal blood-forming tissue. This contrasts with MDS (dysplastic but cellular marrow) and leukemia (blast-filled marrow).", s: "Hematology" },
  { q: "A patient with pancytopenia has ANC 280 and develops temperature 100.6°F. What is the priority nursing action?", o: ["Administer acetaminophen and recheck in 2 hours", "Obtain blood cultures from two sites and notify the provider for STAT broad-spectrum antibiotics", "Continue routine monitoring", "Apply cooling measures and encourage PO fluids"], a: 1, r: "Febrile neutropenia (ANC <500 + temp >100.4°F) is a medical emergency. Fever may be the ONLY sign of life-threatening sepsis because neutropenia eliminates normal inflammatory responses. Blood cultures and empiric broad-spectrum antibiotics within 1 HOUR.", s: "Hematology" },
  { q: "Aplastic anemia differs from MDS in that:", o: ["They are identical conditions", "Aplastic anemia has a HYPOCELLULAR marrow; MDS has a NORMOCELLULAR/HYPERCELLULAR marrow with DYSPLASTIC cells and risk of AML transformation", "MDS has a hypocellular marrow", "Aplastic anemia transforms to AML"], a: 1, r: "Key distinction: aplastic anemia = empty marrow (stem cells destroyed → fat replacement); MDS = full marrow with abnormal-looking cells (dysplasia → ineffective hematopoiesis). MDS carries 30% risk of transforming to AML; aplastic anemia does not.", s: "Hematology" },
  { q: "IM injections should be avoided in pancytopenic patients because:", o: ["They are unnecessary", "Low platelets create risk of intramuscular hematoma, and low neutrophils increase infection risk at injection sites", "IM medications are not absorbed", "IM injections are painful"], a: 1, r: "Dual risk: thrombocytopenia → intramuscular hematoma formation (cannot be compressed like subcutaneous sites); neutropenia → localized infection at injection site with impaired immune defense. Use subcutaneous or IV routes instead.", s: "Hematology" },
  { q: "Fanconi anemia should be suspected in a child with pancytopenia PLUS:", o: ["Normal physical examination", "Café-au-lait spots, short stature, thumb/radial abnormalities, and renal anomalies", "Obesity and large stature", "Normal chromosomal studies"], a: 1, r: "Fanconi anemia is an autosomal recessive DNA repair defect. Physical anomalies include: café-au-lait spots, short stature, microcephaly, thumb/radial abnormalities (absent, hypoplastic, or triphalangeal thumbs), and renal malformations. Diagnosis: chromosomal breakage study.", s: "Hematology" },
  { q: "ATG (anti-thymocyte globulin) therapy for aplastic anemia requires pre-medication because:", o: ["It has no side effects", "Animal-derived antibody preparation carries risk of anaphylaxis and serum sickness — pre-medicate with corticosteroids and antihistamines; skin test first", "It must be given rapidly", "No pre-medication is needed"], a: 1, r: "ATG is derived from horse or rabbit serum and carries significant allergic/anaphylactic risk. A skin test is required before administration. Pre-medication with corticosteroids, antihistamines, and acetaminophen is standard. Monitor for serum sickness 7-14 days post-infusion.", s: "Hematology" },
  { q: "Cyclosporine monitoring in aplastic anemia requires:", o: ["Blood glucose checks", "Trough drug levels (target 200-400 ng/mL) and regular serum creatinine monitoring for nephrotoxicity", "Thyroid function tests", "Bone density scans"], a: 1, r: "Cyclosporine (calcineurin inhibitor) can cause dose-dependent nephrotoxicity. Monitor trough levels to maintain therapeutic range and check serum creatinine regularly. Also monitor for hypertension, hyperkalemia, tremor, and gingival hyperplasia. Avoid grapefruit (inhibits CYP3A4).", s: "Hematology" },
  { q: "Which assessment is MOST critical for a pancytopenic patient with platelets of 8,000/uL?", o: ["Assessment of nutritional intake", "Neurological assessment for signs of intracranial hemorrhage — the most lethal complication of severe thrombocytopenia", "Skin assessment for dryness", "Musculoskeletal assessment"], a: 1, r: "Platelets <10,000 carry risk of spontaneous hemorrhage. Intracranial hemorrhage is the most lethal complication, presenting subtly with headache, confusion, or altered LOC. Neurological assessment is the highest priority to detect this life-threatening complication early.", s: "Hematology" },
  { q: "Hypersplenism as a cause of pancytopenia can occur in:", o: ["All patients equally", "Portal hypertension, Gaucher disease, and Felty syndrome — the enlarged spleen excessively sequesters and destroys blood cells", "Diabetes", "Thyroid disease"], a: 1, r: "Hypersplenism occurs when the spleen enlarges and traps excessive numbers of blood cells. Causes include portal hypertension (liver cirrhosis), storage diseases (Gaucher), and autoimmune conditions (Felty syndrome = RA + splenomegaly + neutropenia). Treatment may include splenectomy.", s: "Hematology" },

  // ============================================================
  // RHEUMATOID ARTHRITIS (20 questions)
  // ============================================================
  { q: "The MOST critical medication safety point about methotrexate for RA is:", o: ["Take it with food", "It is given ONCE WEEKLY — daily dosing causes fatal bone marrow suppression and hepatotoxicity", "It works immediately", "No lab monitoring needed"], a: 1, r: "Methotrexate dosing for RA: ONCE WEEKLY (not daily). Daily dosing delivers a 7x overdose causing fatal pancytopenia and hepatotoxicity. This is one of the most frequently tested medication errors on nursing exams. Always supplement with folic acid 1mg daily.", s: "Musculoskeletal" },
  { q: "RA characteristically involves which joints?", o: ["DIP joints bilaterally", "MCP, PIP, and wrist joints SYMMETRICALLY (SPARES DIP joints)", "Sacroiliac joints", "First MTP joint"], a: 1, r: "RA = symmetric small joint polyarthritis affecting MCP (knuckles), PIP (middle finger joints), wrists. DIP joints are SPARED (DIP = OA/Heberden nodes). First MTP = gout. Sacroiliac = ankylosing spondylitis. The symmetric pattern and DIP sparing are diagnostic clues.", s: "Musculoskeletal" },
  { q: "Morning stiffness in RA typically:", o: ["Lasts less than 15 minutes", "Lasts MORE than 1 hour and improves with activity", "Worsens with activity", "Does not occur"], a: 1, r: "RA morning stiffness >1 hour (inflammatory) vs OA <30 minutes (mechanical). RA stiffness improves with activity (warming up the joints). The duration of morning stiffness is also a clinical marker of disease activity — longer stiffness indicates more active inflammation.", s: "Musculoskeletal" },
  { q: "Before starting a biologic DMARD (TNF inhibitor), the nurse should ensure:", o: ["A bone density scan has been completed", "Screening for latent tuberculosis has been performed and any latent TB has been treated", "The patient has received live vaccines", "No special screening is needed"], a: 1, r: "TNF inhibitors increase TB reactivation risk because TNF-alpha is critical for granuloma formation containing M. tuberculosis. Screen with PPD or IGRA before starting ANY biologic. If positive, treat latent TB with isoniazid 9 months before initiating the biologic.", s: "Musculoskeletal" },
  { q: "Anti-CCP antibodies in RA are significant because:", o: ["They have no clinical significance", "They are highly specific (>95%) for RA and predict erosive disease progression — they may be detectable years before clinical symptoms", "They indicate infection", "They are a treatment target"], a: 1, r: "Anti-CCP antibodies have >95% specificity for RA (more specific than RF). Their presence predicts more aggressive, erosive disease. They can be detected years before clinical onset, making them valuable for early diagnosis and risk stratification.", s: "Musculoskeletal" },
  { q: "Labs to monitor regularly in a patient taking methotrexate include:", o: ["Blood glucose only", "CBC with differential and comprehensive metabolic panel (LFTs) every 4-8 weeks", "Coagulation studies", "Urinalysis only"], a: 1, r: "Methotrexate toxicity monitoring: CBC (bone marrow suppression → pancytopenia) and LFTs (hepatotoxicity → elevated transaminases) every 4-8 weeks. Also monitor renal function (methotrexate is renally excreted). Report leukopenia, thrombocytopenia, or elevated liver enzymes immediately.", s: "Musculoskeletal" },
  { q: "Swan-neck deformity in RA involves:", o: ["DIP hyperextension + PIP flexion", "PIP hyperextension + DIP flexion", "Ulnar deviation of the wrist", "Boutonnière deformity"], a: 1, r: "Swan-neck = PIP hyperextension + DIP flexion (finger looks like a swan's neck). Boutonnière = opposite (PIP flexion + DIP hyperextension). Both result from tendon and ligament destruction by rheumatoid pannus.", s: "Musculoskeletal" },
  { q: "Cervical spine instability (atlantoaxial subluxation) in RA patients is a safety concern during:", o: ["Routine blood draws", "Intubation for general anesthesia — neck manipulation can cause spinal cord compression at C1-C2", "Chest X-ray positioning", "Oral medication administration"], a: 1, r: "RA destroys the transverse ligament of C1, allowing C1 to sublux on C2. During intubation, neck extension/manipulation can displace C1 on C2, compressing the spinal cord. Flexion/extension cervical X-rays should be obtained before elective surgery requiring general anesthesia.", s: "Musculoskeletal" },
  { q: "What is the 'window of opportunity' in RA treatment?", o: ["The first 24 hours after diagnosis", "DMARDs should be initiated within 3 months of symptom onset — early aggressive treatment prevents irreversible joint damage", "Treatment can start at any time with equal effectiveness", "The period after joint deformity occurs"], a: 1, r: "Irreversible joint damage begins within the first 2 years of RA. The 'window of opportunity' refers to the first 3-6 months when early DMARD initiation can prevent structural damage. Delayed treatment leads to worse long-term outcomes regardless of subsequent therapy intensity.", s: "Musculoskeletal" },
  { q: "Folic acid is prescribed with methotrexate because:", o: ["It increases methotrexate effectiveness", "It reduces methotrexate side effects (stomatitis, GI upset, hepatotoxicity) by replenishing folate without reducing anti-inflammatory efficacy", "It treats anemia caused by RA", "It is a placebo"], a: 1, r: "Methotrexate depletes intracellular folate via dihydrofolate reductase inhibition. Folic acid 1mg daily replenishes folate stores, reducing stomatitis (mouth sores), nausea, and hepatotoxicity WITHOUT reducing methotrexate's anti-inflammatory efficacy.", s: "Musculoskeletal" },

  // ============================================================
  // OSTEOARTHRITIS (20 questions)
  // ============================================================
  { q: "The key clinical differentiator between OA and RA morning stiffness is:", o: ["Duration: OA stiffness <30 minutes; RA stiffness >1 hour", "They have identical stiffness patterns", "OA has longer stiffness than RA", "Neither condition causes morning stiffness"], a: 0, r: "OA stiffness: brief (<30 min), mechanical 'gelling,' improves quickly with movement. RA stiffness: prolonged (>1 hr), inflammatory, gradually improves with activity. This is the most frequently tested clinical differentiator on nursing exams.", s: "Musculoskeletal" },
  { q: "Heberden nodes are found at which joints?", o: ["MCP joints", "DIP joints — pathognomonic for OA", "PIP joints only", "Wrist joints"], a: 1, r: "Heberden nodes = DIP (distal interphalangeal) bony enlargements from osteophyte formation = pathognomonic for OA. Bouchard nodes = PIP joints. Remember: RA SPARES the DIP joints, so DIP involvement immediately suggests OA, not RA.", s: "Musculoskeletal" },
  { q: "A patient with right knee OA asks which hand to hold their cane in. The correct answer is:", o: ["Right hand (same side)", "LEFT hand (opposite side)", "Either hand", "Both hands"], a: 1, r: "Cane in the OPPOSITE hand, advanced WITH the affected leg. The contralateral cane provides a counterbalancing force that reduces load on the affected knee by up to 25%, mimicking the normal arm-leg opposition pattern of walking.", s: "Musculoskeletal" },
  { q: "Synovial fluid in OA is:", o: ["Cloudy with high WBC count", "Clear and viscous with WBC <2,000 (non-inflammatory)", "Purulent", "Bloody"], a: 1, r: "OA = non-inflammatory arthritis: synovial fluid is clear, maintains viscosity, WBC <2,000. RA = inflammatory: cloudy, decreased viscosity, WBC 5,000-50,000 with PMN predominance. Septic arthritis: purulent, WBC >50,000.", s: "Musculoskeletal" },
  { q: "Weight loss benefits knee OA because:", o: ["It has no effect on joints", "Every 1 pound lost removes approximately 4 pounds of force across the knee joint", "It only improves appearance", "It reduces medication costs"], a: 1, r: "Biomechanical studies show the knee multiplies body weight by approximately 4x during walking. Even modest weight loss (5-10 lbs) significantly reduces joint loading (20-40 lbs less force), decreasing pain and slowing cartilage degradation.", s: "Musculoskeletal" },
  { q: "The first-line non-pharmacological intervention for OA is:", o: ["Joint replacement surgery", "Weight management and regular low-impact exercise (swimming, cycling, walking)", "Bed rest and joint immobilization", "High-impact aerobics"], a: 1, r: "Non-pharmacological measures are first-line: weight management (most impactful for knee OA), low-impact exercise (strengthens periarticular muscles, improves ROM without damaging cartilage), physical therapy, joint protection techniques, and assistive devices.", s: "Musculoskeletal" },
  { q: "Topical NSAIDs are preferred over oral NSAIDs for knee and hand OA because:", o: ["They are more effective", "They provide local anti-inflammatory effect with less systemic absorption, reducing GI, cardiovascular, and renal risks", "Oral NSAIDs don't work for OA", "Topical NSAIDs are cheaper"], a: 1, r: "Topical NSAIDs (diclofenac gel) deliver the drug directly to the affected joint with minimal systemic absorption. This significantly reduces the GI (ulcers, bleeding), cardiovascular (MI, stroke), and renal (AKI, fluid retention) risks associated with oral NSAID use.", s: "Musculoskeletal" },
  { q: "Intra-articular corticosteroid injections for OA provide:", o: ["Permanent relief", "Temporary symptom relief (typically 4-6 weeks); limited to 3-4 injections per year to the same joint", "No benefit whatsoever", "Disease modification"], a: 1, r: "IA corticosteroid injections provide temporary anti-inflammatory relief, typically lasting 4-6 weeks. They do NOT modify disease progression. Frequent injections (>3-4 per year) may accelerate cartilage degradation and increase infection risk.", s: "Musculoskeletal" },
  { q: "OA primarily affects which joints?", o: ["Small joints of the hands symmetrically", "Weight-bearing joints: knees, hips, spine, and first CMC joint of the thumb", "Sacroiliac joints", "MCP joints bilaterally"], a: 1, r: "OA primarily affects weight-bearing joints (knees, hips, lumbar/cervical spine) and the first carpometacarpal (CMC/base of thumb) joint. Unlike RA, involvement is typically asymmetric and related to mechanical factors (obesity, prior injury, occupational stress).", s: "Musculoskeletal" },
  { q: "The definitive surgical treatment for end-stage OA that fails conservative management is:", o: ["Arthroscopic debridement", "Total joint arthroplasty (replacement)", "Joint fusion", "Synovectomy"], a: 1, r: "Total joint arthroplasty (replacement) is the definitive treatment for end-stage OA when conservative measures fail and functional impairment is severe. Knee and hip replacements have excellent outcomes with significant pain relief and improved function lasting 15-25 years.", s: "Musculoskeletal" },

  // ============================================================
  // OSTEOPOROSIS (20 questions)
  // ============================================================
  { q: "A DEXA scan T-score of -2.8 indicates:", o: ["Normal bone density", "Osteopenia", "Osteoporosis (T-score ≤ -2.5)", "Paget disease"], a: 2, r: "T-score interpretation: ≥ -1.0 = normal; -1.0 to -2.5 = osteopenia; ≤ -2.5 = osteoporosis; ≤ -2.5 with fracture = severe osteoporosis. A T-score of -2.8 meets the osteoporosis threshold and typically warrants pharmacological treatment.", s: "Musculoskeletal" },
  { q: "The MOST important teaching point about bisphosphonate (alendronate) administration is:", o: ["Take with breakfast", "Take on EMPTY stomach with FULL glass of PLAIN water, remain UPRIGHT for 30 minutes, no food/drink/medications for 30 minutes", "Take at bedtime lying down", "Take with milk for calcium"], a: 1, r: "These strict rules prevent esophageal erosion/ulceration (most common side effect) and maximize the very poor oral bioavailability (<1%). Food, calcium, juice, coffee, and other medications all dramatically reduce absorption.", s: "Musculoskeletal" },
  { q: "Denosumab (Prolia) should NEVER be discontinued abruptly because:", o: ["It causes allergic reactions", "Abrupt discontinuation causes severe REBOUND bone loss with rapid vertebral fractures — patients must transition to a bisphosphonate", "It is too expensive to waste", "There are no discontinuation concerns"], a: 1, r: "Stopping denosumab causes a massive rebound surge in RANKL and osteoclast activity, resulting in rapid bone loss exceeding pre-treatment rates. Multiple spontaneous vertebral compression fractures can occur within 12-18 months. Always transition to a bisphosphonate before stopping.", s: "Musculoskeletal" },
  { q: "The RANK-RANKL-OPG pathway: denosumab works by:", o: ["Stimulating osteoblast activity", "Neutralizing RANKL (mimicking OPG's natural function), preventing osteoclast formation and bone resorption", "Providing calcium", "Blocking estrogen receptors"], a: 1, r: "Denosumab = anti-RANKL monoclonal antibody. It binds and neutralizes RANKL, preventing it from activating RANK on osteoclast precursors. This mimics OPG's natural protective role, dramatically reducing osteoclast formation, activation, and survival.", s: "Musculoskeletal" },
  { q: "Estrogen protects against osteoporosis by:", o: ["Providing calcium to bones", "Suppressing RANKL, increasing OPG, promoting osteoclast apoptosis, and supporting osteoblast activity — all lost at menopause", "Strengthening tendons", "Increasing vitamin D levels"], a: 1, r: "Estrogen has multiple bone-protective effects: suppresses RANKL (reduces osteoclast formation), increases OPG (blocks RANKL), promotes osteoclast apoptosis (shortens their lifespan), and supports osteoblast survival. Menopause removes all these effects, causing rapid bone loss.", s: "Musculoskeletal" },
  { q: "Hip fractures in elderly osteoporotic patients carry a one-year mortality rate of:", o: ["Less than 5%", "10-15%", "20-30%", "50%"], a: 2, r: "Hip fractures carry devastating 20-30% one-year mortality in elderly patients. Complications include DVT/PE, pneumonia, delirium, pressure injuries, and progressive deconditioning. This underscores the critical importance of osteoporosis prevention, treatment, and fall prevention.", s: "Musculoskeletal" },
  { q: "Progressive height loss of >1.5 inches from peak height suggests:", o: ["Normal aging process", "Vertebral compression fractures from osteoporosis — often clinically silent", "Dehydration", "Arthritis in the knees"], a: 1, r: "Height loss >1.5 inches (4 cm) from peak height strongly suggests multiple vertebral compression fractures, which may be asymptomatic (only 1/3 are clinically recognized). Physical findings include progressive thoracic kyphosis (dowager's hump).", s: "Musculoskeletal" },
  { q: "Which medication is an ANABOLIC (bone-building) agent for osteoporosis?", o: ["Alendronate (bisphosphonate)", "Teriparatide (PTH analog) — it stimulates osteoblasts to BUILD new bone", "Denosumab (RANKL inhibitor)", "Raloxifene (SERM)"], a: 1, r: "Teriparatide is a recombinant PTH(1-34) analog. When given as daily intermittent SC injections, it preferentially stimulates osteoblasts (anabolic effect), building new bone. This contrasts with antiresorptive agents (bisphosphonates, denosumab) that only slow bone loss.", s: "Musculoskeletal" },
  { q: "Glucocorticoid-induced osteoporosis occurs because corticosteroids:", o: ["Have no effect on bone", "Directly suppress osteoblast function, increase osteocyte apoptosis, enhance RANKL expression, and decrease calcium absorption", "Strengthen bone", "Only affect bone at extremely high doses"], a: 1, r: "Glucocorticoid-induced osteoporosis is the most common secondary cause of osteoporosis. Corticosteroids suppress osteoblasts, kill osteocytes, enhance RANKL (increasing osteoclast activity), decrease intestinal calcium absorption, and increase renal calcium excretion.", s: "Musculoskeletal" },
  { q: "The FRAX tool calculates:", o: ["Bone age", "10-year probability of major osteoporotic fracture and hip fracture, integrating BMD with clinical risk factors", "Daily calcium requirements", "Vitamin D levels"], a: 1, r: "FRAX integrates BMD T-score with clinical risk factors (age, sex, BMI, prior fracture, parental hip fracture, smoking, alcohol, corticosteroids, RA, secondary causes). Treatment threshold: ≥3% hip fracture or ≥20% major osteoporotic fracture 10-year probability.", s: "Musculoskeletal" },
  { q: "Osteonecrosis of the jaw (ONJ) is a rare complication of:", o: ["Calcium supplements", "Long-term bisphosphonate or denosumab therapy", "Vitamin D supplementation", "Exercise"], a: 1, r: "ONJ presents as exposed, non-healing jaw bone. Risk factors: dental procedures (tooth extraction), poor oral hygiene, and prolonged antiresorptive therapy. Patients should complete dental work BEFORE starting bisphosphonates/denosumab. Risk is approximately 1 in 10,000-100,000.", s: "Musculoskeletal" },
  { q: "Wolff's law explains why which intervention helps prevent osteoporosis?", o: ["Calcium supplementation", "Weight-bearing exercise — bone adapts its structure to the mechanical loads placed upon it", "Vitamin D supplementation", "Smoking cessation"], a: 1, r: "Wolff's law: bone remodels in response to mechanical stress. Weight-bearing exercise (walking, stair climbing, resistance training) stimulates osteocyte signaling and osteoblast recruitment, increasing bone formation. Sedentary lifestyle or prolonged immobilization accelerates bone loss.", s: "Musculoskeletal" },
  { q: "A nurse suspects a patient has a vertebral compression fracture. Expected findings include:", o: ["Sudden onset severe back pain that worsens with sitting/standing and improves with lying down, tenderness over the spinous process, and progressive kyphosis", "Sharp radiating pain down the leg", "Pain that improves with standing", "No pain — vertebral fractures are always asymptomatic"], a: 0, r: "Vertebral compression fractures present with sudden severe back pain at the fracture level, worse with axial loading (sitting, standing, bending), improved with recumbency. Tenderness over the affected spinous process is common. However, only 1/3 are clinically recognized — many are asymptomatic.", s: "Musculoskeletal" },
  { q: "Target serum 25-hydroxyvitamin D level for osteoporosis management is:", o: [">10 ng/mL", ">20 ng/mL", ">30 ng/mL", ">50 ng/mL"], a: 2, r: "Target 25-OH vitamin D >30 ng/mL for optimal calcium absorption and bone health. Vitamin D deficiency (<20 ng/mL) causes secondary hyperparathyroidism (increased PTH drives bone resorption). Supplementation: 800-2000 IU/day.", s: "Musculoskeletal" },
  { q: "Fall prevention in osteoporotic patients should include: Select all that apply.", o: ["Home safety assessment: remove throw rugs, install grab bars, ensure adequate lighting", "Medication review: assess for sedatives, antihypertensives, and other fall-risk medications", "Balance and strength training exercises", "Vision correction", "Limiting all physical activity"], a: 0, r: "Comprehensive fall prevention: home safety modifications, medication review (sedatives, antihypertensives, psychotropics increase fall risk), balance/strength training (tai chi, physical therapy), vision correction, and orthostatic hypotension management. Physical activity should be ENCOURAGED, not limited.", s: "Musculoskeletal", t: "sata", ca: [0, 1, 2, 3] },
  { q: "DEXA screening for osteoporosis is recommended for:", o: ["All adults over 30", "All women ≥65 years, all men ≥70 years, and younger adults with risk factors", "Only patients with fractures", "Only postmenopausal women on hormone therapy"], a: 1, r: "USPSTF guidelines: screen all women ≥65 and all men ≥70 with DEXA. Screen younger postmenopausal women and men 50-69 if they have risk factors (low BMI, smoking, corticosteroid use, prior fracture, family history, RA, excessive alcohol).", s: "Musculoskeletal" },
  { q: "A patient on alendronate reports chest pain and difficulty swallowing. What should the nurse suspect?", o: ["Cardiac event", "Esophageal irritation or erosion from the bisphosphonate — assess whether the patient has been following correct administration instructions", "Allergic reaction", "Anxiety"], a: 1, r: "Esophageal irritation/erosion is the most common adverse effect of oral bisphosphonates. It results from the tablet lodging in or irritating the esophageal mucosa. Assess whether the patient is following proper administration: empty stomach, full glass of water, upright 30 minutes.", s: "Musculoskeletal" },
  { q: "After starting bisphosphonate therapy, the nurse should consider a 'drug holiday' after:", o: ["6 months", "1-2 years", "5 years of oral therapy (or 3 years of IV zoledronic acid) — reassess fracture risk to determine if continued treatment is needed", "Drug holidays are never appropriate"], a: 2, r: "Bisphosphonates accumulate in bone and have residual antiresorptive effects after stopping. After 5 years of oral (or 3 years IV) therapy, a drug holiday may be appropriate for low-moderate risk patients. High-risk patients may continue longer. Reassess fracture risk periodically.", s: "Musculoskeletal" },
  { q: "A patient asks about calcium supplementation for osteoporosis prevention. The nurse advises:", o: ["Take 3000mg of calcium daily", "Take 1000-1200mg total daily calcium intake (diet + supplements) in divided doses for better absorption", "Calcium has no benefit for bone health", "Take calcium only when you feel weak"], a: 1, r: "Recommended total calcium intake: 1000-1200 mg/day from diet and supplements combined. Divided doses (≤500mg per dose) improve absorption. Dietary sources preferred (dairy, fortified foods). Excessive calcium (>2000mg/day) increases kidney stone and cardiovascular risk.", s: "Musculoskeletal" },
  { q: "Which fracture pattern is considered a 'fragility fracture' indicative of osteoporosis?", o: ["Fracture from a motor vehicle accident", "Fracture from a fall from standing height or less — minimal trauma causing a fracture indicates underlying bone fragility", "Fracture from a sports injury", "Fracture requiring surgical fixation"], a: 1, r: "Fragility fractures occur from minimal trauma that would not fracture normal bone — typically falls from standing height or less, or even spontaneous fractures. Common sites: vertebral bodies, hip (femoral neck/intertrochanteric), and distal radius (Colles). These fractures confirm clinical osteoporosis.", s: "Musculoskeletal" },
  { q: "The HPA axis negative feedback loop involves cortisol inhibiting:", o: ["Only ACTH release", "Both CRH from the hypothalamus AND ACTH from the anterior pituitary, maintaining cortisol homeostasis", "Aldosterone production", "ADH release"], a: 1, r: "Cortisol binds to glucocorticoid receptors in the hypothalamus (suppressing CRH) and anterior pituitary (suppressing ACTH). This dual negative feedback prevents cortisol overproduction after the stress response resolves. Disruption causes Cushing syndrome (excess) or Addison disease (deficiency).", s: "Endocrine" },
  { q: "Chronic stress causes HPA axis dysfunction through:", o: ["Immediate cortisol depletion", "Sustained cortisol elevation that downregulates glucocorticoid receptors, impairing negative feedback and creating a persistently activated stress axis", "Improved immune function", "Decreased cortisol production"], a: 1, r: "Chronic cortisol elevation causes receptor downregulation (decreased sensitivity), shifting the feedback set point. The axis remains activated at higher cortisol levels, contributing to metabolic syndrome, immunosuppression, depression, cognitive impairment, and accelerated cardiovascular disease.", s: "Endocrine" },
  { q: "A patient on chronic prednisone therapy who undergoes emergency surgery without stress-dose steroids is at risk for:", o: ["Hyperglycemia only", "Adrenal crisis from HPA axis suppression — the atrophied adrenals cannot mount an adequate cortisol response to surgical stress", "Hypertension", "No complications"], a: 1, r: "Chronic exogenous corticosteroids suppress CRH/ACTH via negative feedback, causing adrenal cortex atrophy. During surgery, the body requires 10x the normal cortisol output. Without stress-dose hydrocortisone (100mg IV bolus), the patient develops cardiovascular collapse from cortisol deficiency.", s: "Endocrine" },
  { q: "The cosyntropin stimulation test is performed by:", o: ["Giving oral cortisol", "Injecting synthetic ACTH and measuring cortisol response at 30 and 60 minutes — failure to rise above 18-20 mcg/dL confirms adrenal insufficiency", "Measuring morning cortisol only", "Giving dexamethasone"], a: 1, r: "Cosyntropin (synthetic ACTH1-24) 250 mcg IV/IM stimulates the adrenal cortex. Normal response: cortisol rises to ≥18-20 mcg/dL. Blunted response confirms adrenal insufficiency. The test cannot distinguish primary from secondary AI — additional ACTH levels are needed.", s: "Endocrine" },
  { q: "A patient with Addison disease presents with hyperpigmentation. This occurs because:", o: ["Sun exposure", "Elevated ACTH (from loss of cortisol feedback) co-stimulates melanocyte-stimulating hormone from POMC processing", "Iron deposition", "Medication side effect"], a: 1, r: "ACTH is cleaved from pro-opiomelanocortin (POMC), which also contains MSH. In primary AI, absent cortisol feedback causes dramatically elevated ACTH, increasing POMC processing and MSH release. MSH stimulates melanocytes, causing hyperpigmentation of skin creases, scars, buccal mucosa, and nipples.", s: "Endocrine" },
  { q: "Which electrolyte abnormalities distinguish PRIMARY from SECONDARY adrenal insufficiency?", o: ["Both present identically", "Primary AI has hyponatremia AND hyperkalemia (aldosterone deficiency); secondary AI has hyponatremia but NORMAL potassium (aldosterone preserved via RAAS)", "Neither has electrolyte changes", "Secondary AI has hyperkalemia"], a: 1, r: "Primary AI: adrenal cortex destroyed → both cortisol AND aldosterone deficient → hyponatremia (sodium wasting) AND hyperkalemia (impaired K+ excretion). Secondary AI: pituitary ACTH deficient → only cortisol deficient → aldosterone is preserved (RAAS-controlled) → hyponatremia but NORMAL potassium.", s: "Endocrine" },
  { q: "Emergency treatment of adrenal crisis includes:", o: ["Oral hydrocortisone only", "IV hydrocortisone 100mg bolus, aggressive IV normal saline resuscitation, dextrose for hypoglycemia, and identification/treatment of the precipitating cause", "Withholding fluids", "Potassium replacement first"], a: 1, r: "Adrenal crisis is a medical emergency: (1) IV hydrocortisone 100mg bolus then 50mg q6-8h (replaces cortisol + has mineralocorticoid activity); (2) aggressive IV NS (volume repletion for dehydration and hypotension); (3) D50 if hypoglycemic; (4) treat precipitant (infection, trauma, missed medication).", s: "Endocrine" },
  { q: "Cortisol's permissive effect on catecholamines means:", o: ["Cortisol inhibits catecholamines", "Without adequate cortisol, blood vessels lose responsiveness to epinephrine and norepinephrine, causing vasopressor-resistant hypotension", "Catecholamines produce cortisol", "Cortisol replaces catecholamines"], a: 1, r: "Cortisol maintains the expression of adrenergic receptors on vascular smooth muscle and sensitizes them to catecholamines. In cortisol deficiency, receptor expression decreases and vasodilation predominates, causing hypotension refractory to vasopressors. This is why cortisol replacement rapidly restores hemodynamic stability.", s: "Endocrine" },
  { q: "Stress-dose steroid guidelines recommend:", o: ["The same daily dose during illness", "Minor illness: double/triple oral dose; major surgery/trauma: IV hydrocortisone 100mg then 50mg q8h, tapering over 1-3 days as stress resolves", "No dose adjustment needed", "Stopping steroids during stress"], a: 1, r: "Stress dosing replaces the cortisol that suppressed adrenals cannot produce during physiologic stress. Normal daily cortisol production is approximately 5-7mg (equivalent to 20-25mg hydrocortisone), but during major stress, output increases to 100-300mg/day. Stress dosing matches this physiologic demand.", s: "Endocrine" },
  { q: "Thyroid storm mortality rate without treatment is approximately:", o: ["5%", "20-30%", "50%", "90%"], a: 2, r: "Thyroid storm has approximately 90% mortality if untreated, but even with aggressive treatment, mortality remains 20-30%. The extreme hypermetabolic state causes cardiovascular collapse from high-output heart failure, malignant hyperthermia, and multi-organ dysfunction.", s: "Endocrine" },
  { q: "Lugol's iodine is given in thyroid storm AFTER thionamides because:", o: ["It treats the underlying cause", "Iodine given BEFORE blocking hormone synthesis would provide substrate for MORE thyroid hormone production (Jod-Basedow phenomenon)", "The timing doesn't matter", "Lugol's replaces thyroid hormone"], a: 1, r: "Timing is critical: thionamides (PTU/methimazole) must be given first to block new thyroid hormone synthesis. Lugol's iodine is given 1 hour AFTER to exploit the Wolff-Chaikoff effect (excess iodine acutely inhibits organification and hormone release). Without prior thionamide blockade, iodine fuels MORE hormone production.", s: "Endocrine" },
  { q: "PTU is preferred over methimazole in thyroid storm because:", o: ["It works faster", "PTU blocks both thyroid hormone synthesis AND peripheral T4-to-T3 conversion (inhibits deiodinase), providing a dual mechanism to reduce active thyroid hormone", "It has fewer side effects", "Methimazole is not available"], a: 1, r: "Both PTU and methimazole block thyroid peroxidase (TPO), inhibiting new hormone synthesis. However, PTU additionally inhibits 5'-deiodinase, blocking peripheral conversion of T4 to the more active T3. This dual action makes PTU preferred in thyroid storm, despite its higher hepatotoxicity risk.", s: "Endocrine" },
  { q: "Beta-blockers in thyroid storm are given to:", o: ["Treat the underlying thyroid problem", "Control the adrenergic symptoms (tachycardia, tremor, anxiety, diaphoresis) — propranolol is preferred because it also inhibits T4-to-T3 conversion", "Lower thyroid hormone levels", "Prevent infection"], a: 1, r: "Beta-blockers do NOT reduce thyroid hormone levels but control the cardiovascular and neurological manifestations of excess catecholamine sensitivity. Propranolol is preferred because (1) it crosses the blood-brain barrier (anxiolysis) and (2) at high doses it inhibits peripheral T4-to-T3 conversion.", s: "Endocrine" },
  { q: "DKA treatment requires checking potassium before starting insulin because:", o: ["Potassium is always high in DKA", "Insulin drives potassium intracellularly — starting insulin with K+ <3.3 mEq/L can cause fatal hypokalemia and cardiac arrest", "Potassium has no relevance", "It is just a protocol requirement"], a: 1, r: "In DKA, total body potassium is DEPLETED despite initial serum levels that may appear normal or elevated (acidosis shifts K+ extracellularly). Insulin drives K+ back into cells, potentially dropping serum K+ to lethal levels. If K+ <3.3 mEq/L, replace K+ BEFORE starting insulin. If K+ 3.3-5.3, add 20-40 mEq KCl per liter of IV fluids.", s: "Endocrine" },
  { q: "Cerebral edema during DKA treatment in children occurs from:", o: ["Dehydration", "Too-rapid blood glucose reduction and fluid shifts — glucose should decrease no faster than 50-75 mg/dL/hour", "IV bicarbonate administration", "Insulin overdose"], a: 1, r: "Cerebral edema is the leading cause of DKA death in children. Rapid glucose reduction and aggressive fluid resuscitation cause osmotic fluid shifts into brain cells. Warning signs: headache, vomiting, altered consciousness, bradycardia, and hypertension (Cushing triad). Treatment: stop IV fluids, elevate HOB, IV mannitol or hypertonic saline.", s: "Endocrine" },
  { q: "HHS differs from DKA in that HHS:", o: ["Has lower glucose levels", "Has extreme hyperosmolarity (>320 mOsm/kg), much higher glucose (often >600 mg/dL), minimal/absent ketosis, and profound dehydration (8-12L deficit)", "Has significant ketoacidosis", "Occurs only in T1DM"], a: 1, r: "HHS occurs in T2DM where residual insulin prevents ketogenesis but cannot control glucose. The extreme hyperglycemia causes massive osmotic diuresis with profound dehydration. Key difference: HHS has minimal ketosis and pH >7.30, while DKA has significant ketoacidosis.", s: "Endocrine" },
  { q: "The anion gap in DKA is elevated because:", o: ["Sodium is low", "Ketoacids (acetoacetate and beta-hydroxybutyrate) are unmeasured anions that increase the gap between measured cations and anions", "Chloride is elevated", "Bicarbonate is normal"], a: 1, r: "Anion gap = Na+ - (Cl- + HCO3-). Normal: 8-12 mEq/L. In DKA, ketoacids (unmeasured anions) accumulate and consume bicarbonate as a buffer. The gap between sodium and (chloride + reduced bicarbonate) widens. The anion gap is used to monitor DKA resolution — it should close before stopping the insulin drip.", s: "Endocrine" },
  { q: "Fluid resuscitation in HHS is the FIRST priority because:", o: ["Insulin is not needed", "Correcting the profound dehydration (8-12L deficit) with IV normal saline restores renal perfusion, lowers glucose 35-70 mg/dL/hour through hemodilution and improved renal clearance, and improves tissue perfusion", "Fluids treat ketoacidosis", "Oral fluids are preferred"], a: 1, r: "HHS has more severe dehydration than DKA (8-12L deficit vs 3-6L). Aggressive IV NS (1L/hour for first 1-2 hours) is priority ONE: (1) restores intravascular volume and BP; (2) improves renal blood flow (glucose clearance); (3) causes hemodilution (lowering glucose concentration). Insulin is started AFTER initial fluid resuscitation.", s: "Endocrine" },
  { q: "Transitioning from IV to SQ insulin in DKA requires:", o: ["Just stopping the drip", "Anion gap closure, pH >7.30, patient able to eat, AND overlapping SQ insulin administration 1-2 hours BEFORE stopping the IV drip to prevent rebound ketosis", "Only a normal blood glucose", "No specific criteria"], a: 1, r: "All four criteria must be met: (1) anion gap closed (<12); (2) pH >7.30; (3) bicarbonate >15-18; (4) patient tolerating oral intake. The SQ long-acting insulin must be given 1-2 hours BEFORE stopping the insulin drip — this overlap prevents rebound ketosis from the gap between IV and SQ insulin action.", s: "Endocrine" },
  { q: "Philadelphia chromosome in leukemia involves which gene fusion?", o: ["PML-RARα", "BCR-ABL1 from t(9;22) translocation — the fusion protein is a constitutively active tyrosine kinase driving uncontrolled cell proliferation", "FLT3-ITD", "NPM1 mutation"], a: 1, r: "t(9;22) juxtaposes the BCR gene (chromosome 22) with the ABL1 gene (chromosome 9), creating a fusion protein with constitutive tyrosine kinase activity. This drives uncontrolled myeloid cell proliferation. Found in >95% of CML and approximately 25% of adult ALL. Treated with tyrosine kinase inhibitors (imatinib).", s: "Hematology" },
  { q: "Tumor lysis syndrome prophylaxis in leukemia includes:", o: ["No prophylaxis needed", "Aggressive IV hydration (3L/m²/day), allopurinol or rasburicase, and monitoring electrolytes/uric acid/renal function every 6-8 hours", "Oral fluids only", "Reducing chemotherapy dose"], a: 1, r: "TLS prevention starts 24-48 hours before chemotherapy: (1) aggressive IV hydration (dilutes electrolytes, promotes uric acid renal clearance); (2) allopurinol (inhibits new uric acid formation) or rasburicase (converts existing uric acid to allantoin — faster and more effective); (3) frequent lab monitoring (K+, PO4, Ca2+, uric acid, creatinine).", s: "Hematology" },
  { q: "Leukostasis is an emergency when WBC exceeds:", o: ["20,000/μL", "50,000/μL", "100,000/μL — hyperviscosity causes cerebral and pulmonary microvascular occlusion with stroke-like symptoms and respiratory failure", "200,000/μL"], a: 2, r: "Leukostasis: WBC >100,000 (hyperleukocytosis) with symptoms of microvascular occlusion. More common in AML (large, sticky myeloid blasts) than ALL. Symptoms: dyspnea, hypoxia, headache, confusion, visual changes, priapism. Treatment: emergent leukapheresis, hydroxyurea for rapid cytoreduction, and urgent chemotherapy initiation.", s: "Hematology" },
  { q: "CNS prophylaxis in ALL is necessary because:", o: ["ALL never affects the CNS", "The blood-brain barrier creates a sanctuary site where systemic chemotherapy cannot reach therapeutic concentrations, allowing leukemia cells to survive and cause relapse", "It is optional", "Only adults need CNS prophylaxis"], a: 1, r: "Without CNS prophylaxis, CNS relapse occurs in 50-75% of ALL patients. The BBB excludes most systemic chemotherapy agents. Intrathecal methotrexate (IT MTX), high-dose systemic MTX (which crosses BBB), and/or cranial radiation are used to prevent/treat CNS disease.", s: "Hematology" },
  { q: "ATRA (all-trans retinoic acid) for APL can cause which life-threatening complication?", o: ["Tumor lysis syndrome", "Differentiation syndrome — fever, dyspnea, pulmonary infiltrates, weight gain, and effusions from massive simultaneous maturation of promyelocytes", "Hepatic failure", "Renal failure"], a: 1, r: "Differentiation syndrome (formerly retinoic acid syndrome) occurs when ATRA induces rapid maturation of large numbers of promyelocytes simultaneously. The maturing cells release inflammatory cytokines, cause capillary leak, and infiltrate tissues. Symptoms: fever, dyspnea, pulmonary infiltrates, pleural/pericardial effusions, weight gain. Treatment: dexamethasone.", s: "Hematology" },
  { q: "DIC in APL (AML-M3) is caused by:", o: ["Platelet dysfunction", "Release of procoagulant granules (tissue factor, cancer procoagulant) from abnormal promyelocytes, triggering the coagulation cascade with simultaneous clotting and bleeding", "Vitamin K deficiency", "Liver disease"], a: 1, r: "APL promyelocytes contain granules packed with tissue factor and other procoagulants. Cell lysis (from disease or chemotherapy) releases these into the bloodstream, massively activating the coagulation cascade. Simultaneous thrombosis and hemorrhagic consumption of clotting factors/platelets creates the DIC paradox.", s: "Hematology" },
  { q: "Febrile neutropenia requires antibiotics within:", o: ["4 hours", "60 minutes of presentation — every hour of delay increases mortality in neutropenic patients who lack immune defenses", "24 hours", "Antibiotics are not urgent"], a: 1, r: "Door-to-antibiotic time <60 minutes is the standard of care. Neutropenic patients cannot mount an effective immune response — infection can progress to sepsis and death within hours. Obtain blood cultures FIRST but do NOT delay antibiotics for culture results. Empiric: cefepime, pip-tazo, or meropenem.", s: "Hematology" },
  { q: "Graft-versus-host disease (GVHD) after allogeneic transplant affects which organs? Select all that apply.", o: ["Skin (maculopapular rash)", "Liver (elevated bilirubin, hepatitis)", "GI tract (diarrhea, abdominal pain, nausea)", "Eyes (sicca/dry eyes in chronic GVHD)", "Bone marrow"], a: 0, r: "GVHD target organs: (1) skin — maculopapular rash (most common initial sign); (2) liver — elevated bilirubin, transaminases; (3) GI tract — profuse watery/bloody diarrhea, abdominal cramping, nausea; (4) eyes — keratoconjunctivitis sicca in chronic GVHD. Bone marrow is the graft source, not a GVHD target.", s: "Hematology", t: "sata", ca: [0, 1, 2, 3] },
  { q: "CAR-T cell therapy's most serious complication is:", o: ["Mild nausea", "Cytokine release syndrome (CRS) — massive cytokine release causing fever, hypotension, hypoxia, capillary leak, and potentially fatal multi-organ dysfunction", "Hair loss", "Mild fatigue"], a: 1, r: "CRS occurs when engineered CAR-T cells recognize and attack cancer cells, releasing massive amounts of cytokines (IL-6, IFN-γ, TNF-α). Mild CRS: fever, myalgia. Severe CRS: hypotension, hypoxia, capillary leak, DIC, multi-organ failure. Treatment: tocilizumab (IL-6 receptor blocker) and corticosteroids.", s: "Hematology" },
  { q: "Post-chemotherapy nadir typically occurs:", o: ["Immediately after chemotherapy", "7-14 days after chemotherapy — this is the period of maximum bone marrow suppression and highest infection risk", "30 days after", "3 months after"], a: 1, r: "The nadir represents maximum myelosuppression. For most regimens, ANC nadir occurs 7-14 days post-chemotherapy. Neutrophil recovery begins around day 14-21. During nadir: implement neutropenic precautions, monitor for infection signs (fever may be the ONLY indicator), and ensure patient understands when to seek emergency care.", s: "Hematology" },
  { q: "Aplastic crisis in sickle cell disease is usually caused by:", o: ["Iron deficiency", "Parvovirus B19 infection that selectively infects and destroys erythroid progenitor cells, halting RBC production for 7-10 days", "Folate deficiency", "Dehydration"], a: 1, r: "Parvovirus B19 binds to the P antigen on erythroid progenitors, causing lytic infection. Normal patients tolerate the 7-10 day production halt because their RBCs last 120 days. SCD patients (RBC lifespan 10-20 days) rapidly develop severe anemia with reticulocyte count near zero.", s: "Hematology" },
  { q: "Exchange transfusion in SCD is preferred over simple transfusion for:", o: ["Routine transfusions", "Acute stroke, severe ACS, and multi-organ failure — it rapidly reduces HbS% to <30% without hyperviscosity from volume overload", "All transfusions", "Iron deficiency only"], a: 1, r: "Exchange transfusion (automated erythrocytapheresis) removes sickled blood and replaces it with donor blood. Advantages: (1) rapid HbS reduction to <30%; (2) avoids increasing total hemoglobin/viscosity; (3) reduces iron loading compared to simple transfusion. Indicated for life-threatening SCD complications.", s: "Hematology" },
  { q: "Hydroxyurea in SCD reduces vaso-occlusive crises by:", o: ["Replacing sickled cells", "Reactivating fetal hemoglobin (HbF) production — HbF disrupts HbS polymerization and prevents sickling", "Providing oxygen to tissues", "Chelating iron"], a: 1, r: "Hydroxyurea stimulates γ-globin gene expression, increasing HbF production. HbF (α2γ2) cannot participate in the HbS polymer because γ chains interfere with the deoxyHbS contact site. Higher intracellular HbF concentration = less HbS polymerization = less sickling = fewer crises.", s: "Hematology" },
  { q: "Functional asplenia in SCD increases infection risk from:", o: ["Any organism", "Encapsulated bacteria (Streptococcus pneumoniae, Neisseria meningitidis, Haemophilus influenzae) — the spleen's filtering function is essential for clearing these organisms", "Only viral infections", "Fungal infections only"], a: 1, r: "The spleen filters encapsulated bacteria from the bloodstream. Without splenic function (autosplenectomy from repeated infarction), these organisms cause overwhelming post-splenectomy sepsis (OPSS). Prevention: pneumococcal, meningococcal, and HiB vaccines, plus prophylactic penicillin until at least age 5.", s: "Hematology" },
  { q: "Acute chest syndrome in SCD is managed with:", o: ["Antibiotics alone", "Oxygen, antibiotics (including atypical coverage), incentive spirometry, pain management, and exchange transfusion for severe cases", "Observation only", "IV fluids only"], a: 1, r: "ACS management: (1) supplemental O2 to maintain SpO2 >95%; (2) antibiotics (cephalosporin + macrolide for atypical coverage); (3) incentive spirometry q2h while awake (prevents atelectasis); (4) cautious pain management (avoid respiratory depression); (5) simple or exchange transfusion (target Hgb 10g/dL, HbS <30%).", s: "Hematology" },
  { q: "Thalassemia major requires lifelong transfusion therapy to:", o: ["Replace iron", "Maintain hemoglobin >9.5 g/dL, which suppresses ineffective erythropoiesis and prevents its complications (skeletal deformities, hepatosplenomegaly, iron hyperabsorption)", "Provide white blood cells", "Prevent infections"], a: 1, r: "Regular transfusions serve a dual purpose: (1) correct anemia (improving oxygen delivery and quality of life); (2) suppress endogenous erythropoiesis (preventing bone marrow expansion → skeletal deformities, extramedullary hematopoiesis → hepatosplenomegaly, and increased intestinal iron absorption → additional iron overload).", s: "Hematology" },
  { q: "Iron chelation therapy in thalassemia prevents organ damage from:", o: ["Iron deficiency", "Transfusional iron overload depositing in the heart (cardiomyopathy — leading cause of death), liver (cirrhosis), and endocrine glands (diabetes, hypogonadism, hypothyroidism)", "Calcium deposits", "Copper overload"], a: 1, r: "Each unit of PRBCs contains 200-250mg iron. After approximately 10-20 transfusions, iron accumulation exceeds the body's storage capacity (ferritin >1000 ng/mL). Free iron generates toxic reactive oxygen species via Fenton chemistry, damaging cellular membranes. Cardiac iron overload causes the majority of thalassemia-related deaths.", s: "Hematology" },
  { q: "Hemoglobin electrophoresis in beta-thalassemia minor characteristically shows:", o: ["Normal pattern", "Elevated HbA2 (>3.5%) — this is the diagnostic hallmark distinguishing thalassemia trait from iron deficiency anemia", "HbS only", "Absent HbA"], a: 1, r: "In β-thalassemia minor, reduced β-chain synthesis shifts hemoglobin production to alternative chains: δ-chains increase (HbA2 = α2δ2 rises >3.5%) and γ-chains may mildly increase (HbF = α2γ2). Normal HbA2 is <3.5%. Elevated HbA2 distinguishes thalassemia trait from iron deficiency (which has normal HbA2).", s: "Hematology" },
  { q: "A patient with thalassemia minor has microcytic anemia. Why should iron supplements be AVOIDED?", o: ["Iron causes hemolysis", "Thalassemia patients are NOT iron deficient — their anemia is from impaired hemoglobin synthesis, not iron lack; giving iron causes iatrogenic iron overload", "Iron worsens the genetic defect", "Iron is always contraindicated"], a: 1, r: "Thalassemia trait causes microcytic hypochromic anemia that mimics iron deficiency on CBC. However, thalassemia patients have normal or increased iron stores (from increased intestinal absorption due to ineffective erythropoiesis). Always check iron studies (serum iron, ferritin, TIBC) before treating microcytic anemia.", s: "Hematology" },
  { q: "Bone marrow biopsy in pancytopenia may show:", o: ["Only elevated WBCs", "Hypocellularity (aplastic anemia), hypercellularity with dysplasia (MDS), or infiltration (leukemia, myelofibrosis, metastatic cancer)", "Normal cellularity only", "Elevated platelets"], a: 1, r: "The bone marrow biopsy is essential for pancytopenia workup: (1) hypocellular (<30% cellularity in adults) = aplastic anemia; (2) hypercellular with dysplastic morphology = MDS (paradox of full marrow with low peripheral counts due to intramedullary apoptosis); (3) infiltrated = leukemia, fibrosis, or metastatic disease.", s: "Hematology" },
  { q: "MDS causes pancytopenia through:", o: ["Marrow aplasia", "Ineffective hematopoiesis — the bone marrow is hypercellular but produces dysplastic cells that undergo premature apoptosis before reaching the peripheral blood", "Peripheral destruction only", "Nutritional deficiency"], a: 1, r: "MDS paradox: the marrow is actively producing cells (often HYPERcellular) but these cells are clonal and morphologically/functionally abnormal (dysplastic). They die via apoptosis within the marrow before maturation (ineffective hematopoiesis). Result: full marrow + empty blood = peripheral cytopenias.", s: "Hematology" },
  { q: "Drug-induced pancytopenia is most commonly caused by: Select all that apply.", o: ["Chemotherapy agents", "Methotrexate", "Carbamazepine", "Sulfonamides", "Acetaminophen at therapeutic doses"], a: 0, r: "Common offenders: (1) chemotherapy — dose-dependent myelosuppression; (2) methotrexate — folate antagonist suppressing rapidly dividing cells; (3) carbamazepine — idiosyncratic aplastic anemia; (4) sulfonamides — idiosyncratic bone marrow suppression. Acetaminophen at therapeutic doses does not cause myelosuppression.", s: "Hematology", t: "sata", ca: [0, 1, 2, 3] },
  { q: "Nursing priorities for neutropenic patients include: Select all that apply.", o: ["Strict hand hygiene (most important intervention)", "No fresh flowers or standing water in the room", "Monitor temperature every 4 hours and report >38.0°C immediately", "Avoid rectal temperatures, suppositories, and invasive procedures", "Encourage visitors with active upper respiratory infections to wear masks only"], a: 0, r: "All neutropenic precautions apply except allowing visitors with active infections — they should NOT visit at all. Hand hygiene is the single most important infection prevention measure. No fresh flowers (Aspergillus risk), no standing water, no raw/undercooked foods. Report ANY fever immediately.", s: "Hematology", t: "sata", ca: [0, 1, 2, 3] },
  { q: "Aplastic anemia treatment for severe cases in young patients is:", o: ["Iron supplementation", "Allogeneic hematopoietic stem cell transplantation from an HLA-matched sibling donor — this is the only curative treatment for severe aplastic anemia", "Splenectomy", "Vitamin B12 injections"], a: 1, r: "Severe aplastic anemia (ANC <500) treatment: (1) age <40 with HLA-matched sibling: allogeneic stem cell transplant (75-90% cure rate); (2) no matched donor or age >40: immunosuppressive therapy (ATG + cyclosporine — 60-70% response rate); (3) supportive care: transfusions, growth factors, infection prophylaxis.", s: "Hematology" },
  { q: "The 4 classic X-ray findings of OA are:", o: ["Erosions and periarticular osteopenia", "Joint space narrowing, subchondral sclerosis, osteophytes, and subchondral cysts", "Periosteal reaction and soft tissue swelling", "Normal X-ray findings"], a: 1, r: "OA radiographic hallmarks: (1) joint space narrowing (asymmetric, from cartilage loss); (2) subchondral sclerosis (reactive bone hardening); (3) osteophytes (bony spurs at joint margins); (4) subchondral cysts (fluid-filled bone cavities). Unlike RA, OA does NOT show erosions, periarticular osteopenia, or symmetric joint space narrowing.", s: "Musculoskeletal" },
  { q: "OA joint stiffness characteristically lasts:", o: [">60 minutes", "<30 minutes and resolves with movement (gelling phenomenon) — unlike RA morning stiffness which lasts >60 minutes", "All day", "Only at night"], a: 1, r: "OA 'gelling': brief stiffness (<30 min) after rest/inactivity that resolves with movement. This differs from RA morning stiffness (>60 min) caused by inflammatory synovitis. The distinction helps differentiate OA from inflammatory arthritis. OA pain: worse with activity, better with rest. RA pain: better with movement.", s: "Musculoskeletal" },
  { q: "Matrix metalloproteinases (MMPs) contribute to OA by:", o: ["Rebuilding cartilage", "Degrading the type II collagen and proteoglycan matrix of articular cartilage faster than chondrocytes can repair it", "Providing joint lubrication", "Strengthening subchondral bone"], a: 1, r: "MMP-1, MMP-3, MMP-13, and ADAMTS-4/5 (aggrecanases) are upregulated in OA chondrocytes and synoviocytes. They break down the structural components of cartilage: type II collagen (providing tensile strength) and aggrecan (providing compressive resilience). This enzymatic degradation exceeds the limited repair capacity of chondrocytes.", s: "Musculoskeletal" },
  { q: "Weight loss of 10 pounds reduces knee joint force by:", o: ["10 pounds", "30-40 pounds per step — each pound of body weight translates to 3-4 pounds of force across the knee during walking", "5 pounds", "It has no effect"], a: 1, r: "Biomechanical amplification: the knee joint experiences 3-4x body weight during walking and up to 6-8x during stair climbing. A 10-pound weight loss therefore reduces knee loading by 30-40 pounds per step during walking. Additionally, adipose tissue produces inflammatory adipokines (IL-6, TNF-α) that directly degrade cartilage.", s: "Musculoskeletal" },
  { q: "First-line non-pharmacologic OA management includes: Select all that apply.", o: ["Low-impact exercise (walking, swimming, cycling)", "Weight loss if overweight", "Physical therapy for strengthening and range of motion", "Heat and cold therapy", "Complete bedrest"], a: 0, r: "All non-pharmacologic measures are first-line EXCEPT complete bedrest, which worsens OA by causing muscle atrophy, joint stiffness, and deconditioning. Exercise strengthens periarticular muscles (unloading the joint), maintains range of motion, and improves proprioception. Weight loss is the single most effective intervention for knee OA.", s: "Musculoskeletal", t: "sata", ca: [0, 1, 2, 3] },
  { q: "Intra-articular corticosteroid injections for OA provide:", o: ["Permanent relief", "Temporary relief (weeks to months) by reducing local inflammation and pain — limited to 3-4 injections per year to avoid cartilage damage", "No benefit", "Structural cartilage repair"], a: 1, r: "Intra-articular corticosteroids provide potent local anti-inflammatory effects, reducing pain and swelling. Benefits are temporary (typically 4-12 weeks). Repeated injections (>3-4/year) may accelerate cartilage loss. They are most useful for acute flares or to facilitate participation in physical therapy.", s: "Musculoskeletal" },
  { q: "Total knee replacement postoperative nursing priorities include: Select all that apply.", o: ["DVT prophylaxis (anticoagulation, SCDs, early mobilization)", "Continuous passive motion (CPM) or early ROM exercises", "Neurovascular checks of the affected extremity", "Pain management to facilitate participation in physical therapy", "Keeping the knee immobilized in full extension for 6 weeks"], a: 0, r: "Postoperative TKR priorities: (1) DVT prevention (anticoagulation, SCDs, early mobilization); (2) early ROM exercises/CPM to prevent stiffness; (3) neurovascular checks (circulation, sensation, movement); (4) multimodal pain management. Prolonged immobilization in full extension is NOT recommended — early mobilization within 24 hours is current standard.", s: "Musculoskeletal", t: "sata", ca: [0, 1, 2, 3] },
  { q: "Heberden nodes vs Bouchard nodes in OA: which joints are affected?", o: ["Both affect the same joints", "Heberden nodes = DIP joints; Bouchard nodes = PIP joints — both are bony enlargements (osteophytes) characteristic of OA", "Heberden = MCP; Bouchard = wrist", "Neither involves the hands"], a: 1, r: "Heberden nodes (DIP joints) and Bouchard nodes (PIP joints) are bony osteophytes that are pathognomonic for OA. Their location helps distinguish OA from RA: OA affects DIP joints (RA spares DIP); RA symmetrically affects MCP and PIP joints with soft tissue swelling (not bony nodes).", s: "Musculoskeletal" },
  { q: "Viscosupplementation for OA involves:", o: ["IV fluid administration", "Intra-articular injection of hyaluronic acid to supplement decreased synovial fluid viscosity and volume, providing temporary lubrication and pain relief", "Oral collagen supplements", "Joint lavage with saline"], a: 1, r: "In OA, synovial fluid hyaluronic acid concentration and molecular weight decrease, reducing viscoelastic properties. Viscosupplementation restores some lubrication and shock-absorbing capacity. Benefits are modest, temporary (6-12 months), and most effective in early-moderate OA. Evidence is mixed regarding superiority to placebo.", s: "Musculoskeletal" },
  { q: "Topical NSAIDs (diclofenac gel) are preferred over oral NSAIDs for localized OA because:", o: ["They are more effective systemically", "They provide local anti-inflammatory effect with significantly lower systemic absorption, reducing GI, renal, and cardiovascular adverse effects", "They are cheaper", "They work faster"], a: 1, r: "Topical NSAIDs achieve therapeutic concentrations in the target joint with minimal systemic absorption (<5% of oral dosing). This dramatically reduces GI (ulcers, bleeding), renal (AKI, CKD), and cardiovascular (MI, stroke) risks compared to oral NSAIDs, making them preferred for localized joint OA.", s: "Musculoskeletal" },
  { q: "SGLT2 inhibitors lower blood glucose by:", o: ["Stimulating insulin release", "Blocking glucose reabsorption in the proximal renal tubule, causing glycosuria and lowering blood glucose independent of insulin", "Enhancing insulin sensitivity", "Blocking glucagon"], a: 1, r: "SGLT2 inhibitors (empagliflozin, dapagliflozin, canagliflozin) block the sodium-glucose cotransporter 2 in the proximal convoluted tubule, preventing reabsorption of approximately 70g/day of filtered glucose. This insulin-independent mechanism also provides cardiovascular and renal protective benefits.", s: "Endocrine" },
  { q: "Euglycemic DKA is a dangerous complication of:", o: ["Metformin", "SGLT2 inhibitors — DKA occurs with near-normal glucose levels (<250 mg/dL), delaying diagnosis because providers expect hyperglycemia with DKA", "Sulfonylureas", "Insulin therapy"], a: 1, r: "SGLT2 inhibitors cause glycosuria that lowers glucose levels, but ketogenesis can still be triggered by insulin deficiency, dehydration, or illness. The near-normal glucose (euglycemic DKA) masks the diagnosis. Suspect DKA in any patient on SGLT2i with nausea, vomiting, malaise, or metabolic acidosis regardless of glucose level.", s: "Endocrine" },
  { q: "The dawn phenomenon in diabetes is managed by:", o: ["Eating a bedtime snack", "Adjusting the timing or dose of evening/nighttime insulin to cover the early morning counterregulatory hormone surge", "Reducing morning insulin", "No treatment needed"], a: 1, r: "Dawn phenomenon: physiologic surge of GH and cortisol in early morning (4-8 AM) causes hyperglycemia. Management: (1) give NPH/intermediate insulin later in the evening; (2) use insulin pump with increased basal rate 4-8 AM; (3) adjust long-acting insulin dose. Differentiate from Somogyi effect (rebound from nocturnal hypoglycemia) by checking 3 AM glucose.", s: "Endocrine" },
  { q: "Diabetic retinopathy is caused by:", o: ["Elevated cholesterol", "Chronic hyperglycemia damaging retinal microvasculature — nonproliferative (microaneurysms, hemorrhages) progresses to proliferative (neovascularization with risk of vitreous hemorrhage and retinal detachment)", "Cataracts only", "Optic nerve compression"], a: 1, r: "Hyperglycemia damages retinal capillaries through polyol pathway activation, AGE formation, and PKC activation. Nonproliferative: microaneurysms, dot-blot hemorrhages, cotton wool spots, hard exudates. Proliferative: VEGF-driven neovascularization — new fragile vessels bleed (vitreous hemorrhage) and cause tractional retinal detachment.", s: "Endocrine" },
  { q: "Diabetic foot ulcers result from the combination of:", o: ["Poor hygiene only", "Peripheral neuropathy (loss of protective sensation), peripheral arterial disease (impaired healing), and hyperglycemia-induced immune dysfunction (infection risk)", "Improper footwear only", "Genetic predisposition only"], a: 1, r: "The triad of diabetic foot complications: (1) neuropathy — loss of pain sensation allows undetected injuries; (2) PAD — reduced blood flow impairs wound healing and antibiotic delivery; (3) immunopathy — hyperglycemia impairs WBC function (chemotaxis, phagocytosis). Teaching: daily foot inspection, proper footwear, avoid walking barefoot, professional nail care.", s: "Endocrine" },
  { q: "The honeymoon phase in T1DM:", o: ["Is a permanent cure", "Is a temporary period of reduced insulin requirements from residual beta cell function — it always ends as autoimmune destruction continues", "Occurs only in adults", "Means the patient doesn't need insulin"], a: 1, r: "After T1DM diagnosis and insulin initiation, beta cell rest and reduced glucotoxicity allow residual beta cells to improve function temporarily. Insulin requirements may decrease significantly. This phase lasts weeks to months but is NOT a cure — autoimmune destruction continues to completion. The patient ALWAYS needs insulin long-term.", s: "Endocrine" },
  { q: "Continuous glucose monitoring (CGM) measures glucose in:", o: ["Venous blood", "Interstitial fluid via a subcutaneous sensor — readings lag 5-15 minutes behind blood glucose, significant during rapid glucose changes", "Capillary blood", "Urine"], a: 1, r: "CGM sensors measure glucose in interstitial fluid, which equilibrates with blood glucose with a 5-15 minute lag. This lag matters during rapid glucose changes (post-meals, exercise, insulin bolus). CGM provides: real-time readings, trend arrows, high/low alerts, and time-in-range data that complements HbA1c.", s: "Endocrine" },
  { q: "Insulin lipodystrophy is prevented by:", o: ["Using the same injection site", "Rotating injection sites systematically within the same anatomic region to prevent subcutaneous fat changes that alter insulin absorption", "Injecting into muscle", "Using only the abdomen"], a: 1, r: "Lipohypertrophy (fatty lumps) develops from repeated insulin injection at the same site. These areas have erratic insulin absorption, causing unpredictable blood glucose. Prevention: systematic rotation within a region (e.g., abdomen — use a grid pattern). Teach patients to feel for lumps and avoid injecting into them.", s: "Endocrine" },
  { q: "Sick-day rules for T1DM patients include:", o: ["Stopping insulin during illness", "NEVER stopping insulin, checking glucose every 2-4 hours, checking ketones, maintaining hydration, and contacting provider if unable to keep fluids down or ketones are moderate/large", "Eating normally regardless of nausea", "Reducing fluid intake"], a: 1, r: "Critical teaching: (1) NEVER stop insulin — illness increases counterregulatory hormones and insulin demand; (2) check glucose q2-4h; (3) check urine/blood ketones q4h; (4) sip fluids (water, clear broth) to prevent dehydration; (5) if vomiting or large ketones → ED evaluation; (6) may need increased basal insulin during illness.", s: "Endocrine" },
  { q: "HbA1c reflects average glucose over:", o: ["24 hours", "1 week", "2-3 months — corresponding to the average lifespan of red blood cells", "6 months"], a: 2, r: "HbA1c measures glycated hemoglobin — glucose irreversibly binds to hemoglobin over the RBC's 120-day lifespan. The result reflects average glucose over the preceding 2-3 months, with more recent weeks weighted more heavily. Target: <7% for most adults with diabetes. Each 1% increase ≈ 30 mg/dL average glucose increase.", s: "Endocrine" },
  { q: "Hypoglycemia in diabetic patients is defined as glucose:", o: ["<100 mg/dL", "<70 mg/dL — symptoms include tremor, diaphoresis, tachycardia, confusion, and if untreated, seizures and loss of consciousness", "<50 mg/dL", "<40 mg/dL"], a: 1, r: "Hypoglycemia (<70 mg/dL): Level 1 (54-70): autonomic symptoms (tremor, diaphoresis, palpitations, hunger). Level 2 (<54): neuroglycopenic symptoms (confusion, slurred speech, visual changes). Level 3: severe — altered consciousness, seizure, requiring assistance. Treatment: Rule of 15 (15g fast-acting carbs, recheck in 15 min).", s: "Endocrine" },
  { q: "Glucagon is administered for hypoglycemia when:", o: ["The patient can swallow", "The patient is unconscious or unable to safely swallow — glucagon stimulates hepatic glycogenolysis to raise blood glucose", "The patient's glucose is >100", "The patient has type 2 diabetes only"], a: 1, r: "Glucagon 1mg IM/SQ (or intranasal) for severe hypoglycemia when the patient cannot safely take oral glucose (unconscious, seizing, combative). Glucagon stimulates hepatic glycogenolysis, raising glucose within 10-20 minutes. Position the patient on their side (aspiration risk from nausea/vomiting). Recheck glucose in 15 minutes.", s: "Endocrine" },
  { q: "Thyroid storm causes cardiac complications because:", o: ["Thyroid hormones have no cardiac effect", "Excess thyroid hormones increase cardiac β-adrenergic receptor sensitivity and number, causing severe tachycardia, high-output heart failure, and atrial fibrillation", "Thyroid hormones decrease heart rate", "Only through volume overload"], a: 1, r: "Thyroid hormones upregulate β-adrenergic receptors on cardiomyocytes, amplifying catecholamine effects. This causes: (1) severe tachycardia (rate often >140); (2) increased contractility and stroke volume → high-output state; (3) atrial fibrillation (10-35% of thyrotoxic patients); (4) high-output heart failure (the heart cannot sustain the elevated demand).", s: "Endocrine" },
  { q: "Myxedema coma is the opposite extreme of thyroid storm and presents with:", o: ["Tachycardia and fever", "Profound hypothermia, bradycardia, altered consciousness, hypotension, hyponatremia, and respiratory failure — triggered by cold exposure, infection, or sedatives in untreated hypothyroidism", "Normal vital signs", "Hyperglycemia"], a: 1, r: "Myxedema coma = decompensated hypothyroidism with: (1) hypothermia (may be <95°F — use a low-reading thermometer); (2) bradycardia; (3) hypotension; (4) altered consciousness → coma; (5) hyponatremia (impaired free water clearance); (6) hypoglycemia; (7) hypoventilation → respiratory failure → CO2 retention. Mortality: 30-60%.", s: "Endocrine" },
  { q: "Aspirin is CONTRAINDICATED in thyroid storm because:", o: ["It causes bleeding", "It displaces thyroid hormones from thyroid-binding globulin, increasing FREE (active) thyroid hormone levels and potentially worsening the storm", "It is an antipyretic", "It interacts with propranolol"], a: 1, r: "Aspirin displaces T3 and T4 from their carrier proteins (TBG, albumin, transthyretin), increasing the unbound (free, active) fraction. This can worsen thyroid storm by raising free thyroid hormone levels. Use acetaminophen instead for fever reduction in thyroid storm.", s: "Endocrine" },
  { q: "Agranulocytosis from thionamide therapy presents with:", o: ["Mild fatigue", "Sudden sore throat, high fever, and oral ulcers — requires immediate CBC and drug discontinuation", "Rash only", "Weight gain"], a: 1, r: "Thionamide-induced agranulocytosis (ANC <500) is an immunologic reaction, not dose-dependent. It occurs in 0.1-0.5% of patients, usually within the first 3 months. Presentation: abrupt onset sore throat, fever, mouth ulcers. Teach patients to stop the drug immediately and go to the ED for a stat CBC if these symptoms develop.", s: "Endocrine" },
  { q: "Cholestyramine is sometimes used in thyroid storm because:", o: ["It treats cholesterol", "It binds thyroid hormones in the GI tract, preventing enterohepatic recirculation and enhancing fecal elimination of T3 and T4", "It reduces fever", "It blocks thyroid synthesis"], a: 1, r: "Thyroid hormones undergo enterohepatic circulation: they are excreted in bile, reabsorbed in the intestine, and returned to the circulation. Cholestyramine (bile acid sequestrant) binds thyroid hormones in the gut, preventing reabsorption and increasing fecal elimination. This provides an additional mechanism to reduce circulating thyroid hormone levels.", s: "Endocrine" },
  { q: "The nurse teaching a patient with Addison disease about emergency preparedness should include:", o: ["No special preparations needed", "Carrying a medical alert bracelet, keeping an emergency IM hydrocortisone injection kit, training family members on injection technique, and understanding sick-day steroid dosing", "Only carrying extra oral medication", "Calling 911 for any illness"], a: 1, r: "Addison disease emergency preparedness: (1) Medical alert bracelet/necklace stating 'adrenal insufficiency — requires stress-dose steroids'; (2) Emergency IM hydrocortisone kit (Solu-Cortef 100mg) — teach patient AND family to administer; (3) Sick-day rules card; (4) Never run out of medication; (5) Notify all healthcare providers of AI diagnosis.", s: "Endocrine" },
  { q: "Cushing syndrome's clinical manifestations include: Select all that apply.", o: ["Central obesity with thin extremities (buffalo hump, moon face)", "Purple striae >1cm wide on abdomen", "Easy bruising and poor wound healing", "Proximal muscle weakness", "Weight loss and hypotension"], a: 0, r: "Cushing features from chronic cortisol excess: (1) central obesity (visceral fat deposition); (2) wide purple striae (fragile skin from collagen breakdown); (3) easy bruising (capillary fragility); (4) proximal myopathy (protein catabolism); (5) hypertension (not hypotension — cortisol's mineralocorticoid effect); (6) hyperglycemia; (7) osteoporosis.", s: "Endocrine", t: "sata", ca: [0, 1, 2, 3] },
  { q: "24-hour urine free cortisol is used to diagnose:", o: ["Adrenal insufficiency", "Cushing syndrome — elevated levels confirm hypercortisolism; combined with dexamethasone suppression test and midnight salivary cortisol for confirmation", "Thyroid disorders", "Pheochromocytoma"], a: 1, r: "Three screening tests for Cushing syndrome: (1) 24-hour urine free cortisol (>3x upper normal is diagnostic); (2) late-night salivary cortisol (loss of diurnal variation — cortisol should be lowest at midnight); (3) low-dose dexamethasone suppression test (failure to suppress cortisol after 1mg dexamethasone at bedtime). Two positive tests confirm Cushing.", s: "Endocrine" },
  { q: "Pheochromocytoma must be ruled out before surgery in a patient with:", o: ["Hypothyroidism", "Episodic severe hypertension, headache, diaphoresis, and palpitations — undiagnosed pheochromocytoma can cause fatal hypertensive crisis during anesthesia", "Stable hypertension", "Hypotension"], a: 1, r: "The classic triad: episodic headache + palpitations + diaphoresis with severe hypertension. Pheochromocytoma secretes catecholamines (epinephrine/norepinephrine) from the adrenal medulla. Anesthesia can trigger massive catecholamine release → hypertensive crisis, cardiac arrhythmias, or death. Screen with plasma metanephrines. Alpha-blockade (phenoxybenzamine) BEFORE beta-blockade.", s: "Endocrine" },
  { q: "Rheumatoid factor (RF) is positive in RA but is NOT specific because:", o: ["It is always negative in RA", "RF can be positive in chronic infections, other autoimmune diseases (Sjögren, SLE), hepatitis C, and even in 5-10% of healthy elderly", "It is 100% specific for RA", "It is only positive in severe RA"], a: 1, r: "RF (IgM anti-IgG) is sensitive (60-80%) but NOT specific for RA. Positive in: hepatitis C, bacterial endocarditis, TB, Sjögren syndrome, SLE, sarcoidosis, and 5-10% of healthy elderly. Anti-CCP antibodies are much more specific (>95%) and are the preferred serologic test for RA diagnosis.", s: "Musculoskeletal" },
  { q: "Pannus formation in RA represents:", o: ["Normal healing tissue", "Proliferative inflammatory synovial tissue that invades and erodes articular cartilage and subchondral bone — the hallmark destructive process of RA", "Scar tissue", "Bone growth"], a: 1, r: "Pannus: abnormal granulation tissue formed from proliferating fibroblast-like synoviocytes, infiltrating T cells, macrophages, B cells, and new blood vessels. The pannus grows over the cartilage surface and invades both cartilage and bone through enzymatic degradation (MMPs, cathepsins). This is the mechanism of irreversible joint destruction in RA.", s: "Musculoskeletal" },
  { q: "Methotrexate for RA requires folic acid supplementation because:", o: ["Folic acid is the antidote", "Methotrexate inhibits dihydrofolate reductase, and folic acid supplementation (1mg daily) reduces GI, hematologic, and hepatic side effects without reducing efficacy", "Folic acid enhances methotrexate", "It is not needed"], a: 1, r: "Methotrexate is a folate antagonist — it inhibits dihydrofolate reductase and other folate-dependent enzymes. Folic acid 1mg daily (NOT on methotrexate dosing day) replenishes folate pools, reducing mucositis, nausea, hepatotoxicity, and myelosuppression. Leucovorin (folinic acid) is the rescue agent for methotrexate toxicity.", s: "Musculoskeletal" },
  { q: "Biologic DMARDs for RA (adalimumab, etanercept) require screening for:", o: ["Only liver function", "Latent tuberculosis (PPD/IGRA) and hepatitis B before starting — TNF-α inhibition increases risk of reactivation of these infections", "Only renal function", "No screening needed"], a: 1, r: "TNF-α is critical for containing intracellular pathogens (TB, fungi). Blocking it allows latent TB to reactivate. Required screening: (1) PPD or IGRA for latent TB — if positive, treat with isoniazid before starting biologic; (2) Hepatitis B serologies — HBV reactivation can cause fulminant hepatic failure; (3) Baseline CBC, LFTs, lipids.", s: "Musculoskeletal" },
  { q: "Extra-articular manifestations of RA include: Select all that apply.", o: ["Rheumatoid nodules on extensor surfaces", "Interstitial lung disease and pleural effusions", "Pericarditis and accelerated atherosclerosis", "Scleritis and keratoconjunctivitis sicca", "Improved wound healing"], a: 0, r: "RA is a systemic disease: (1) Rheumatoid nodules (20-30% of patients) — subcutaneous, over pressure points; (2) Pulmonary — ILD, pleuritis, effusions; (3) Cardiac — pericarditis, accelerated atherosclerosis (CVD is #1 cause of death); (4) Ocular — scleritis, sicca; (5) Vasculitis; (6) Felty syndrome. RA impairs wound healing, it does not improve it.", s: "Musculoskeletal", t: "sata", ca: [0, 1, 2, 3] },
  { q: "Swan neck deformity in RA involves:", o: ["MCP joint subluxation", "PIP hyperextension with DIP flexion — caused by chronic synovitis weakening the volar plate and lateral bands of the extensor mechanism", "Ulnar deviation", "Wrist fusion"], a: 1, r: "Swan neck deformity: PIP hyperextension + DIP flexion. Mechanism: RA synovitis damages the volar plate at the PIP (allowing hyperextension) and causes lateral band subluxation (pulling DIP into flexion). Boutonniere deformity is the opposite: PIP flexion + DIP hyperextension from central slip disruption.", s: "Musculoskeletal" },
  { q: "Ulnar deviation in RA occurs at the MCP joints because:", o: ["Bones are eroded", "Chronic synovitis weakens radial collateral ligaments and allows extensor tendon ulnar subluxation — the pull of flexor tendons then deviates fingers toward the ulnar side", "Muscles are too strong", "Ligaments shorten"], a: 1, r: "MCP joint anatomy: radial collateral ligaments are weaker than ulnar. RA synovitis preferentially stretches these weaker radial structures. As radial support fails, extensor tendons sublux ulnarly, and the mechanical advantage of the flexor tendons (which cross MCP at an ulnar angle) gradually deviates all fingers toward the ulnar side.", s: "Musculoskeletal" },
  { q: "C1-C2 (atlantoaxial) instability in RA must be assessed before:", o: ["Starting NSAIDs", "Intubation or any procedure requiring neck manipulation — RA can erode the transverse ligament of C1, allowing the odontoid process to compress the cervical spinal cord", "Drawing blood", "Starting physical therapy"], a: 1, r: "RA erodes the transverse ligament of the atlas (C1), which normally prevents posterior displacement of the dens (C2). Atlantodental interval >3mm on flexion C-spine X-ray = instability. Risk: dens compresses the cervical cord during neck flexion (intubation, positioning). Assess for neck pain, paresthesias, and gait changes.", s: "Musculoskeletal" },
  { q: "Joint protection principles for RA patients include: Select all that apply.", o: ["Use the largest joint possible for the task", "Distribute load across multiple joints", "Avoid positions of deformity (sustained grip, ulnar deviation)", "Use assistive devices to reduce joint stress", "Forcefully push through pain during exercise"], a: 0, r: "Joint protection reduces mechanical stress: (1) large joints over small (push doors with hip); (2) distribute load (carry with both hands/forearms); (3) avoid deformity-promoting positions; (4) use adaptive equipment (jar openers, built-up handles). Pushing through pain is WRONG — pain signals inflammation and joint damage; reduce activity during flares.", s: "Musculoskeletal", t: "sata", ca: [0, 1, 2, 3] },
  { q: "Felty syndrome is a complication of RA consisting of:", o: ["Joint deformity only", "RA + splenomegaly + neutropenia — increasing infection risk significantly", "RA + renal failure", "RA + liver disease"], a: 1, r: "Felty syndrome triad: (1) seropositive RA (usually long-standing); (2) splenomegaly (sequestering neutrophils); (3) neutropenia (ANC <2000). The neutropenia dramatically increases infection risk. Occurs in <1% of RA patients but carries significant morbidity. Treatment: aggressive RA treatment with DMARDs, growth factors, possibly splenectomy.", s: "Musculoskeletal" },
  { q: "Sickle cell patients should receive which immunizations beyond routine? Select all that apply.", o: ["Pneumococcal (PCV13 and PPSV23)", "Meningococcal (MenACWY and MenB)", "Haemophilus influenzae type B", "Annual influenza", "None — routine immunizations are sufficient"], a: 0, r: "Functional asplenia from autosplenectomy increases susceptibility to encapsulated organisms. Required: (1) pneumococcal (PCV13 + PPSV23); (2) meningococcal (both conjugate and serogroup B); (3) HiB; (4) annual influenza. These are beyond routine childhood immunizations. Prophylactic penicillin is also given until at least age 5.", s: "Hematology", t: "sata", ca: [0, 1, 2, 3] },
  { q: "Crizanlizumab for SCD works by:", o: ["Increasing HbF", "Blocking P-selectin on endothelial cells, preventing sickled RBC adhesion to vessel walls and reducing vaso-occlusive crises", "Chelating iron", "Replacing hemoglobin"], a: 1, r: "P-selectin is an adhesion molecule on activated endothelial cells that mediates sickled RBC adhesion to vessel walls, initiating vaso-occlusion. Crizanlizumab (monoclonal antibody) blocks P-selectin, reducing RBC-endothelial interaction and decreasing VOC frequency. FDA-approved for reducing VOC in SCD patients age ≥16.", s: "Hematology" },
  { q: "L-glutamine supplementation in SCD reduces oxidative stress by:", o: ["Providing iron", "Serving as a precursor for NAD+ (nicotinamide adenine dinucleotide) and glutathione, protecting sickle RBCs from oxidative damage that promotes sickling", "Increasing HbF", "Blocking polymerization"], a: 1, r: "Sickle RBCs have increased oxidative stress from repeated sickling/unsickling cycles. L-glutamine increases intracellular NAD+ and glutathione (antioxidant) levels, reducing oxidative damage to the RBC membrane. This decreases hemolysis and VOC frequency. FDA-approved for SCD patients ≥5 years to reduce acute complications.", s: "Hematology" },
  { q: "Gene therapy for SCD aims to:", o: ["Replace the spleen", "Correct or compensate for the sickle mutation by modifying the patient's own hematopoietic stem cells — either by gene addition (adding functional β-globin) or gene editing (reactivating fetal hemoglobin)", "Provide lifelong transfusions", "Remove the spleen"], a: 1, r: "Two gene therapy approaches: (1) gene addition — insert a functional or modified β-globin gene using a lentiviral vector (lovotibeglogene autotemcel); (2) gene editing — use CRISPR-Cas9 to disrupt BCL11A (a repressor of fetal hemoglobin), reactivating HbF production (exagamglogene autotemcel). Both require myeloablative conditioning and autologous stem cell transplant.", s: "Hematology" },
  { q: "Dactylitis (hand-foot syndrome) in infants with SCD is caused by:", o: ["Infection", "Vaso-occlusion in the small bones of the hands and feet — often the FIRST clinical manifestation of SCD, appearing at 6-12 months when fetal hemoglobin declines", "Allergic reaction", "Vitamin deficiency"], a: 1, r: "Dactylitis: symmetric painful swelling of hands and feet in infants 6-24 months. It occurs when HbF levels decline sufficiently (around 6 months) for HbS to predominate. Vaso-occlusion in metacarpal/metatarsal and phalangeal bones causes infarction and periosteal inflammation. Often the first clinical sign prompting SCD diagnosis.", s: "Hematology" },
  { q: "Avascular necrosis (osteonecrosis) in SCD most commonly affects:", o: ["The spine", "The femoral head — repeated vaso-occlusion of end-arteries supplying the femoral head causes bone infarction and eventual joint collapse", "The mandible", "The fingers"], a: 1, r: "The femoral head has a vulnerable blood supply (medial circumflex femoral artery provides most blood via retinacular vessels). Repeated vaso-occlusion causes bone marrow ischemia → infarction → weakening → collapse of the femoral head articular surface. Affects 10-50% of SCD patients by age 35. May require hip replacement.", s: "Hematology" },
  { q: "Hemoglobin SC disease differs from HbSS disease in that:", o: ["Both are identical", "HbSC is generally milder with higher hemoglobin but has increased risk of proliferative retinopathy and avascular necrosis compared to the overall milder clinical course", "HbSC is always more severe", "HbSC never causes complications"], a: 1, r: "HbSC disease (one S gene + one C gene): generally milder than HbSS — higher hemoglobin (10-12g/dL), less hemolysis, fewer pain crises. However, the higher viscosity paradoxically increases risk of proliferative retinopathy, avascular necrosis, and splenic sequestration (spleen remains functional longer than in HbSS). Splenectomy may be needed.", s: "Hematology" },
  { q: "Iron chelation agents include: Select all that apply.", o: ["Deferoxamine (Desferal) — IV/SQ infusion over 8-12 hours", "Deferasirox (Exjade/Jadenu) — oral once-daily tablet", "Deferiprone (Ferriprox) — oral three times daily", "Calcium gluconate", "Sodium bicarbonate"], a: 0, r: "Three iron chelation agents: (1) Deferoxamine — parenteral (IV/SQ), 8-12 hour infusion via portable pump, most established agent; (2) Deferasirox — oral, once daily, most commonly used for convenience; (3) Deferiprone — oral, TID, unique for cardiac iron removal. Calcium gluconate and sodium bicarbonate are not chelation agents.", s: "Hematology", t: "sata", ca: [0, 1, 2] },
  { q: "Luspatercept benefits thalassemia patients by:", o: ["Chelating iron", "Targeting the TGF-β superfamily to promote late-stage erythroid maturation, reducing ineffective erythropoiesis and transfusion requirements", "Replacing hemoglobin", "Suppressing the immune system"], a: 1, r: "Luspatercept (modified activin receptor) traps TGF-β superfamily ligands (GDF11, activin B) that normally inhibit late-stage erythroid differentiation. By blocking these inhibitory signals, it promotes terminal erythroid maturation, improving effective RBC production and reducing transfusion burden in beta-thalassemia.", s: "Hematology" },
  { q: "Bone marrow transplant for thalassemia major is most successful when:", o: ["Performed in adulthood", "Performed in childhood from an HLA-matched sibling donor before the development of iron overload complications — cure rates exceed 80-90%", "Any donor is acceptable", "Iron overload is established"], a: 1, r: "Transplant outcomes correlate with: (1) age (younger = better); (2) donor type (HLA-matched sibling = best); (3) pre-transplant iron status (less iron overload = better outcomes). The Pesaro classification stratifies risk based on hepatomegaly, liver fibrosis, and chelation history. Matched sibling transplant in low-risk children: >90% disease-free survival.", s: "Hematology" },
  { q: "MDS (myelodysplastic syndrome) can transform into:", o: ["Chronic lymphocytic leukemia", "Acute myeloid leukemia (AML) — approximately 30% of MDS cases progress to AML, making MDS a 'pre-leukemic' condition", "Chronic myeloid leukemia", "Multiple myeloma"], a: 1, r: "MDS is a clonal stem cell disorder with inherent genomic instability. Accumulation of additional mutations drives progression from ineffective hematopoiesis to overt AML in approximately 30% of patients. Higher IPSS-R scores (more cytopenias, higher blast percentage, adverse cytogenetics) predict faster transformation.", s: "Hematology" },
  { q: "Disseminated intravascular coagulation (DIC) in leukemia presents with:", o: ["Elevated platelets only", "Simultaneous thrombosis and hemorrhage — elevated PT/INR, aPTT, D-dimer; decreased fibrinogen and platelets from consumption", "Normal coagulation studies", "Only bruising"], a: 1, r: "DIC paradox: simultaneous clot formation (microvascular thrombosis → organ damage) and bleeding (consumption of clotting factors and platelets). Labs: prolonged PT/aPTT, low fibrinogen (<100), elevated D-dimer/FDP, thrombocytopenia, schistocytes on smear. Most common in APL (AML-M3). Treatment: treat underlying cause, replace factors (FFP, cryo, platelets).", s: "Hematology" },
  { q: "Neutropenic diet recommendations have changed to emphasize:", o: ["Avoiding all fresh foods", "Safe food handling practices (thorough washing, proper cooking temperatures, avoiding unpasteurized products) rather than blanket restriction of fresh fruits and vegetables", "Only eating canned foods", "Parenteral nutrition for all neutropenic patients"], a: 1, r: "The traditional 'neutropenic diet' (no raw foods) lacked evidence of benefit and may have been harmful (nutritional deficiencies, reduced compliance). Current evidence supports safe food handling: thorough handwashing, washing produce, proper meat cooking temperatures, avoiding unpasteurized products, and proper food storage.", s: "Hematology" },
  { q: "Differentiation syndrome from ATRA therapy in APL is treated with:", o: ["Stopping chemotherapy", "Dexamethasone 10mg IV every 12 hours — it counteracts the cytokine storm from rapid promyelocyte maturation", "IV fluids only", "Blood transfusion"], a: 1, r: "Differentiation syndrome: rapid simultaneous maturation of promyelocytes releases massive cytokines → capillary leak, pulmonary infiltrates, effusions, weight gain, fever. Treatment: (1) dexamethasone 10mg IV q12h until symptom resolution; (2) continue ATRA if mild; (3) hold ATRA temporarily if severe; (4) supportive care (O2, diuretics).", s: "Hematology" },
  { q: "A nurse is caring for a patient with AML who has blast count of 85%. Which complication should the nurse monitor for during initial chemotherapy?", o: ["Hyperkalemia only", "Tumor lysis syndrome — rapid cell death releases intracellular potassium, phosphorus, uric acid, and nucleic acids, potentially causing renal failure and cardiac arrhythmias", "Improved blood counts immediately", "No complications expected"], a: 1, r: "High blast count (>85%) = massive tumor burden with high risk of TLS during induction chemotherapy. Prevention: aggressive hydration (3L/m²/day) starting 24-48 hours before chemo, allopurinol or rasburicase, and frequent electrolyte monitoring (q6-8h). Monitor for hyperkalemia (cardiac risk), hyperphosphatemia, hypocalcemia, and rising creatinine.", s: "Hematology" },
  { q: "Bone marrow recovery after chemotherapy is indicated by:", o: ["Decreased WBC", "Rising absolute neutrophil count (ANC) and reticulocyte count — indicating new cell production from recovering stem cells", "Increased blast percentage", "Falling platelet count"], a: 1, r: "Marrow recovery signs: (1) ANC rising above nadir (recovery typically begins day 14-21); (2) reticulocyte count increasing (new RBC production); (3) platelet count rising. Immature forms may appear (left shift) — bands and metamyelocytes indicate active marrow recovery. Full count recovery may take 3-4 weeks after standard chemotherapy.", s: "Hematology" },
  { q: "Pancytopenia in the elderly should raise suspicion for:", o: ["Normal aging", "Myelodysplastic syndrome (MDS) — the most common acquired bone marrow failure syndrome in adults >60 years, characterized by cytopenias with dysplastic marrow changes", "Iron deficiency only", "Viral illness only"], a: 1, r: "MDS is predominantly a disease of the elderly (median age 70). Presents with unexplained cytopenias (especially macrocytic anemia). Clonal stem cell disorder with dysplastic morphology on peripheral smear and bone marrow biopsy. Carries risk of AML transformation (approximately 30%). Classification: WHO system based on lineage dysplasia and blast percentage.", s: "Hematology" },
  { q: "Anemia of chronic disease (ACD) in inflammatory conditions differs from iron deficiency because:", o: ["Both have the same iron studies", "ACD has elevated ferritin (acute phase reactant) and LOW TIBC, while iron deficiency has LOW ferritin and HIGH TIBC — ferritin is the key differentiating test", "ACD has low ferritin", "Iron deficiency has elevated ferritin"], a: 1, r: "Key distinction: Ferritin in ACD is elevated (it's an acute phase reactant that increases with inflammation) despite functional iron deficiency. ACD pattern: elevated ferritin, low serum iron, LOW TIBC (unlike iron deficiency where TIBC is HIGH), low transferrin saturation. ACD is caused by hepcidin-mediated iron sequestration.", s: "Hematology" },
  { q: "Duloxetine for chronic OA pain works by:", o: ["Reducing joint inflammation", "Modulating central pain processing as an SNRI — addressing the central sensitization component of chronic OA pain", "Building cartilage", "Blocking prostaglandins"], a: 1, r: "Chronic OA pain involves central sensitization — amplified pain processing in the spinal cord and brain. Duloxetine (SNRI) increases serotonin and norepinephrine in descending inhibitory pain pathways, modulating central pain perception. FDA-approved for chronic musculoskeletal pain. Consider when NSAIDs are contraindicated or insufficient.", s: "Musculoskeletal" },
  { q: "OA synovial fluid analysis shows:", o: ["Turbid fluid with >50,000 WBCs (inflammatory)", "Clear to slightly yellow fluid with <2,000 WBCs — noninflammatory, distinguishing OA from inflammatory arthritis and septic arthritis", "Purulent fluid with bacteria", "Bloody fluid"], a: 1, r: "OA synovial fluid is noninflammatory: clear to slightly yellow, viscous, WBC <2,000/μL, no crystals, negative culture. Inflammatory arthritis (RA): cloudy, WBC 2,000-50,000. Septic arthritis: purulent, WBC >50,000 (often >100,000), positive culture. Gout/pseudogout: inflammatory with crystals.", s: "Musculoskeletal" },
  { q: "Total joint replacement complications include: Select all that apply.", o: ["Deep vein thrombosis and pulmonary embolism", "Prosthetic joint infection", "Periprosthetic fracture", "Joint dislocation (especially hip)", "Guaranteed 100% pain relief"], a: 0, r: "TJR complications: (1) DVT/PE (highest risk first 2 weeks — prophylaxis mandatory); (2) infection (1-2% — devastating, may require prosthesis removal); (3) periprosthetic fracture (weakened bone around prosthesis); (4) dislocation (hip > knee, especially first 6-12 weeks). 100% pain relief is NOT guaranteed — 85-90% report significant improvement.", s: "Musculoskeletal", t: "sata", ca: [0, 1, 2, 3] },
  { q: "Chondrocytes in OA become dysfunctional because:", o: ["They multiply too rapidly", "They shift from maintaining cartilage matrix to producing catabolic enzymes (MMPs, aggrecanases) and pro-inflammatory mediators under mechanical stress", "They migrate to other joints", "They have no role in OA"], a: 1, r: "In OA, chondrocytes undergo phenotypic changes: (1) upregulate MMP-1, MMP-13 (collagenases), ADAMTS-4/5 (aggrecanases); (2) produce IL-1β, TNF-α, PGE2; (3) undergo hypertrophic differentiation (resembling growth plate chondrocytes); (4) eventually undergo senescence and apoptosis. The result: cartilage destruction exceeds repair.", s: "Musculoskeletal" },
  { q: "Erosive osteoarthritis differs from typical OA by:", o: ["Being less severe", "Involving inflammatory destruction of the central portion of the joint (erosive changes on X-ray) — most commonly affecting the DIP and PIP joints with acute inflammatory flares", "Affecting only the knees", "Having no inflammation"], a: 1, r: "Erosive (inflammatory) OA: subtype primarily affecting DIP and PIP joints with central erosions on X-ray (gull-wing/saw-tooth pattern), acute inflammatory episodes (red, hot, swollen joints), and more aggressive joint destruction than typical nodal OA. Can be confused with RA or psoriatic arthritis. RF and anti-CCP are negative.", s: "Musculoskeletal" },
  { q: "Post-operative DVT prophylaxis after total joint replacement includes:", o: ["Aspirin alone is always sufficient", "Pharmacologic anticoagulation (LMWH, DOACs, or aspirin depending on risk) combined with mechanical prophylaxis (SCDs, early mobilization) for 10-35 days post-surgery", "No prophylaxis needed", "Bedrest for 2 weeks"], a: 1, r: "TJR DVT prophylaxis: (1) pharmacologic — LMWH (enoxaparin), DOACs (rivaroxaban, apixaban), or aspirin for lower-risk patients; (2) mechanical — sequential compression devices (SCDs), TED hose; (3) early mobilization (within 24 hours). Duration: minimum 10-14 days, some guidelines recommend 35 days (especially THA). Bedrest dramatically increases DVT risk.", s: "Musculoskeletal" },
  { q: "Sulfonylureas (glipizide, glyburide) lower glucose by:", o: ["Blocking glucose absorption", "Stimulating pancreatic beta cells to release insulin — they carry a risk of hypoglycemia and weight gain", "Blocking SGLT2", "Enhancing insulin sensitivity"], a: 1, r: "Sulfonylureas bind to SUR1 receptors on beta cell K-ATP channels, causing channel closure → depolarization → calcium influx → insulin granule exocytosis. Key risks: (1) hypoglycemia (insulin secretion is NOT glucose-dependent); (2) weight gain (insulin is anabolic); (3) secondary failure (beta cell exhaustion over time).", s: "Endocrine" },
  { q: "DPP-4 inhibitors (sitagliptin, linagliptin) work by:", o: ["Stimulating insulin directly", "Inhibiting dipeptidyl peptidase-4, which normally degrades incretin hormones (GLP-1, GIP) — this extends incretin action, enhancing glucose-dependent insulin secretion", "Blocking glucose reabsorption", "Replacing insulin"], a: 1, r: "DPP-4 normally degrades GLP-1 and GIP (incretin hormones) within 2-3 minutes. DPP-4 inhibitors prolong incretin action: enhanced glucose-dependent insulin secretion, suppressed glucagon, delayed gastric emptying. Advantages: weight-neutral, low hypoglycemia risk, well-tolerated. Less potent than GLP-1 RAs but oral and easier to use.", s: "Endocrine" },
  { q: "Thiazolidinediones (pioglitazone) improve insulin sensitivity by:", o: ["Stimulating beta cells", "Activating PPARγ receptors in adipose tissue, increasing adiponectin and enhancing insulin signaling in muscle and liver — but causing weight gain and fluid retention", "Blocking glucose absorption", "Inhibiting gluconeogenesis directly"], a: 1, r: "TZDs activate PPARγ nuclear receptors, primarily in adipocytes: (1) increase adiponectin (enhances insulin sensitivity); (2) redistribute visceral fat to subcutaneous fat; (3) enhance muscle and liver insulin sensitivity. Risks: weight gain, fluid retention (exacerbates heart failure — BLACK BOX warning), increased fracture risk, possible bladder cancer risk.", s: "Endocrine" },
  { q: "Diabetic autonomic neuropathy can cause: Select all that apply.", o: ["Gastroparesis (delayed gastric emptying)", "Orthostatic hypotension", "Neurogenic bladder with urinary retention", "Resting tachycardia from vagal denervation", "Enhanced sweating in all areas"], a: 0, r: "Diabetic autonomic neuropathy affects multiple organ systems: (1) GI — gastroparesis, constipation/diarrhea; (2) cardiovascular — resting tachycardia, orthostatic hypotension, silent MI; (3) GU — neurogenic bladder, erectile dysfunction; (4) sudomotor — anhidrosis (decreased sweating) in extremities with compensatory hyperhidrosis in trunk/face.", s: "Endocrine", t: "sata", ca: [0, 1, 2, 3] },
  { q: "Somogyi effect vs dawn phenomenon — the key differentiating factor is:", o: ["Time of day", "3 AM glucose level — Somogyi has 3 AM HYPOglycemia (rebound) while dawn phenomenon has normal or elevated 3 AM glucose (counterregulatory surge)", "Type of diabetes", "Insulin type used"], a: 1, r: "Both cause fasting morning hyperglycemia but from different mechanisms: Somogyi: nocturnal hypoglycemia triggers counterregulatory hormone release → rebound hyperglycemia (check 3 AM glucose — it will be LOW). Dawn: physiologic early morning GH/cortisol surge → hyperglycemia (3 AM glucose normal/high). Treatment differs: Somogyi = reduce evening insulin; Dawn = increase/adjust.", s: "Endocrine" },
  { q: "Gestational diabetes screening occurs at:", o: ["First prenatal visit for all patients", "24-28 weeks gestation for average-risk patients using a 50g glucose challenge test (GCT) — elevated results (≥140 mg/dL) require confirmatory 100g OGTT", "Only after delivery", "Only for patients with family history"], a: 1, r: "Screening: 50g GCT at 24-28 weeks. If 1-hour glucose ≥140 mg/dL → confirmatory 100g OGTT (fasting, 1h, 2h, 3h). Two or more elevated values confirm GDM (Carpenter-Coustan criteria). High-risk patients (obesity, prior GDM, family history) should be screened at first prenatal visit AND again at 24-28 weeks if initially negative.", s: "Endocrine" },
  { q: "A1c targets for most non-pregnant adults with diabetes are:", o: ["<5%", "<6%", "<7% — balancing glycemic control benefits against hypoglycemia risk", "<10%"], a: 2, r: "ADA guidelines: HbA1c <7% for most adults. Individualized targets: <6.5% for newly diagnosed younger patients without hypoglycemia risk; <8% for elderly with limited life expectancy, extensive comorbidities, or hypoglycemia unawareness. Each 1% A1c reduction reduces microvascular complications by approximately 25%.", s: "Endocrine" },
  { q: "Insulin pen safety includes which practices? Select all that apply.", o: ["Never share insulin pens between patients even with needle changes", "Always prime the pen before each injection (2 units into air)", "Attach a new needle for each injection", "Store opened insulin at room temperature for up to 28 days", "Reuse pen needles to save costs"], a: 0, r: "Insulin pen safety: (1) NEVER share pens (cross-contamination of blood/pathogens — even with new needle, blood can enter the cartridge); (2) prime 2 units before each injection; (3) new needle each time (reuse dulls needle, increases lipodystrophy risk); (4) opened insulin stable at room temperature 28 days. Needle reuse is NOT recommended despite being common.", s: "Endocrine", t: "sata", ca: [0, 1, 2, 3] },
  { q: "Potassium replacement in DKA must be initiated when:", o: ["Only after insulin starts", "Serum potassium falls below 5.3 mEq/L — add 20-40 mEq KCl to each liter of IV fluids to maintain K+ 4.0-5.0", "Only when EKG changes appear", "Potassium replacement is never needed"], a: 1, r: "DKA potassium management: (1) K+ <3.3: HOLD insulin, replace K+ aggressively (40 mEq/hour central line); (2) K+ 3.3-5.3: add 20-40 mEq KCl per liter of IV fluids and start insulin; (3) K+ >5.3: DO NOT add K+ but recheck in 2 hours (insulin will drive K+ down). Monitor K+ every 1-2 hours.", s: "Endocrine" },
  { q: "Subcutaneous insulin absorption rates from fastest to slowest site:", o: ["All sites absorb equally", "Abdomen (fastest) → arm → thigh → buttock (slowest) — exercise increases absorption from the exercised limb", "Buttock fastest → abdomen slowest", "Only the abdomen should be used"], a: 1, r: "Absorption rate varies by site due to blood flow differences: abdomen has greatest vascularity (fastest, most consistent), followed by upper arm, lateral thigh, and buttock (slowest). Teaching: rotate within the SAME region to maintain consistency. If switching regions, expect timing changes. Exercise increases absorption from the exercised area.", s: "Endocrine" },
  { q: "Hemoglobin S polymerization in SCD is triggered by:", o: ["High oxygen levels", "Deoxygenation — when HbS releases oxygen, the exposed valine at position 6 on the β-chain creates a hydrophobic contact site that allows HbS molecules to form rigid polymers", "Iron deficiency", "High temperature"], a: 1, r: "The sickle mutation (Glu6Val) substitutes hydrophobic valine for hydrophilic glutamic acid on the β-globin chain. In the deoxy state, this valine fits into a complementary hydrophobic pocket on an adjacent HbS molecule, initiating polymerization. Polymer strands align into rigid fibers that distort the RBC into the sickle shape.", s: "Hematology" },
  { q: "Hemolytic anemia in SCD is both intravascular and extravascular:", o: ["Only intravascular", "Intravascular hemolysis releases free hemoglobin (scavenges nitric oxide → vasculopathy), while extravascular hemolysis (splenic trapping of sickled cells) causes jaundice and gallstones", "Only extravascular", "Neither occurs in SCD"], a: 1, r: "Dual hemolysis: (1) Intravascular: sickled RBCs lyse within circulation, releasing free hemoglobin that scavenges nitric oxide (causing vasoconstriction, pulmonary hypertension, priapism) and releases arginase; (2) Extravascular: rigid sickled cells are trapped and destroyed by splenic macrophages → unconjugated hyperbilirubinemia → pigment gallstones.", s: "Hematology" },
  { q: "Hemoglobin electrophoresis in sickle cell disease shows:", o: ["Normal hemoglobin pattern", "HbSS pattern: predominantly HbS (>80%), elevated HbF (variable), absent or minimal HbA — HbA2 is normal", "Only HbA present", "Only HbF present"], a: 1, r: "HbSS electrophoresis: HbS predominates (80-95%), HbF is variable (2-20%, higher with hydroxyurea), HbA is ABSENT (no normal β-globin gene). HbA2 is normal (2-3.5%). In sickle trait (HbAS): HbA predominates (55-60%), HbS is 35-45%. Hemoglobin electrophoresis is the gold standard diagnostic test.", s: "Hematology" },
  { q: "Newborn screening for SCD is important because:", o: ["SCD is not present at birth", "Early diagnosis allows initiation of prophylactic penicillin by 2 months of age, which dramatically reduces fatal pneumococcal sepsis in infants with functional asplenia", "Treatment must start before birth", "Screening is not recommended"], a: 1, r: "Universal newborn screening for hemoglobinopathies detects SCD before clinical symptoms appear (HbF predominates until approximately 6 months). Early prophylactic penicillin (starting at 2 months) reduced mortality from pneumococcal sepsis by 84% in the landmark PROPS study. Additional benefits: early parental education, pneumococcal vaccination, and care coordination.", s: "Hematology" },
  { q: "Alpha-thalassemia results from deletion of α-globin genes on chromosome:", o: ["Chromosome 11", "Chromosome 16 — each person has FOUR α-globin genes (two on each chromosome 16); severity depends on how many are deleted", "Chromosome 22", "Chromosome 9"], a: 1, r: "Four α-globin genes exist (two copies of HGA1 and HGA2 on each chromosome 16): (1) silent carrier (−α/αα): one gene deleted, normal CBC; (2) trait (−α/−α or −−/αα): two deleted, mild microcytic anemia; (3) HbH disease (−−/−α): three deleted, moderate anemia with HbH (β4); (4) Bart hydrops (−−/−−): four deleted, lethal.", s: "Hematology" },
  { q: "Ineffective erythropoiesis in thalassemia causes increased iron absorption because:", o: ["Patients need more iron", "Erythroferrone (produced by expanding erythroid precursors) suppresses hepcidin — the master iron-regulatory hormone — allowing unrestricted intestinal iron absorption", "The liver fails", "Iron transport is blocked"], a: 1, r: "Expanded but ineffective erythroid precursors produce erythroferrone, which suppresses hepatic hepcidin production. Hepcidin normally blocks ferroportin (intestinal iron exporter), limiting iron absorption. With suppressed hepcidin, ferroportin is uninhibited → unrestricted iron absorption → additional iron overload on top of transfusional iron loading.", s: "Hematology" },
  { q: "MDS is classified using the WHO system based on:", o: ["Only blast percentage", "Number of dysplastic lineages, blast percentage in blood and marrow, ring sideroblasts, cytogenetic abnormalities (del(5q)), and specific molecular mutations", "Only symptoms", "Only age at diagnosis"], a: 1, r: "WHO classification considers: (1) unilineage vs multilineage dysplasia; (2) blast percentage (5-9% = MDS with excess blasts-1; 10-19% = MDS-EB2; ≥20% = AML); (3) ring sideroblasts (≥15% or SF3B1 mutation); (4) cytogenetics (isolated del(5q) = favorable prognosis, responsive to lenalidomide); (5) molecular mutations (TP53 = poor prognosis).", s: "Hematology" },
  { q: "Azacitidine for MDS works by:", o: ["Stimulating bone marrow", "Inhibiting DNA methyltransferase — this hypomethylating agent reactivates silenced tumor suppressor genes, promoting normal cell differentiation and reducing abnormal blast proliferation", "Chelating iron", "Suppressing the immune system"], a: 1, r: "Azacitidine (hypomethylating agent) is incorporated into DNA and inhibits DNA methyltransferase, causing hypomethylation. This reactivates silenced tumor suppressor genes, promoting normal differentiation. It is first-line for higher-risk MDS (IPSS intermediate-2 and high-risk) and has been shown to delay progression to AML and improve overall survival.", s: "Hematology" },
  { q: "Pancytopenia from SLE occurs through:", o: ["Only bone marrow failure", "Multiple mechanisms: autoimmune destruction of blood cells (immune cytopenias), bone marrow suppression from inflammation, and medication side effects (cyclophosphamide, methotrexate)", "Only medication effects", "Only infection"], a: 1, r: "SLE can cause pancytopenia through: (1) autoimmune hemolytic anemia (warm antibodies); (2) immune thrombocytopenia (antiplatelet antibodies); (3) autoimmune neutropenia; (4) bone marrow suppression from chronic inflammation; (5) medication-related myelosuppression (cyclophosphamide, azathioprine, methotrexate); (6) secondary hemophagocytic syndrome.", s: "Hematology" },
  { q: "Transfusion-associated iron overload affects which organs? Select all that apply.", o: ["Heart — cardiomyopathy and arrhythmias (leading cause of death)", "Liver — fibrosis and cirrhosis", "Endocrine glands — diabetes, hypogonadism, hypothyroidism, growth failure", "Skin — bronze discoloration", "Kidneys — iron deposits cause direct renal failure"], a: 0, r: "Iron deposits in: (1) heart — #1 cause of death (cardiomyopathy, heart failure, arrhythmias); (2) liver — fibrosis → cirrhosis → hepatocellular carcinoma risk; (3) endocrine — anterior pituitary (hypogonadism, growth failure), pancreas (diabetes), thyroid (hypothyroidism); (4) skin — bronze/gray discoloration. Kidneys are relatively spared by iron overload.", s: "Hematology", t: "sata", ca: [0, 1, 2, 3] },
  { q: "The Revised International Prognostic Scoring System (IPSS-R) for MDS uses:", o: ["Only age", "Cytogenetics, bone marrow blast percentage, hemoglobin, platelet count, and ANC to stratify patients into five risk groups from very low to very high risk", "Only blast percentage", "Only WBC count"], a: 1, r: "IPSS-R risk stratification: (1) cytogenetics (5 categories from very good to very poor); (2) marrow blast % (≤2%, >2-<5%, 5-10%, >10%); (3) hemoglobin; (4) platelet count; (5) ANC. Risk groups predict overall survival and risk of AML transformation, guiding treatment decisions (observation vs hypomethylating agents vs transplant).", s: "Hematology" },
  { q: "Occupational risk factors for OA include:", o: ["Only desk work", "Repetitive joint loading, heavy lifting, prolonged kneeling/squatting — these increase mechanical wear on weight-bearing and heavily used joints", "Only contact sports", "No occupational factors exist"], a: 1, r: "Occupational OA risk factors: (1) farming — hip and knee OA from heavy lifting, prolonged standing; (2) construction — knee OA from kneeling/squatting; (3) manufacturing — hand OA from repetitive grip/pinch; (4) mining — knee/hip OA from heavy loads. Workplace ergonomic modifications can reduce risk.", s: "Musculoskeletal" },
  { q: "Malalignment in OA (varus/valgus) accelerates disease because:", o: ["It has no effect", "Altered joint mechanics concentrate forces on one compartment — varus (bowlegged) overloads the MEDIAL compartment; valgus (knock-kneed) overloads the LATERAL compartment", "It distributes forces evenly", "It only affects appearance"], a: 1, r: "Normal knee alignment distributes load evenly across medial and lateral compartments. Varus malalignment shifts approximately 70% of load to the medial compartment (already the most commonly affected in knee OA). This creates a vicious cycle: cartilage loss → malalignment → more cartilage loss. Corrective osteotomy or unloader braces can redistribute forces.", s: "Musculoskeletal" },
  { q: "Platelet-rich plasma (PRP) injection for OA:", o: ["Is FDA-approved standard treatment", "Contains concentrated growth factors that may promote cartilage repair and reduce inflammation — evidence is promising but inconsistent, and it is not yet standard of care", "Cures OA completely", "Is contraindicated in all cases"], a: 1, r: "PRP: patient's blood is centrifuged to concentrate platelets and growth factors (PDGF, TGF-β, VEGF, IGF-1). When injected into OA joints, these growth factors may reduce inflammation and potentially promote tissue repair. Evidence: some RCTs show benefit over hyaluronic acid or saline, but heterogeneity in preparation methods limits definitive conclusions.", s: "Musculoskeletal" },
  { q: "Capsaicin cream for OA works by:", o: ["Cooling the joint", "Depleting substance P from peripheral pain nerve endings — initial burning sensation decreases with continued use as pain transmission is reduced", "Rebuilding cartilage", "Reducing joint swelling"], a: 1, r: "Capsaicin (from chili peppers) binds to TRPV1 receptors on C-fiber nociceptors, initially causing burning sensation (substance P release). With repeated application, substance P stores are depleted, reducing pain signal transmission. Must be applied consistently (3-4x daily) for 2-4 weeks before significant benefit. Wash hands thoroughly after application.", s: "Musculoskeletal" },
  { q: "Hip OA typically presents with pain in:", o: ["The lower back only", "The groin, anterior thigh, and sometimes referred to the knee — patients often complain of difficulty with stair climbing, putting on shoes, and getting in/out of cars", "The foot and ankle", "Only at rest"], a: 1, r: "Hip OA pain location: groin (most common), anterior thigh, lateral hip (trochanteric region), and referred to the knee (L3 dermatome). Functional limitations: stair climbing, getting up from seated position, putting on shoes/socks, entering/exiting vehicles. Pain typically worsens with weight-bearing and improves with rest.", s: "Musculoskeletal" },
  { q: "Cervical spine OA (cervical spondylosis) can cause:", o: ["Only neck pain", "Neck pain, radiculopathy (arm pain/numbness from nerve root compression), and myelopathy (spinal cord compression causing gait disturbance, hand clumsiness, and bladder dysfunction)", "Only headaches", "No neurological symptoms"], a: 1, r: "Cervical OA: osteophytes and disc degeneration can compress: (1) nerve roots → cervical radiculopathy (dermatomal arm pain, numbness, weakness); (2) spinal cord → cervical myelopathy (gait ataxia, hand weakness/clumsiness, Lhermitte sign, hyperreflexia, Babinski sign, bladder dysfunction). Myelopathy requires urgent surgical evaluation.", s: "Musculoskeletal" },
  { q: "Prosthetic joint infection presents with:", o: ["No symptoms", "Persistent joint pain, warmth, effusion, and possibly wound drainage or sinus tract formation — elevated ESR and CRP support the diagnosis, but joint aspiration with culture is definitive", "Only fever", "Normal inflammatory markers"], a: 1, r: "PJI: early (<3 months post-op) — usually Staph aureus from surgical inoculation; delayed (3-24 months) — often coagulase-negative Staph; late (>24 months) — hematogenous seeding. Diagnosis: ESR/CRP (screening), synovial fluid WBC >1,100-3,000 with >65-80% PMNs, positive culture. Treatment: often requires prosthesis removal (two-stage revision).", s: "Musculoskeletal" },
  { q: "Patient education for OA self-management includes: Select all that apply.", o: ["Regular low-impact exercise (walking, swimming, cycling)", "Weight management — even 5-10% weight loss significantly reduces symptoms", "Joint protection techniques (proper body mechanics, assistive devices)", "Application of heat before activity and ice after activity for pain", "Avoiding all physical activity to protect joints"], a: 0, r: "Comprehensive OA self-management: (1) exercise is FIRST-LINE (strengthens muscles, maintains ROM, reduces pain); (2) weight loss reduces joint loading and inflammatory adipokines; (3) joint protection reduces mechanical stress; (4) heat before activity (reduces stiffness), ice after (reduces swelling/pain). Avoiding activity is WRONG — it worsens deconditioning and stiffness.", s: "Musculoskeletal", t: "sata", ca: [0, 1, 2, 3] },
  { q: "The nurse assessing a patient with suspected RA should look for: Select all that apply.", o: ["Symmetric joint swelling of MCP and PIP joints", "Morning stiffness lasting >60 minutes", "Subcutaneous rheumatoid nodules on extensor surfaces", "Positive anti-CCP antibodies and elevated ESR/CRP", "Heberden nodes at DIP joints"], a: 0, r: "RA assessment findings: (1) symmetric MCP/PIP swelling (boggy synovitis); (2) prolonged morning stiffness >60 minutes; (3) rheumatoid nodules (subcutaneous, firm, non-tender); (4) positive anti-CCP (most specific) and elevated inflammatory markers. Heberden nodes (DIP) are characteristic of OA, not RA — RA typically SPARES DIP joints.", s: "Musculoskeletal", t: "sata", ca: [0, 1, 2, 3] },
  { q: "Hydroxychloroquine for RA requires monitoring for:", o: ["No monitoring needed", "Retinal toxicity — baseline and annual ophthalmologic exams are required because hydroxychloroquine can cause irreversible bull's-eye maculopathy", "Only liver function", "Only kidney function"], a: 1, r: "Hydroxychloroquine accumulates in the retinal pigment epithelium, causing toxic maculopathy (bull's-eye pattern on fundoscopy). Risk increases after 5 years of use and with higher doses. Screening: baseline eye exam, then annual after 5 years (or sooner with risk factors: renal impairment, tamoxifen use, macular disease). Damage is irreversible if not caught early.", s: "Musculoskeletal" },
  { q: "JAK inhibitors (tofacitinib, baricitinib) for RA work by:", o: ["Blocking TNF-α directly", "Inhibiting Janus kinases, blocking intracellular cytokine signaling pathways — they are oral small molecules that offer an alternative to injectable biologics", "Replacing immune cells", "Blocking B cells"], a: 1, r: "JAK inhibitors block Janus kinase enzymes that transduce intracellular signals from cytokine receptors (IL-6, IL-12, IL-23, interferons). Unlike biologics (which target one specific cytokine), JAK inhibitors broadly modulate multiple cytokine pathways. Advantages: oral administration, rapid onset. Risks: infections, herpes zoster reactivation, VTE, cardiovascular events.", s: "Musculoskeletal" },
  { q: "Anemia of chronic disease in RA is caused by:", o: ["Iron deficiency from poor diet", "Hepcidin elevation from chronic inflammation, which blocks iron absorption and iron release from macrophages — trapping iron in storage rather than making it available for erythropoiesis", "Blood loss", "Bone marrow failure"], a: 1, r: "Chronic inflammation (IL-6) stimulates hepatic hepcidin production. Hepcidin: (1) blocks ferroportin on intestinal enterocytes (reduced iron absorption); (2) blocks ferroportin on macrophages (trapped iron in storage). Result: iron is sequestered in macrophages, unavailable for erythropoiesis despite adequate iron stores (elevated ferritin). This is functional iron deficiency.", s: "Musculoskeletal" },
  { q: "Rituximab for RA targets:", o: ["T cells", "CD20-positive B cells — depleting B cells reduces autoantibody production (RF, anti-CCP) and B-cell-mediated antigen presentation and cytokine production", "Monocytes", "Natural killer cells"], a: 1, r: "Rituximab: anti-CD20 monoclonal antibody that depletes CD20+ B cells through complement-dependent cytotoxicity and antibody-dependent cellular cytotoxicity. B cell depletion reduces: (1) autoantibody production; (2) antigen presentation to T cells; (3) pro-inflammatory cytokine release. Used in RA patients who have failed TNF inhibitors. Risk: PML (rare), infections.", s: "Musculoskeletal" },
  { q: "Vaso-occlusive crisis in SCD pain management includes: Select all that apply.", o: ["IV opioids via PCA (patient-controlled analgesia)", "IV fluids at 1-1.5x maintenance rate", "Incentive spirometry every 2 hours while awake", "Warm compresses to painful areas", "Cold compresses to all affected joints"], a: 0, r: "VOC pain management: (1) IV opioids (hydromorphone or morphine PCA — most effective, rapid onset); (2) IV fluids (rehydration reduces RBC concentration and viscosity); (3) incentive spirometry (prevents ACS from hypoventilation due to chest/rib pain); (4) WARM compresses (vasodilation improves circulation). COLD is contraindicated — causes vasoconstriction and worsens sickling.", s: "Hematology", t: "sata", ca: [0, 1, 2, 3] },
  { q: "Epigenetic therapy for MDS includes:", o: ["Surgery", "Hypomethylating agents (azacitidine, decitabine) that reactivate silenced tumor suppressor genes through DNA demethylation — first-line for higher-risk MDS", "Radiation therapy", "Antibiotics"], a: 1, r: "MDS involves epigenetic silencing of tumor suppressor genes through DNA hypermethylation. Azacitidine and decitabine incorporate into DNA and inhibit DNA methyltransferase, causing passive demethylation and gene reactivation. In the CALGB 9221 trial, azacitidine significantly improved survival and delayed AML transformation in higher-risk MDS.", s: "Hematology" },
  { q: "The nurse caring for a patient receiving iron chelation should monitor for:", o: ["No monitoring needed", "Renal function (deferasirox is nephrotoxic), hepatic function, audiometry and ophthalmology exams (deferoxamine causes ototoxicity and retinal toxicity), and agranulocytosis (deferiprone)", "Only blood counts", "Only iron levels"], a: 1, r: "Agent-specific monitoring: (1) Deferoxamine: vision (retinal toxicity) and hearing (ototoxicity) — annual audiometry and ophthalmology; (2) Deferasirox: renal function (serum creatinine monthly), hepatic function (monthly LFTs), GI symptoms; (3) Deferiprone: weekly CBC (agranulocytosis risk — 1-2%), hepatic function.", s: "Hematology" },
  { q: "Hemoglobin F (fetal hemoglobin) is protective against sickling because:", o: ["It contains β-globin chains", "HbF (α2γ2) cannot participate in HbS polymer formation — the γ-chain blocks the critical hydrophobic contact site needed for polymerization", "It carries less oxygen", "It is found only in adults"], a: 1, r: "HbS polymerization requires the Val6→Val6 contact between deoxy-HbS β-chains. HbF's γ-chains have glutamine at the corresponding position, which cannot form this hydrophobic contact. Higher intracellular HbF concentration: (1) dilutes HbS concentration; (2) directly inhibits polymer initiation. This explains why SCD symptoms appear after 6 months when HbF declines.", s: "Hematology" },
  { q: "Stem cell transplant for SCD is most successful when:", o: ["Performed in elderly patients", "Performed in children from an HLA-matched sibling donor — cure rates exceed 90% with reduced-intensity conditioning", "Any donor can be used", "Age does not matter"], a: 1, r: "Allogeneic stem cell transplant is the only established CURE for SCD. Best outcomes: (1) young age (<16 years); (2) HLA-matched sibling donor (90-95% event-free survival); (3) limited end-organ damage. Challenges: only approximately 14% of patients have a matched sibling. Haploidentical and unrelated donor transplants are expanding access but with higher complication rates.", s: "Hematology" },
  { q: "Sickle cell nephropathy progresses from:", o: ["Sudden kidney failure", "Hyposthenuria (inability to concentrate urine) → microalbuminuria → proteinuria → progressive glomerulosclerosis → end-stage renal disease", "Only UTIs", "No renal involvement occurs"], a: 1, r: "Sickle cell nephropathy: (1) earliest finding: hyposthenuria — loss of concentrating ability from medullary ischemia (vasa recta sickling); (2) microalbuminuria → proteinuria from glomerular damage (hyperfiltration, FSGS); (3) progressive decline in GFR; (4) ESRD (4-12% of SCD patients). ACE inhibitors/ARBs for proteinuria. SCD is now a recognized cause of CKD in young adults.", s: "Hematology" },
  { q: "Immune thrombocytopenic purpura (ITP) can cause isolated thrombocytopenia or be part of pancytopenia because:", o: ["ITP only affects platelets", "Antiplatelet antibodies destroy platelets, AND the same autoimmune process can produce antibodies against RBCs (Evans syndrome) and neutrophils, causing multilineage cytopenias", "ITP never causes pancytopenia", "It is not an autoimmune condition"], a: 1, r: "ITP: autoantibodies (usually IgG) target platelet surface glycoproteins (GPIIb/IIIa, GPIb/IX), causing platelet destruction in the spleen. Evans syndrome: ITP + autoimmune hemolytic anemia (concurrent antiplatelet AND anti-RBC antibodies). Some patients also develop autoimmune neutropenia, resulting in pancytopenia. Treatment: corticosteroids, IVIG, rituximab, TPO-RAs.", s: "Hematology" },
  { q: "GLP-1 receptor agonists (semaglutide, liraglutide) provide benefits beyond glucose control including:", o: ["Only glucose lowering", "Cardiovascular risk reduction, weight loss (5-15%), and renal protection — they slow gastric emptying, reduce appetite centrally, and improve insulin sensitivity", "Increased appetite", "No additional benefits"], a: 1, r: "GLP-1 RAs mimic incretin hormones: (1) glucose-dependent insulin secretion; (2) glucagon suppression; (3) delayed gastric emptying; (4) central appetite suppression. Weight loss: 5-15% (semaglutide most effective). Cardiovascular benefits: reduced MACE events. Renal benefits: reduced albuminuria and CKD progression. Side effects: nausea, vomiting (start low, titrate slowly).", s: "Endocrine" },
  { q: "Metformin is contraindicated when eGFR falls below:", o: ["90 mL/min", "30 mL/min — because impaired renal clearance increases metformin accumulation and the risk of lactic acidosis", "60 mL/min", "45 mL/min"], a: 1, r: "Metformin is renally cleared. Updated guidelines: (1) eGFR >45: use at full dose; (2) eGFR 30-45: reduce dose by 50%, monitor renal function q3 months; (3) eGFR <30: CONTRAINDICATED — metformin accumulation inhibits lactate conversion to glucose, risking lactic acidosis (mortality 50%). Also hold for 48 hours after IV contrast.", s: "Endocrine" },
  { q: "Basal-bolus insulin therapy consists of:", o: ["Only rapid-acting insulin", "A long-acting insulin (glargine or detemir) providing background coverage PLUS rapid-acting insulin (lispro, aspart, glulisine) before each meal to cover carbohydrate intake", "Only long-acting insulin", "Intermediate insulin only"], a: 1, r: "Basal-bolus mimics physiologic insulin secretion: (1) basal component — long-acting insulin (glargine: 24h, peakless; detemir: 12-24h) replaces background insulin that maintains fasting glucose; (2) bolus component — rapid-acting insulin before meals covers postprandial glucose excursion. Total daily dose: approximately 50% basal, 50% bolus. Adjust based on glucose patterns.", s: "Endocrine" },
  { q: "Diabetic nephropathy is characterized by progressive stages:", o: ["Only one stage", "Hyperfiltration → microalbuminuria (30-300 mg/day) → macroalbuminuria (>300 mg/day) → declining GFR → end-stage renal disease", "Sudden onset renal failure", "Reversible changes only"], a: 1, r: "Diabetic nephropathy progression: Stage 1: hyperfiltration (GFR >140, enlarged kidneys); Stage 2: silent phase (structural changes without clinical findings); Stage 3: incipient nephropathy (microalbuminuria — earliest detectable sign); Stage 4: overt nephropathy (macroproteinuria, declining GFR, hypertension); Stage 5: ESRD. ACEi/ARBs slow progression at microalbuminuria stage.", s: "Endocrine" },
  { q: "Insulin-to-carbohydrate ratio is used for:", o: ["All diabetes patients", "Calculating the mealtime rapid-acting insulin dose based on planned carbohydrate intake — a typical starting ratio is 1 unit per 10-15g of carbohydrates", "Only basal insulin dosing", "Only DKA management"], a: 1, r: "Insulin-to-carb (I:C) ratio: how many grams of carbohydrate one unit of rapid insulin covers. Starting ratios: approximately 1:10-1:15 for most adults (Rule of 500: 500 ÷ total daily dose = I:C ratio). Example: TDD 50 units → I:C = 1:10 → patient eating 60g carbs needs 6 units of rapid insulin. Adjust based on post-meal glucose readings.", s: "Endocrine" },
  { q: "Correction factor (sensitivity factor) for insulin dosing:", o: ["Is the same for all patients", "Estimates how much one unit of rapid-acting insulin will lower blood glucose — calculated using the Rule of 1800 (1800 ÷ TDD = mg/dL drop per unit)", "Only applies to type 2 diabetes", "Is only used in the hospital"], a: 1, r: "Correction factor: 1800 ÷ total daily dose (TDD). Example: TDD 50 units → 1800/50 = 36 → one unit of rapid insulin drops glucose approximately 36 mg/dL. Used for 'sliding scale' corrections above target. Combined with I:C ratio for mealtime dosing. Some formulas use 1700 or 1500 for different insulin types.", s: "Endocrine" },
  { q: "Hyperosmolar hyperglycemic state (HHS) differs from DKA in that:", o: ["Both are identical", "HHS has MORE severe hyperglycemia (often >600 mg/dL), GREATER dehydration (8-12L deficit), NO significant ketosis (enough insulin to prevent lipolysis), and HIGHER mortality (5-20% vs 1-5% for DKA)", "HHS has lower glucose than DKA", "HHS always has ketones"], a: 1, r: "Key differences: (1) glucose: HHS >600 vs DKA 250-600; (2) pH: HHS >7.30 vs DKA <7.30; (3) ketones: HHS minimal/absent vs DKA strongly positive; (4) osmolality: HHS >320 vs DKA variable; (5) dehydration: HHS 8-12L vs DKA 3-6L; (6) mental status: HHS more altered due to hyperosmolality; (7) mortality: HHS 5-20% vs DKA 1-5%.", s: "Endocrine" },
  { q: "Bicarbonate administration in DKA is reserved for:", o: ["All DKA patients", "pH <6.9 — routine bicarbonate is NOT recommended because it can worsen intracellular acidosis, cause paradoxical CNS acidosis, shift the oxyhemoglobin curve leftward, and cause hypokalemia", "pH <7.2", "pH <7.0"], a: 0, r: "Bicarbonate in DKA: only when pH <6.9 (immediately life-threatening acidemia). Risks: (1) paradoxical CSF acidosis (CO2 crosses BBB faster than HCO3); (2) worsened intracellular acidosis; (3) left shift of oxyhemoglobin curve (impaired O2 delivery); (4) hypokalemia (bicarbonate drives K+ into cells); (5) rebound metabolic alkalosis. The acidosis resolves with insulin and fluids.", s: "Endocrine" },
  { q: "Cerebral edema is the most feared complication of DKA treatment, especially in:", o: ["Elderly adults", "Children and adolescents — rapid osmolality correction causes water to shift into brain cells; symptoms include headache, altered consciousness, and bradycardia", "Only in HHS", "It never occurs with treatment"], a: 1, r: "Cerebral edema complicates 0.5-1% of pediatric DKA episodes (mortality 21-24%). Risk factors: (1) young age; (2) new-onset diabetes; (3) severe acidosis; (4) rapid glucose correction (>100 mg/dL/hr); (5) rapid fluid administration; (6) early bicarbonate use. Warning signs: headache, confusion, pupil changes, bradycardia, posturing. Treatment: mannitol or hypertonic saline, reduce IV rate.", s: "Endocrine" },
  { q: "Transition from IV insulin drip to subcutaneous insulin in DKA requires:", o: ["Simply stopping the drip", "Administering subcutaneous long-acting insulin 2-4 hours BEFORE stopping the drip — this overlapping period prevents rebound hyperglycemia and recurrent ketogenesis", "Stopping the drip then starting SQ insulin the next day", "No overlap needed"], a: 1, r: "Critical transition: IV insulin has a half-life of only 5-10 minutes. If stopped without prior SQ long-acting insulin, the patient rapidly becomes insulin-deficient → recurrent hyperglycemia and ketogenesis within hours. Protocol: give SQ basal insulin (glargine/detemir) 2-4 hours before planned drip discontinuation. Criteria to transition: anion gap closed, pH >7.30, bicarbonate >18, patient eating.", s: "Endocrine" },
  { q: "Thyroid function tests in thyroid storm show:", o: ["Normal values", "Elevated free T3 and T4 with suppressed TSH — but the degree of thyroid hormone elevation does NOT distinguish thyroid storm from uncomplicated thyrotoxicosis; the diagnosis is clinical", "Only elevated TSH", "Low T3 and T4"], a: 1, r: "Thyroid storm labs: elevated free T4 and T3, suppressed TSH (<0.01) — same pattern as thyrotoxicosis. The distinction between thyrotoxicosis and thyroid storm is CLINICAL using the Burch-Wartofsky score: temperature, CNS effects, GI dysfunction, tachycardia, heart failure, precipitating event, and atrial fibrillation. Score ≥45 = highly suggestive of storm.", s: "Endocrine" },
  { q: "Radioactive iodine (RAI) therapy for Graves disease works by:", o: ["Stimulating the thyroid", "Delivering targeted radiation to thyroid follicular cells that take up iodine-131, causing progressive thyroid cell destruction — most patients eventually become HYPOthyroid requiring lifelong levothyroxine", "Removing the thyroid surgically", "Blocking antibodies"], a: 1, r: "I-131 is selectively taken up by thyroid follicular cells via the sodium-iodide symporter. Beta particle radiation destroys cells over 6-12 weeks. Results: (1) euthyroid (rare); (2) hypothyroid (majority — 80%+ within 1 year, EXPECTED outcome requiring levothyroxine). Contraindicated in: pregnancy, breastfeeding, severe ophthalmopathy. Patient must observe radiation safety precautions.", s: "Endocrine" },
  { q: "Levothyroxine administration teaching includes:", o: ["Take with meals", "Take on an empty stomach 30-60 minutes before breakfast or at bedtime — separate from calcium, iron, and antacids by 4 hours because they impair absorption", "Take with calcium supplements", "Take only when feeling hypothyroid symptoms"], a: 1, r: "Levothyroxine absorption: (1) empty stomach (food reduces absorption by 20-40%); (2) separate from calcium, iron, PPI, antacids, cholestyramine by at least 4 hours; (3) consistent timing daily; (4) do NOT switch brands without provider approval (bioavailability varies); (5) TSH monitoring 6-8 weeks after dose changes. Full thyroid replacement: approximately 1.6 mcg/kg/day.", s: "Endocrine" },
  { q: "Primary vs secondary adrenal insufficiency is differentiated by:", o: ["Symptoms alone", "Aldosterone status — PRIMARY (Addison) has low cortisol AND low aldosterone (causing hyperkalemia, hyponatremia); SECONDARY (pituitary) has low cortisol but NORMAL aldosterone (renin-angiotensin controls aldosterone independently)", "Only by imaging", "Both are identical"], a: 1, r: "Critical distinction: Primary AI (adrenal gland destruction): ACTH HIGH (no negative feedback), cortisol LOW, aldosterone LOW (zona glomerulosa destroyed), hyperpigmentation (ACTH stimulates melanocytes). Secondary AI (pituitary ACTH deficiency): ACTH LOW, cortisol LOW, aldosterone NORMAL (regulated by RAAS, not ACTH), NO hyperpigmentation.", s: "Endocrine" },
  { q: "Steroid taper is necessary when discontinuing chronic corticosteroids because:", o: ["Steroids are addictive", "Chronic exogenous steroids suppress the HPA axis — abrupt withdrawal causes acute adrenal insufficiency (adrenal crisis) because the adrenals have atrophied and cannot resume adequate cortisol production immediately", "Steroids cause rebound inflammation only", "Tapering is optional"], a: 1, r: "HPA axis suppression: exogenous glucocorticoids (>7.5mg prednisone for >3 weeks) suppress CRH and ACTH secretion. Bilateral adrenal cortex atrophies from disuse. Recovery of adrenal function after discontinuation may take 6-12 months. Abrupt withdrawal → adrenal crisis (life-threatening hypotension, shock). Taper schedule depends on dose and duration of therapy.", s: "Endocrine" },
  { q: "Adrenal crisis management includes: Select all that apply.", o: ["IV hydrocortisone 100mg bolus, then 50mg every 6-8 hours", "Aggressive IV normal saline for volume resuscitation", "IV dextrose if hypoglycemic", "Identify and treat the precipitating cause (infection, trauma, surgery)", "Hold all steroids and observe"], a: 0, r: "Adrenal crisis treatment: (1) IV hydrocortisone 100mg STAT (stress dose — provides both glucocorticoid and mineralocorticoid coverage at this dose); (2) Aggressive IV NS (2-3L in first hours) — these patients are profoundly volume depleted; (3) D5NS or D50 for hypoglycemia; (4) identify/treat trigger (infection is most common). NEVER withhold steroids — this is immediately lethal.", s: "Endocrine", t: "sata", ca: [0, 1, 2, 3] },
  { q: "Cushing disease specifically refers to:", o: ["Any cause of cortisol excess", "ACTH-secreting pituitary adenoma — distinguished from other causes of Cushing SYNDROME (adrenal tumor, ectopic ACTH, exogenous steroids) by elevated ACTH and pituitary adenoma on MRI", "Adrenal tumor", "Exogenous steroid use"], a: 1, r: "Terminology: Cushing SYNDROME = any cause of cortisol excess. Cushing DISEASE = specifically ACTH-secreting pituitary adenoma (most common endogenous cause, approximately 70%). Diagnosis: high-dose dexamethasone suppression test (pituitary adenomas partially suppress, ectopic ACTH does not). Treatment: transsphenoidal pituitary surgery (85-90% cure rate).", s: "Endocrine" },
  { q: "Bone density is measured using DEXA scanning, which reports:", o: ["Only calcium levels", "T-scores comparing patient bone density to young adult reference — T-score ≤-2.5 = osteoporosis, -1.0 to -2.5 = osteopenia, >-1.0 = normal", "Only fracture history", "Blood test results"], a: 1, r: "DEXA (dual-energy X-ray absorptiometry): gold standard for bone density measurement. Measures at lumbar spine, femoral neck, and total hip. T-score: standard deviations from young adult mean (peak bone mass). Z-score (for premenopausal women and men <50): compares to age-matched controls. Screen: all women ≥65, men ≥70, and younger patients with risk factors.", s: "Musculoskeletal" },
  { q: "Bisphosphonates for osteoporosis work by:", o: ["Building new bone directly", "Binding to hydroxyapatite in bone and being ingested by osteoclasts during resorption — once inside, they inhibit the mevalonate pathway, causing osteoclast apoptosis and reducing bone resorption", "Replacing calcium", "Stimulating osteoblasts"], a: 1, r: "Bisphosphonates (alendronate, risedronate, zoledronic acid): (1) bind to hydroxyapatite at resorption sites; (2) osteoclasts ingest bisphosphonate-coated bone; (3) nitrogen-containing bisphosphonates inhibit farnesyl pyrophosphate synthase (mevalonate pathway); (4) disrupted protein prenylation → osteoclast dysfunction and apoptosis. Net effect: reduced bone turnover and increased density.", s: "Musculoskeletal" },
  { q: "Bisphosphonate administration requires:", o: ["Taking with meals", "Taking on an empty stomach with a FULL glass of plain water (6-8oz), remaining upright for 30-60 minutes, and waiting to eat or take other medications — this prevents esophageal irritation and ensures absorption", "Taking at bedtime", "No special instructions"], a: 1, r: "Bisphosphonate oral administration: (1) empty stomach (food reduces absorption from already low 1-3% to near zero); (2) FULL glass of plain water (not coffee, juice, mineral water); (3) remain UPRIGHT 30-60 minutes (prevents esophageal erosion/ulceration); (4) no food/drink/medications for 30-60 minutes. Severe esophageal adverse effects if instructions not followed.", s: "Musculoskeletal" },
  { q: "Osteonecrosis of the jaw (ONJ) is a rare but serious complication of:", o: ["Calcium supplements", "Bisphosphonates and denosumab — particularly with IV bisphosphonates (zoledronic acid) and in patients undergoing dental procedures", "ACE inhibitors", "Acetaminophen"], a: 1, r: "ONJ: exposed bone in the maxilla or mandible that fails to heal for >8 weeks. Risk factors: IV bisphosphonates >> oral, dental extractions/surgery, cancer treatment, poor oral hygiene. Prevention: dental evaluation and necessary procedures BEFORE starting therapy. If on antiresorptive therapy, discuss timing of dental procedures with oncologist/prescriber.", s: "Musculoskeletal" },
  { q: "Teriparatide (Forteo) is unique among osteoporosis drugs because:", o: ["It prevents bone resorption", "It is an ANABOLIC agent — recombinant PTH(1-34) given in intermittent doses STIMULATES osteoblast activity and NEW bone formation, unlike antiresorptive agents", "It replaces calcium", "It is an antiresorptive bisphosphonate"], a: 1, r: "Teriparatide: intermittent (pulsatile) PTH administration paradoxically stimulates osteoblast activity and new bone formation (continuous PTH = bone resorption; intermittent PTH = bone formation). It increases both trabecular and cortical bone. Limited to 2 years due to theoretical osteosarcoma risk (seen in rats). Most effective for severe osteoporosis with fractures.", s: "Musculoskeletal" },
  { q: "FRAX score is used to:", o: ["Diagnose osteoporosis", "Calculate the 10-year probability of major osteoporotic fracture and hip fracture — incorporating clinical risk factors (age, sex, BMI, prior fracture, family history, smoking, alcohol, glucocorticoids, RA, secondary osteoporosis) with or without BMD", "Measure bone density", "Only assess fall risk"], a: 1, r: "FRAX (Fracture Risk Assessment Tool) integrates BMD (optional) with clinical risk factors to predict fracture probability. Treatment thresholds (NOF): ≥3% 10-year hip fracture probability OR ≥20% major osteoporotic fracture probability. FRAX helps guide treatment decisions for patients with osteopenia (T-score -1.0 to -2.5) where treatment benefit is uncertain.", s: "Musculoskeletal" },
  { q: "Weight-bearing exercise reduces osteoporosis risk by:", o: ["Having no effect on bone", "Generating mechanical loading forces on bone that stimulate osteoblast activity through the Wnt signaling pathway — exercises include walking, jogging, stair climbing, and resistance training", "Only building muscle", "Only improving balance"], a: 1, r: "Wolff's Law: bone adapts to the loads placed upon it. Mechanical stress activates osteocytes → reduced sclerostin secretion → activated Wnt pathway → osteoblast recruitment and bone formation. Most effective exercises: weight-bearing impact (walking, jogging, dancing) and progressive resistance training. Swimming and cycling are NOT weight-bearing and have less bone benefit.", s: "Musculoskeletal" },
  { q: "Fall prevention in osteoporosis patients includes: Select all that apply.", o: ["Home safety assessment (remove rugs, improve lighting, install grab bars)", "Medication review (sedatives, antihypertensives that cause orthostasis)", "Vision and hearing correction", "Balance and strength training exercises", "Encouraging rapid movement to build confidence"], a: 0, r: "Fall prevention is critical — most osteoporotic fractures result from falls: (1) environmental modifications (lighting, rugs, grab bars, non-slip surfaces); (2) medication review (reduce sedatives, manage orthostatic hypotension); (3) sensory correction (vision, hearing, proprioception); (4) exercise (tai chi, balance training, strength exercises). Encouraging rapid movement increases fall risk.", s: "Musculoskeletal", t: "sata", ca: [0, 1, 2, 3] },
  { q: "Kyphoplasty/vertebroplasty for osteoporotic vertebral compression fractures:", o: ["Cures osteoporosis", "Involves injecting bone cement (PMMA) into the collapsed vertebral body to stabilize the fracture and reduce pain — kyphoplasty additionally uses a balloon to restore vertebral height before cement injection", "Replaces the vertebra", "Is first-line for all fractures"], a: 1, r: "Vertebroplasty: percutaneous PMMA injection stabilizes the fracture, reduces pain. Kyphoplasty: balloon tamp inflated first to restore height and create a cavity for cement (more controlled injection, less cement leakage). Indications: painful VCF refractory to conservative management (4-6 weeks of pain management, bracing). Not first-line — try conservative management first.", s: "Musculoskeletal" },
  { q: "Osteoporosis in men is:", o: ["Rare and unimportant", "Underdiagnosed and undertreated — approximately 1 in 4 men over 50 will have an osteoporotic fracture; causes include hypogonadism, glucocorticoids, alcohol, and aging", "Only seen in women", "Always genetic"], a: 1, r: "Male osteoporosis: 2 million American men have osteoporosis; 12 million have osteopenia. Men have 25% lifetime fracture risk after age 50. Secondary causes more common: hypogonadism (androgen deprivation therapy for prostate cancer), glucocorticoids, excessive alcohol, smoking, anticonvulsants. Screen men ≥70 years or younger with risk factors.", s: "Musculoskeletal" },
  { q: "Glucocorticoid-induced osteoporosis is prevented by:", o: ["No prevention needed", "Starting bisphosphonate therapy when glucocorticoid use is expected to exceed ≥3 months at ≥2.5mg prednisone daily — combined with calcium 1000-1200mg and vitamin D 800-1000 IU daily", "Only calcium supplementation", "Stopping glucocorticoids immediately"], a: 1, r: "Glucocorticoid-induced osteoporosis (GIO): most rapid bone loss occurs in first 3-6 months. Prevention: (1) use lowest effective steroid dose; (2) calcium + vitamin D for ALL patients; (3) bisphosphonate (alendronate, risedronate, or zoledronic acid) for MODERATE-HIGH risk patients on ≥2.5mg prednisone daily for ≥3 months. GIOP is the most common secondary cause of osteoporosis.", s: "Musculoskeletal" },
  { q: "ALL (acute lymphoblastic leukemia) treatment phases include: Select all that apply.", o: ["Induction (achieve complete remission)", "Consolidation/intensification (eliminate residual disease)", "Maintenance (low-dose chemotherapy for 2-3 years)", "CNS prophylaxis (intrathecal chemotherapy)", "Single-dose chemotherapy only"], a: 0, r: "ALL treatment: (1) Induction (4-6 weeks): multi-agent chemo (vincristine, prednisone, asparaginase, anthracycline) — goal: CR in >95% of children; (2) Consolidation: intensified chemo to eliminate MRD; (3) Maintenance: 2-3 years of oral 6-MP and methotrexate; (4) CNS prophylaxis: intrathecal methotrexate (ALL has high CNS relapse risk). Single-dose is never sufficient.", s: "Hematology", t: "sata", ca: [0, 1, 2, 3] },
  { q: "Philadelphia chromosome in ALL indicates:", o: ["Good prognosis", "Poor prognosis — the BCR-ABL1 translocation t(9;22) confers resistance to standard chemotherapy and requires addition of tyrosine kinase inhibitors (imatinib, dasatinib) to improve outcomes", "No impact on prognosis", "Only affects adults"], a: 1, r: "Philadelphia chromosome t(9;22): BCR-ABL1 fusion gene produces constitutively active tyrosine kinase → uncontrolled proliferation. Present in approximately 25% of adult ALL (only 3-5% in children). Historically poor prognosis, but TKI addition (imatinib, dasatinib) has dramatically improved outcomes. Ph+ ALL now approaches similar survival to Ph- ALL with TKI-containing regimens.", s: "Hematology" },
  { q: "Minimal residual disease (MRD) testing in leukemia:", o: ["Is not useful", "Detects extremely small numbers of leukemia cells (1 in 10,000 to 1 in 1,000,000) remaining after treatment — MRD-positive status predicts higher relapse risk and guides treatment intensification decisions", "Only measures remission", "Is only used at diagnosis"], a: 1, r: "MRD: detected by flow cytometry or PCR. MRD-negative after induction = excellent prognosis. MRD-positive after induction/consolidation = higher relapse risk → may need treatment intensification (additional chemo, transplant, or immunotherapy). MRD is now the most powerful independent prognostic factor in ALL and is increasingly used in AML treatment decisions.", s: "Hematology" },
  { q: "Chimeric antigen receptor T-cell (CAR-T) therapy for relapsed ALL:", o: ["Uses donor T cells", "Uses the patient's OWN T cells, genetically modified to express a chimeric antigen receptor targeting CD19 on B-cell ALL blasts — providing a personalized immunotherapy with high response rates", "Is a form of chemotherapy", "Uses unmodified T cells"], a: 1, r: "CAR-T therapy process: (1) leukapheresis — collect patient's T cells; (2) genetic engineering — insert CAR construct targeting CD19 (a B-cell surface marker); (3) expand modified T cells in lab; (4) lymphodepleting chemotherapy; (5) infuse CAR-T cells. Response rates: approximately 70-90% CR in relapsed/refractory ALL. Complications: cytokine release syndrome, neurotoxicity.", s: "Hematology" },
  { q: "Cytokine release syndrome (CRS) after CAR-T therapy presents with:", o: ["No symptoms", "Fever, hypotension, hypoxia, and capillary leak — caused by massive cytokine release from activated T cells; treated with tocilizumab (IL-6 receptor blocker) and supportive care", "Only mild rash", "Delayed response weeks later"], a: 1, r: "CRS: activated CAR-T cells release massive amounts of IL-6, IFN-γ, TNF-α. Grading: Grade 1 (fever only) → Grade 4 (life-threatening hypotension, respiratory failure, organ dysfunction). Treatment: (1) tocilizumab (anti-IL-6R, first-line for ≥Grade 2); (2) corticosteroids (if refractory to tocilizumab); (3) supportive care (vasopressors, mechanical ventilation). Onset: typically 1-14 days post-infusion.", s: "Hematology" },
  { q: "AML induction chemotherapy (7+3 regimen) consists of:", o: ["Oral medications only", "7 days of continuous infusion cytarabine PLUS 3 days of an anthracycline (daunorubicin or idarubicin) — achieving complete remission in approximately 60-80% of younger adults", "Single-agent therapy", "Radiation only"], a: 1, r: "7+3 regimen: (1) cytarabine (Ara-C): nucleoside analog, 7-day continuous IV infusion (disrupts DNA synthesis in S-phase); (2) anthracycline: 3 days of IV push (intercalates DNA, inhibits topoisomerase II, generates free radicals). Intensive regimen causing prolonged pancytopenia (2-4 weeks). CR rate: 60-80% in adults <60, 40-60% in older adults.", s: "Hematology" },
  { q: "Leukostasis from hyperleukocytosis in AML occurs when WBC exceeds:", o: ["10,000", "100,000 — large, sticky myeloid blasts occlude the microvasculature of the lungs and brain, causing respiratory distress and neurological symptoms; this is a medical emergency", "50,000", "200,000"], a: 1, r: "Leukostasis: WBC >100,000 with large blasts (more common in AML than ALL because myeloid blasts are larger and stickier). Symptoms: pulmonary (dyspnea, hypoxia, bilateral infiltrates) and CNS (confusion, visual changes, headache, stroke). Emergency treatment: (1) leukapheresis; (2) hydroxyurea for cytoreduction; (3) avoid RBC transfusion (increases viscosity); (4) TLS prevention.", s: "Hematology" },
  { q: "Graft-versus-host disease (GVHD) after allogeneic stem cell transplant:", o: ["Is always beneficial", "Occurs when donor T cells attack the recipient's tissues — acute GVHD (skin rash, liver dysfunction, GI symptoms) occurs within 100 days; chronic GVHD resembles autoimmune disease", "Never occurs with matched donors", "Only affects the skin"], a: 1, r: "GVHD: donor T cells recognize host tissues as foreign. Acute (≤100 days): skin (maculopapular rash), liver (elevated bilirubin), GI (diarrhea, abdominal pain). Chronic (>100 days): resembles systemic sclerosis, sicca syndrome, bronchiolitis obliterans. Paradox: mild GVHD is actually BENEFICIAL (graft-versus-leukemia effect reduces relapse). Prevention: immunosuppression (cyclosporine, methotrexate).", s: "Hematology" },
  { q: "Aplastic anemia bone marrow biopsy shows:", o: ["Hypercellular marrow with blasts", "Profoundly HYPOcellular marrow with replacement by fat — <25% cellularity (or <50% with <30% hematopoietic cells); remaining cells are morphologically normal (no dysplasia or blasts)", "Normal cellularity", "Fibrosis only"], a: 1, r: "Aplastic anemia: biopsy is diagnostic. Key findings: (1) severely hypocellular (often <10-25% cellularity vs normal 30-70% for age); (2) hematopoietic elements replaced by fat; (3) remaining cells are morphologically NORMAL (distinguishes from MDS which shows dysplastic changes); (4) no increase in blasts (distinguishes from leukemia); (5) reticulin fibrosis absent (distinguishes from myelofibrosis).", s: "Hematology" },
  { q: "Eltrombopag for aplastic anemia works by:", o: ["Stimulating only platelets", "Stimulating the thrombopoietin (TPO) receptor on hematopoietic stem cells — in aplastic anemia, it promotes MULTILINEAGE blood cell production (not just platelets), improving all three cell lines", "Suppressing the immune system", "Chelating iron"], a: 1, r: "Eltrombopag: oral TPO receptor agonist. Originally developed for ITP (stimulates megakaryopoiesis). In aplastic anemia, it stimulates residual HSCs via the c-MPL receptor, promoting TRILINEAGE hematopoiesis (RBCs, WBCs, AND platelets). Added to standard IST (ATG + cyclosporine) improves overall and complete response rates. Now part of first-line AA treatment.", s: "Hematology" },
  { q: "Paroxysmal nocturnal hemoglobinuria (PNH) is associated with aplastic anemia because:", o: ["They are unrelated", "Both involve stem cell dysfunction — PNH clones (lacking GPI-anchored complement regulatory proteins) can emerge from the immune-mediated destruction in aplastic anemia, as PNH stem cells may have a survival advantage", "PNH causes aplastic anemia", "Aplastic anemia always becomes PNH"], a: 1, r: "PNH-aplastic anemia overlap: (1) AA immune attack preferentially spares PNH clones (which lack GPI-anchored proteins that serve as immune targets); (2) PNH clones expand due to this survival advantage; (3) approximately 50% of AA patients have small PNH clones; (4) approximately 15% develop clinically significant PNH. Screen all AA patients for PNH using flow cytometry.", s: "Hematology" },
  { q: "OA radiographic findings include: Select all that apply.", o: ["Joint space narrowing from cartilage loss", "Osteophyte formation at joint margins", "Subchondral sclerosis (increased bone density below cartilage)", "Subchondral cysts", "Periarticular osteopenia (bone loss around joints)"], a: 0, r: "Classic OA radiographic features (LOSS mnemonic): Loss of joint space (cartilage thinning), Osteophytes (bone spurs at joint margins), Subchondral sclerosis (reactive bone thickening from increased stress), Subchondral cysts (synovial fluid forced through microfractures). Periarticular osteopenia is a feature of RA (not OA) — OA has subchondral SCLEROSIS (increased density).", s: "Musculoskeletal", t: "sata", ca: [0, 1, 2, 3] },
  { q: "Spinal stenosis from OA causes:", o: ["Only back pain", "Neurogenic claudication — bilateral leg pain, weakness, and numbness that worsens with walking and standing (spinal extension narrows the canal) and improves with sitting or bending forward (flexion opens the canal)", "Improved mobility", "No neurological symptoms"], a: 1, r: "Lumbar spinal stenosis: OA causes facet joint hypertrophy, ligamentum flavum thickening, disc bulging, and osteophyte formation → narrowed spinal canal compressing the cauda equina. Neurogenic claudication (vs vascular claudication): (1) bilateral symptoms; (2) worse with walking/standing; (3) relieved by sitting/leaning forward (shopping cart sign); (4) normal pedal pulses.", s: "Musculoskeletal" },
  { q: "Knee OA is more common in the MEDIAL compartment because:", o: ["Genetics only", "Normal gait biomechanics place 60-80% of compressive force through the medial compartment — this inherent loading asymmetry accelerates medial cartilage wear", "The lateral compartment is more stressed", "Cartilage is thinner laterally"], a: 1, r: "During normal gait, the ground reaction force passes medial to the knee center, creating an adduction moment that loads the medial compartment with 60-80% of total force. This explains medial > lateral OA prevalence, and why varus (bowlegged) malalignment worsens medial OA. Lateral thrust during walking further increases medial loading. Medial wedge insoles may reduce this force.", s: "Musculoskeletal" },
  { q: "Arthroscopic surgery for knee OA:", o: ["Is the first-line treatment", "Has been shown in multiple RCTs to be NO more effective than sham surgery for typical OA — current guidelines recommend against arthroscopic lavage and debridement for OA", "Cures OA permanently", "Rebuilds cartilage"], a: 1, r: "Landmark trials (Moseley 2002, Kirkley 2008): arthroscopic lavage/debridement for knee OA was no better than placebo (sham) surgery. AAOS and ACR guidelines recommend AGAINST arthroscopy for OA. Exception: specific mechanical symptoms (true locking from loose body, bucket-handle meniscus tear) may warrant arthroscopy, but the underlying OA is not treated.", s: "Musculoskeletal" },
  { q: "Osteosarcopenia in the elderly combines:", o: ["Only osteoporosis", "Osteoporosis AND sarcopenia (muscle loss) — the combination dramatically increases fall and fracture risk because weak muscles cannot protect weakened bones", "Only muscle loss", "Neither condition"], a: 1, r: "Osteosarcopenia: concurrent bone loss + muscle loss, sharing common pathophysiology (hormonal decline, inflammation, malnutrition, inactivity). Synergistic risk: weak muscles increase fall frequency; osteoporotic bones fracture more easily. Management requires dual approach: resistance exercise (builds both muscle and bone), protein supplementation (1.0-1.2 g/kg/day), vitamin D, and fall prevention.", s: "Musculoskeletal" },
  { q: "Insulin pump therapy advantages include: Select all that apply.", o: ["More precise basal rate programming with variable hourly rates", "Bolus calculator for carb counting and correction doses", "Reduced severe hypoglycemia episodes compared to MDI in many studies", "Integration with CGM for sensor-augmented therapy", "Never requires any manual intervention"], a: 0, r: "Insulin pump advantages: (1) programmable basal rates (adjust for dawn phenomenon, exercise, etc.); (2) bolus calculator reduces math errors; (3) improved glycemic control with less hypoglycemia; (4) CGM integration allows predictive suspend and closed-loop control. Pumps still require: site changes q2-3 days, carb counting, calibration, and backup insulin supplies.", s: "Endocrine", t: "sata", ca: [0, 1, 2, 3] },
  { q: "Diabetic ketoacidosis in T2DM (ketosis-prone T2DM) can occur in:", o: ["Only T1DM patients", "African American, Hispanic, and Asian patients with T2DM who develop DKA during metabolic stress — they have transient beta cell failure that recovers, eventually allowing return to oral medications", "All T2DM patients equally", "Only elderly patients"], a: 1, r: "Ketosis-prone T2DM (previously called 'Flatbush diabetes'): patients present with DKA like T1DM but later recover beta cell function. Common in African American, Hispanic, and Asian populations. After DKA resolution, GAD/IA-2 antibodies are negative. Many can eventually discontinue insulin and maintain control with oral agents. Reclassification based on autoantibody status and beta cell reserve.", s: "Endocrine" },
  { q: "The dawn phenomenon occurs because:", o: ["Of evening snacking", "Growth hormone and cortisol secretion in the early morning hours (4-8 AM) increase hepatic glucose output and insulin resistance, causing fasting hyperglycemia", "Of medication wearing off", "Of exercise the night before"], a: 1, r: "Dawn phenomenon physiology: (1) GH pulse during sleep (stimulates gluconeogenesis and promotes insulin resistance); (2) early morning cortisol rise (circadian rhythm — stimulates gluconeogenesis); (3) reduced insulin sensitivity in early morning. Result: hepatic glucose output exceeds insulin's ability to maintain normoglycemia. Management: adjust basal insulin timing/dose.", s: "Endocrine" },
  { q: "Perioperative management of diabetes includes:", o: ["Stopping all diabetes medications", "Holding oral hypoglycemics day of surgery, reducing basal insulin to 50-80% of dose, monitoring glucose intraoperatively with target 140-180 mg/dL, and using an insulin drip if needed", "Giving full insulin dose regardless of NPO status", "No glucose monitoring needed"], a: 1, r: "Perioperative diabetes management: (1) NPO — hold oral agents and mealtime insulin; (2) reduce basal insulin to 50-80% the night before/morning of surgery; (3) IV D5 or D10 to prevent hypoglycemia during NPO period; (4) intraoperative glucose monitoring q1-2h; (5) target 140-180 mg/dL (tight control increases hypoglycemia risk); (6) insulin drip for major surgery or uncontrolled glucose.", s: "Endocrine" },
  { q: "Thyroid eye disease (Graves ophthalmopathy) is caused by:", o: ["Direct thyroid hormone effect on eyes", "Autoantibodies attacking TSH receptors on orbital fibroblasts — these cells produce glycosaminoglycans and undergo adipogenesis, causing retroorbital tissue expansion and inflammation", "Infection of the eye", "Vitamin A deficiency"], a: 1, r: "Graves ophthalmopathy: TSH receptor antibodies (TRAb) cross-react with TSH receptors on orbital fibroblasts. These fibroblasts: (1) produce excess glycosaminoglycans (attract water → edema); (2) differentiate into adipocytes (fat expansion); (3) recruit inflammatory cells. Result: retroorbital tissue expansion pushes eyes forward (proptosis). Can progress to optic nerve compression.", s: "Endocrine" },
  { q: "Propylthiouracil (PTU) is preferred over methimazole in:", o: ["All patients", "First trimester of pregnancy — methimazole causes aplasia cutis and choanal/esophageal atresia; after the first trimester, switch to methimazole (lower hepatotoxicity risk)", "Elderly patients", "Children exclusively"], a: 1, r: "PTU vs methimazole in pregnancy: methimazole is teratogenic in the first trimester (aplasia cutis congenita, choanal atresia, tracheoesophageal fistula — 'methimazole embryopathy'). PTU is safer in first trimester. After first trimester, switch to methimazole because PTU carries higher hepatotoxicity risk (FDA black box warning). PTU also preferred in thyroid storm (blocks T4→T3 conversion).", s: "Endocrine" },
  { q: "Waterhouse-Friderichsen syndrome is:", o: ["A thyroid condition", "Bilateral adrenal hemorrhage, most commonly from meningococcal sepsis — causing acute, fulminant adrenal insufficiency with refractory shock and DIC", "A pituitary disorder", "A liver condition"], a: 1, r: "Waterhouse-Friderichsen: acute bilateral adrenal hemorrhagic necrosis from overwhelming sepsis (classically Neisseria meningitidis, also Pseudomonas, Streptococcus, Staphylococcus). DIC → adrenal hemorrhage → acute cortisol and aldosterone deficiency. Clinical: purpura fulminans, refractory hypotension, fever, altered consciousness. Treatment: immediate stress-dose steroids, antibiotics, vasopressors, DIC management.", s: "Endocrine" },
  { q: "HPA axis suppression from chronic corticosteroid use begins at:", o: ["Any dose", "Physiologic doses >5mg prednisone equivalent daily for >3 weeks — the degree of suppression depends on dose, duration, timing (evening dosing suppresses more than morning), and individual susceptibility", "Only after 6 months", "Only with IV steroids"], a: 1, r: "HPA suppression risk: dose >5mg prednisone (above physiologic replacement), duration >3 weeks, and frequency (daily > alternate day). Morning dosing mimics normal cortisol diurnal rhythm and is less suppressive. Evening dosing suppresses the nocturnal ACTH surge more effectively. After discontinuation, adrenal recovery takes 6-12 months. ACTH stimulation test confirms recovery.", s: "Endocrine" },
  { q: "Leukemia cutis is a sign of:", o: ["Skin infection", "Extramedullary leukemia — leukemic blast infiltration of the skin, appearing as violaceous papules or nodules; most common in AML (especially AML-M4 and M5 subtypes)", "Allergic reaction", "Normal finding"], a: 1, r: "Leukemia cutis: leukemic cell infiltration of the dermis and subcutaneous tissue. Appearance: firm, violaceous (purple-brown), non-tender papules, plaques, or nodules. Most common in AML, especially monocytic subtypes (M4, M5). Can be presenting sign of leukemia or indicate relapse. Biopsy confirms diagnosis. Associated with higher-risk disease and CNS involvement.", s: "Hematology" },
  { q: "Tumor lysis syndrome prevention includes: Select all that apply.", o: ["Aggressive IV hydration (2.5-3 L/m²/day) starting 24-48 hours before chemotherapy", "Allopurinol prophylaxis to reduce uric acid production", "Rasburicase for patients at highest risk (converts uric acid to allantoin)", "Frequent electrolyte monitoring (every 6-8 hours during high-risk period)", "Fluid restriction to prevent edema"], a: 0, r: "TLS prevention: (1) hyperhydration dilutes uric acid and promotes renal excretion; (2) allopurinol inhibits xanthine oxidase (prevents new uric acid formation but does NOT reduce existing uric acid); (3) rasburicase converts existing uric acid to allantoin (water-soluble, easily excreted) — use for high-risk patients; (4) frequent monitoring catches electrolyte derangements early. Fluid restriction would WORSEN TLS.", s: "Hematology", t: "sata", ca: [0, 1, 2, 3] },
  { q: "Voxelotor for SCD works by:", o: ["Increasing HbF levels", "Stabilizing the oxy-hemoglobin state of HbS, preventing deoxygenation-induced polymerization — this increases hemoglobin levels and reduces hemolysis", "Blocking P-selectin", "Chelating iron"], a: 1, r: "Voxelotor: oral HbS polymerization inhibitor that binds to the alpha chain of hemoglobin, increasing oxygen affinity. By keeping HbS in the oxygenated (R) state, it prevents the deoxygenation that triggers sickling. Results: increased Hgb (reduced hemolysis), but concerns about tissue oxygen delivery due to increased oxygen affinity. FDA-approved for SCD patients ≥4 years.", s: "Hematology" },
  { q: "Splenic sequestration crisis in SCD presents with:", o: ["Gradual onset", "Acute left upper quadrant pain, rapidly enlarging spleen, sudden drop in hemoglobin (≥2g/dL below baseline), tachycardia, and signs of hypovolemic shock", "Only mild discomfort", "Right-sided abdominal pain"], a: 1, r: "Splenic sequestration: sudden massive pooling of blood in the spleen. Most common in children 6 months to 6 years (before autosplenectomy) and in HbSC disease (spleen preserved longer). Can trap 30% of blood volume. Clinical: acute LUQ pain, rapidly enlarging spleen, dropping Hgb (can drop 3-5 g/dL in hours), hypovolemic shock. Treatment: immediate transfusion, fluid resuscitation, consider splenectomy after resolution.", s: "Hematology" },
  { q: "Fanconi anemia is distinguished from acquired aplastic anemia by:", o: ["Being more common", "Being a genetic (autosomal recessive) DNA repair disorder with characteristic physical anomalies (short stature, thumb/radius abnormalities, café-au-lait spots, microcephaly) and progressive bone marrow failure — diagnosed by chromosome breakage testing", "Only affecting adults", "Having normal chromosomes"], a: 1, r: "Fanconi anemia: inherited bone marrow failure syndrome from defective DNA repair (20+ FA genes identified). Physical anomalies in approximately 75%: short stature, thumb/radial ray anomalies, café-au-lait spots, renal malformations, microcephaly. Progressive pancytopenia develops (median age 7 years). High risk of MDS/AML and solid tumors. Diagnosis: chromosome breakage test (DEB/MMC). Treatment: transplant.", s: "Hematology" },
  { q: "MDS treatment is based on risk stratification:", o: ["All patients get the same treatment", "Lower-risk: supportive care, ESAs, lenalidomide for del(5q); higher-risk: hypomethylating agents (azacitidine/decitabine) or allogeneic stem cell transplant (only curative option)", "Surgery is the primary treatment", "Radiation therapy only"], a: 1, r: "Risk-stratified MDS treatment: Lower risk (IPSS-R ≤3.5): (1) observation if asymptomatic; (2) ESAs (epoetin/darbepoetin) for anemia; (3) lenalidomide for del(5q) MDS (60-70% transfusion independence). Higher risk (IPSS-R >3.5): (1) hypomethylating agents (first-line); (2) allogeneic SCT (only CURE but limited by age, comorbidities, donor availability).", s: "Hematology" },
  { q: "Drug-induced pancytopenia is most commonly caused by: Select all that apply.", o: ["Chemotherapy agents (expected myelosuppression)", "Methotrexate (especially with renal impairment)", "Chloramphenicol (rare but classic cause of aplastic anemia)", "Carbamazepine and other anticonvulsants", "Acetaminophen at therapeutic doses"], a: 0, r: "Common drug-induced pancytopenia causes: (1) chemotherapy — expected, dose-dependent; (2) methotrexate — folate antagonism, accumulates in renal failure; (3) chloramphenicol — dose-dependent (reversible) and idiosyncratic (irreversible aplastic anemia); (4) anticonvulsants (carbamazepine, phenytoin, valproic acid). Acetaminophen at therapeutic doses does NOT cause pancytopenia (hepatotoxicity only in overdose).", s: "Hematology", t: "sata", ca: [0, 1, 2, 3] },
  { q: "Menopause accelerates osteoporosis because:", o: ["Aging alone causes bone loss", "Estrogen withdrawal eliminates its protective effect on bone — estrogen normally suppresses osteoclast activity, promotes osteoclast apoptosis, and stimulates osteoblast function; without it, bone resorption dramatically exceeds formation", "Diet changes at menopause", "Exercise decreases"], a: 1, r: "Estrogen's bone protective mechanisms: (1) suppresses RANKL expression (reduces osteoclast formation); (2) increases OPG (decoy RANKL receptor); (3) promotes osteoclast apoptosis; (4) enhances osteoblast survival. At menopause, rapid estrogen decline → burst of osteoclast activity → 2-3% bone loss per year for 5-10 years (vs 0.3-0.5%/year premenopausal). Greatest loss in trabecular bone (vertebrae).", s: "Musculoskeletal" },
  { q: "Secondary causes of osteoporosis include: Select all that apply.", o: ["Chronic glucocorticoid therapy (most common drug cause)", "Hyperparathyroidism (excess PTH increases bone resorption)", "Hyperthyroidism (excess thyroid hormone increases bone turnover)", "Celiac disease and malabsorption syndromes (calcium/vitamin D deficiency)", "Moderate weight-bearing exercise"], a: 0, r: "Secondary osteoporosis causes: (1) glucocorticoids (suppress osteoblasts, increase osteoclast lifespan); (2) hyperPTH (continuous PTH elevation = net bone resorption); (3) hyperthyroidism (increased bone turnover with net loss); (4) malabsorption (celiac, IBD, gastric bypass → calcium/vitamin D deficiency); (5) others: hypogonadism, T1DM, CKD, RA, alcoholism. Exercise prevents osteoporosis — it is NOT a cause.", s: "Musculoskeletal", t: "sata", ca: [0, 1, 2, 3] },
  { q: "Romosozumab for osteoporosis is a monoclonal antibody against:", o: ["RANKL", "Sclerostin — blocking sclerostin releases the brake on the Wnt signaling pathway, simultaneously stimulating bone formation AND reducing bone resorption (dual mechanism)", "Osteoclasts", "Vitamin D receptors"], a: 1, r: "Romosozumab (Evenity): anti-sclerostin antibody. Sclerostin (produced by osteocytes) normally inhibits the Wnt/β-catenin pathway, suppressing osteoblast activity. Blocking sclerostin → (1) increased bone formation (Wnt activation); (2) decreased bone resorption (reduced RANKL expression). This unique dual mechanism provides rapid, significant BMD increases. Given monthly SQ for 12 months. Black box: CV risk (MI, stroke) — avoid in high-CV-risk patients.", s: "Musculoskeletal" },
  { q: "Hip fracture in osteoporosis carries a mortality rate of:", o: ["<1%", "20-30% at one year — with an additional 50% of survivors having permanent functional disability", "50% at one month", "No increased mortality"], a: 1, r: "Hip fracture consequences: (1) 1-year mortality 20-30% (higher in men than women); (2) approximately 50% of survivors never regain pre-fracture functional independence; (3) approximately 25% require long-term nursing care; (4) increased mortality persists for 5-10 years post-fracture. This devastating outcome underscores the importance of osteoporosis prevention, screening, and treatment.", s: "Musculoskeletal" },
  { q: "Zoledronic acid (IV bisphosphonate) is given:", o: ["Daily", "Once yearly as a single IV infusion over at least 15 minutes — with pre-infusion calcium and vitamin D optimization to prevent hypocalcemia", "Weekly", "Monthly"], a: 1, r: "Zoledronic acid 5mg IV annually: most potent bisphosphonate, once-yearly dosing improves adherence (oral bisphosphonates have approximately 50% discontinuation rate at 1 year). Infusion-related adverse effects: acute phase reaction (fever, myalgias — approximately 30% after first dose, decreases with subsequent infusions), hypocalcemia, renal toxicity. Requires: adequate renal function (eGFR >35), pre-treatment calcium/vitamin D, and 15-minute minimum infusion time.", s: "Musculoskeletal" }
];
